// Ensure BigInt can be JSON-stringified anywhere.
(BigInt.prototype as any).toJSON = function () {
  return this.toString();
};

function mustEnv(name: string): string {
  const v = process.env[name];
  if (!v || !String(v).trim()) throw new Error(`${name} missing in apps/api/.env`);
  return String(v).trim();
}

function asString(x: unknown): string {
  return typeof x === "string" ? x : String(x ?? "");
}

function normalizeEmail(x: unknown): string {
  return asString(x).trim().toLowerCase();
}

function base32Encode(buf: Buffer): string {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
  let bits = 0;
  let value = 0;
  let out = "";
  for (const b of buf) {
    value = (value << 8) | b;
    bits += 8;
    while (bits >= 5) {
      out += alphabet[(value >>> (bits - 5)) & 31];
      bits -= 5;
    }
  }
  if (bits > 0) {
    out += alphabet[(value << (5 - bits)) & 31];
  }
  return out;
}

function generateRecoveryKey(): string {
  const raw = crypto.randomBytes(32);
  return base32Encode(raw);
}

function hashRecoveryKey(recoveryKey: string): string {
  const salt = crypto.randomBytes(16);
  const hash = argon2id(new TextEncoder().encode(recoveryKey), salt, {
    t: 2,
    m: 65536,
    p: 1,
    dkLen: 32
  });
  return `argon2id$${salt.toString("base64url")}$${Buffer.from(hash).toString("base64url")}`;
}

function verifyRecoveryKey(recoveryKey: string, stored: string): boolean {
  const parts = String(stored || "").split("$");
  if (parts.length !== 3 || parts[0] !== "argon2id") return false;
  const salt = Buffer.from(parts[1], "base64url");
  const expected = Buffer.from(parts[2], "base64url");
  const hash = Buffer.from(
    argon2id(new TextEncoder().encode(recoveryKey), salt, {
      t: 2,
      m: 65536,
      p: 1,
      dkLen: expected.length
    })
  );
  return hash.length === expected.length && crypto.timingSafeEqual(hash, expected);
}

function getClientIp(req: any): string {
  const xf = String(req.headers?.["x-forwarded-for"] || "").split(",")[0].trim();
  return xf || req.ip || req.socket?.remoteAddress || "unknown";
}

const rateBuckets = new Map<string, { count: number; resetAt: number }>();
function rateLimit(req: any, key: string, max: number, windowMs: number): boolean {
  const now = Date.now();
  const ip = getClientIp(req);
  const k = `${key}:${ip}`;
  const cur = rateBuckets.get(k);
  if (!cur || cur.resetAt <= now) {
    rateBuckets.set(k, { count: 1, resetAt: now + windowMs });
    return true;
  }
  if (cur.count >= max) return false;
  cur.count += 1;
  return true;
}

const RUNTIME_CONFIG = resolveRuntimeConfig();

function emailEquals(email: string | null | undefined) {
  if (!email) return undefined;
  return { equals: email };
}

function emailIn(emails: Array<string> | null | undefined) {
  if (!emails || emails.length === 0) return undefined;
  return { in: emails };
}

function num(x: unknown): number {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function parseFixedUpstreamBps(input: any): number {
  const bpsRaw = input?.upstreamBps;
  if (bpsRaw !== undefined && bpsRaw !== null && String(bpsRaw).trim() !== "") {
    const parsed = Math.floor(num(bpsRaw));
    return Math.max(0, Math.min(10000, parsed));
  }
  const pctRaw = input?.upstreamRatePercent;
  if (pctRaw !== undefined && pctRaw !== null && String(pctRaw).trim() !== "") {
    const pct = num(pctRaw);
    if (Number.isFinite(pct)) {
      return Math.max(0, Math.min(10000, Math.round(pct * 100)));
    }
  }
  return 0;
}

function hasExplicitUpstreamInput(input: any): boolean {
  const bpsRaw = input?.upstreamBps;
  if (bpsRaw !== undefined && bpsRaw !== null && String(bpsRaw).trim() !== "") return true;
  const pctRaw = input?.upstreamRatePercent;
  if (pctRaw !== undefined && pctRaw !== null && String(pctRaw).trim() !== "") return true;
  return false;
}

function parseRejectReason(input: any): string | null {
  const raw = asString(input?.reason || "").trim();
  if (!raw) return null;
  return raw.slice(0, 240);
}

function parseSats(x: unknown): bigint {
  if (typeof x === "bigint") return x;
  if (typeof x === "number") return BigInt(Math.floor(x));
  const s = asString(x).trim();
  if (!s) return 0n;
  if (/^\d+$/.test(s)) return BigInt(s);
  const n = Number(s);
  return Number.isFinite(n) ? BigInt(Math.floor(n)) : 0n;
}

type DatabaseTargetSource =
  | "env_database_url"
  | "contentbox_root"
  | "dev_quickstart"
  | "unset";

function resolveRuntimeDatabaseUrl(
  storage: "sqlite" | "postgres",
  explicitDatabaseUrl: string,
  explicitContentboxRoot: string,
  contentboxRootResolved: string
): { databaseUrl: string; source: DatabaseTargetSource } {
  const rawDatabaseUrl = String(explicitDatabaseUrl || "").trim();
  if (rawDatabaseUrl) return { databaseUrl: rawDatabaseUrl, source: "env_database_url" };
  if (storage !== "sqlite") return { databaseUrl: "", source: "unset" };

  const rawContentboxRoot = String(explicitContentboxRoot || "").trim();
  if (rawContentboxRoot) {
    const dbPath = path.join(contentboxRootResolved, "contentbox.db");
    return { databaseUrl: `file:${dbPath}`, source: "contentbox_root" };
  }

  return { databaseUrl: "file:./prisma/data/dev.db", source: "dev_quickstart" };
}

function normalizePublicOriginBase(origin: unknown): string {
  return asString(origin || "").trim().replace(/\/+$/, "");
}

function buildPublicUrlFromOrigin(origin: unknown, routePath: unknown): string {
  const base = normalizePublicOriginBase(origin);
  const p = asString(routePath || "").trim();
  if (!base || !p) return "";
  return `${base}${p.startsWith("/") ? p : `/${p}`}`;
}

function normalizeKnownPublicRouteToOrigin(origin: unknown, rawUrl: unknown): string {
  const raw = asString(rawUrl || "").trim();
  if (!raw) return "";
  if (raw.startsWith("/")) return buildPublicUrlFromOrigin(origin, raw);
  if (/^https?:\/\//i.test(raw)) {
    try {
      const u = new URL(raw);
      const pathAndQuery = `${u.pathname}${u.search || ""}`;
      if (
        u.pathname.startsWith("/buy/") ||
        u.pathname.startsWith("/public/content/") ||
        u.pathname.startsWith("/u/")
      ) {
        return buildPublicUrlFromOrigin(origin, pathAndQuery);
      }
    } catch {}
    return raw;
  }
  return "";
}

type RangeRequest =
  | { kind: "ok"; start: number; end: number }
  | { kind: "invalid" }
  | { kind: "none" };

function parseRangeHeader(range: string | undefined, size: number): RangeRequest {
  if (!range) return { kind: "none" };
  const trimmed = range.trim();
  if (!trimmed.startsWith("bytes=")) return { kind: "invalid" };
  const spec = trimmed.slice(6);
  if (!spec || spec.includes(",")) return { kind: "invalid" };

  const match = spec.match(/^(\d*)-(\d*)$/);
  if (!match) return { kind: "invalid" };

  const startRaw = match[1];
  const endRaw = match[2];

  if (!startRaw && !endRaw) return { kind: "invalid" };

  if (!startRaw && endRaw) {
    const suffix = Number(endRaw);
    if (!Number.isFinite(suffix) || suffix <= 0) return { kind: "invalid" };
    const end = Math.max(0, size - 1);
    const start = Math.max(0, size - suffix);
    if (start > end) return { kind: "invalid" };
    return { kind: "ok", start, end };
  }

  const start = Number(startRaw);
  if (!Number.isFinite(start) || start < 0) return { kind: "invalid" };

  if (!endRaw) {
    const end = Math.max(0, size - 1);
    if (start > end) return { kind: "invalid" };
    return { kind: "ok", start, end };
  }

  const end = Number(endRaw);
  if (!Number.isFinite(end) || end < start) return { kind: "invalid" };
  if (start >= size) return { kind: "invalid" };
  return { kind: "ok", start, end: Math.min(end, size - 1) };
}

function previewMaxBytesFor(mime: string | null | undefined, contentType: string | null | undefined): number {
  const mt = (mime || "").toLowerCase();
  const ct = (contentType || "").toLowerCase();
  if (mt.startsWith("audio/") || ct === "song") return 1_000_000;
  if (mt.startsWith("video/") || ct === "video") return 2_500_000;
  if (ct === "book") return 256_000;
  return 0;
}

function canPreview(mime: string | null | undefined, contentType: string | null | undefined): boolean {
  const ct = (contentType || "").toLowerCase();
  if (ct === "file") return false;
  const mt = (mime || "").toLowerCase();
  if (mt.startsWith("audio/") || mt.startsWith("video/")) return true;
  if (ct === "book") return true;
  return false;
}

const previewTokens = new Map<
  string,
  { manifestHash: string; fileId: string; expiresAt: number; maxBytes: number }
>();
const previewRate = new Map<string, { count: number; resetAt: number }>();
const uploadIdempotency = new Map<string, { status: "inflight" | "done"; response?: any; expiresAt: number }>();
const UPLOAD_IDEMPOTENCY_INFLIGHT_TTL_MS = 2 * 60 * 1000;
const UPLOAD_IDEMPOTENCY_DONE_TTL_MS = 30 * 1000;

function isPreviewToken(token: string | null | undefined): boolean {
  return Boolean(token && token.startsWith("preview_"));
}

function issuePreviewToken(input: { manifestHash: string; fileId: string; maxBytes: number; ttlMs: number }) {
  const token = `preview_${crypto.randomBytes(18).toString("hex")}`;
  const expiresAt = Date.now() + input.ttlMs;
  previewTokens.set(token, {
    manifestHash: input.manifestHash,
    fileId: input.fileId,
    maxBytes: input.maxBytes,
    expiresAt
  });
  return { token, expiresAt };
}

function allowPreviewIssue(ip: string, limit = 6, windowMs = 5 * 60 * 1000): boolean {
  const now = Date.now();
  const entry = previewRate.get(ip);
  if (!entry || now > entry.resetAt) {
    previewRate.set(ip, { count: 1, resetAt: now + windowMs });
    return true;
  }
  if (entry.count >= limit) return false;
  entry.count += 1;
  return true;
}

function base64UrlEncode(input: Buffer | string): string {
  const buf = Buffer.isBuffer(input) ? input : Buffer.from(input);
  return buf.toString("base64").replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function base64UrlDecode(input: string): Buffer {
  const pad = input.length % 4 === 0 ? "" : "=".repeat(4 - (input.length % 4));
  const normalized = input.replace(/-/g, "+").replace(/_/g, "/") + pad;
  return Buffer.from(normalized, "base64");
}

type PermitClaims = {
  manifestHash: string;
  fileId: string;
  buyerId: string;
  scopes: string[];
  iat: number;
  exp: number;
  nonce: string;
};

function signPermit(claims: PermitClaims): string {
  const header = { alg: "HS256", typ: "CBP1" };
  const headerB64 = base64UrlEncode(JSON.stringify(header));
  const payloadB64 = base64UrlEncode(JSON.stringify(claims));
  const data = `${headerB64}.${payloadB64}`;
  const sig = crypto.createHmac("sha256", PERMIT_SECRET).update(data).digest();
  const sigB64 = base64UrlEncode(sig);
  return `permit_${data}.${sigB64}`;
}

function verifyPermit(token: string): { ok: boolean; expired?: boolean; claims?: PermitClaims } {
  if (!token.startsWith("permit_")) return { ok: false };
  const raw = token.slice("permit_".length);
  const parts = raw.split(".");
  if (parts.length !== 3) return { ok: false };
  const [headerB64, payloadB64, sigB64] = parts;
  try {
    const header = JSON.parse(base64UrlDecode(headerB64).toString("utf8"));
    if (header?.alg !== "HS256") return { ok: false };
    const data = `${headerB64}.${payloadB64}`;
    const expected = crypto.createHmac("sha256", PERMIT_SECRET).update(data).digest();
    const actual = base64UrlDecode(sigB64);
    if (expected.length !== actual.length || !crypto.timingSafeEqual(expected, actual)) return { ok: false };
    const claims = JSON.parse(base64UrlDecode(payloadB64).toString("utf8")) as PermitClaims;
    if (!claims?.manifestHash || !claims?.fileId || !claims?.exp || !claims?.iat) return { ok: false };
    if (Date.now() > Number(claims.exp)) return { ok: false, expired: true, claims };
    return { ok: true, claims };
  } catch {
    return { ok: false };
  }
}

function readPemMaybeFile(value?: string | null): string | null {
  if (!value) return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (trimmed.includes("BEGIN")) return trimmed;
  if (fsSync.existsSync(trimmed)) {
    try {
      return fsSync.readFileSync(trimmed, "utf8");
    } catch {
      return null;
    }
  }
  return trimmed;
}

function readMacaroon(value?: string | null): string | null {
  if (!value) return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (fsSync.existsSync(trimmed)) {
    try {
      const buf = fsSync.readFileSync(trimmed);
      return buf.toString("hex");
    } catch {
      return null;
    }
  }
  return trimmed;
}

function isValidPublicOrigin(url: string | null | undefined): boolean {
  if (!url) return false;
  return /^https?:\/\/[^/\s]+/i.test(url);
}

async function fetchWithTimeout(url: string, init: RequestInit, timeoutMs = 4000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(url, { ...init, signal: controller.signal } as any);
  } finally {
    clearTimeout(timer);
  }
}

async function lndHealthCheck() {
  const cfg = await getStoredLndConfig(prisma).catch(() => null);
  if (!cfg) {
    return {
      status: "missing",
      message: "Lightning node not configured",
      endpoint: null,
      hint: null
    };
  }

  try {
    await probeLndConnection({ restUrl: cfg.restUrl, network: cfg.network, macaroonHex: cfg.macaroonHex, tlsCert: cfg.tlsCert || null });
    return { status: "healthy", message: "LND reachable", endpoint: cfg.restUrl, hint: null };
  } catch (e: any) {
    const mapped = mapLightningErrorMessage(String(e?.message || e));
    return { status: mapped.status, message: mapped.reason, endpoint: cfg.restUrl, hint: null };
  }
}

async function bitcoindHealthCheck() {
  const url = (process.env.BITCOIND_RPC_URL || "").trim();
  if (!url) {
    // If direct bitcoind RPC is not configured but local LND is healthy on loopback,
    // treat chain/backend as locally ready for sovereign-node gating.
    const lnd = await lndHealthCheck().catch(() => null as any);
    const lndEndpoint = String(lnd?.endpoint || "").trim().toLowerCase();
    const lndLocal =
      lndEndpoint.startsWith("https://127.0.0.1:") ||
      lndEndpoint.startsWith("http://127.0.0.1:") ||
      lndEndpoint.startsWith("https://localhost:") ||
      lndEndpoint.startsWith("http://localhost:");
    if (lnd?.status === "healthy" && lndLocal) {
      return {
        status: "healthy",
        message: "bitcoind inferred healthy via local LND backend",
        endpoint: lnd.endpoint || null,
        hint: null
      };
    }
    return { status: "missing", message: "BITCOIND_RPC_URL not configured", endpoint: null, hint: "Set BITCOIND_RPC_URL" };
  }
  const user = process.env.BITCOIND_RPC_USER || "";
  const pass = process.env.BITCOIND_RPC_PASS || "";
  if (!user || !pass) return { status: "degraded", message: "RPC user/pass missing", endpoint: url, hint: "Set BITCOIND_RPC_USER/BITCOIND_RPC_PASS" };
  try {
    const auth = Buffer.from(`${user}:${pass}`).toString("base64");
    const body = JSON.stringify({ jsonrpc: "1.0", id: crypto.randomUUID(), method: "getblockchaininfo", params: [] });
    const res = await fetchWithTimeout(
      url,
      { method: "POST", headers: { "Content-Type": "application/json", Authorization: `Basic ${auth}` }, body },
      4000
    );
    if (!res.ok) {
      const text = await res.text();
      return { status: "degraded", message: `RPC error: ${text}`, endpoint: url, hint: "Check bitcoind RPC settings" };
    }
    return { status: "healthy", message: "bitcoind reachable", endpoint: url, hint: null };
  } catch (e: any) {
    return { status: "degraded", message: String(e?.message || e), endpoint: url, hint: "Check RPC connectivity" };
  }
}
// Try to return a URL string that is safe to pass to fetch. If the input
// contains spaces or other characters that make it invalid, attempt to
// encode it with encodeURI and re-validate. Returns null if still invalid.
function normalizeUrlString(u: string | null | undefined): string | null {
  if (!u) return null;
  const s = String(u).trim();
  if (!s) return null;
  try {
    // If this succeeds it's already a valid URL (may be relative in some callers)
    new URL(s);
    return s;
  } catch {
    try {
      const enc = encodeURI(s);
      new URL(enc);
      return enc;
    } catch {
      return null;
    }
  }
}

function normalizeOrigin(value: string | null | undefined): string | null {
  const raw = String(value || "").trim();
  if (!raw) return null;
  if (/^https?:\/\//i.test(raw)) return raw.replace(/\/+$/, "");
  const isLocal =
    raw.startsWith("localhost") ||
    raw.startsWith("127.0.0.1") ||
    raw === "localhost" ||
    raw === "127.0.0.1";
  if (process.env.NODE_ENV !== "production" && isLocal) {
    return `http://${raw.replace(/\/+$/, "")}`;
  }
  return `https://${raw.replace(/\/+$/, "")}`;
}

function isShareablePublicOrigin(value: string | null | undefined): boolean {
  const origin = normalizeOrigin(value);
  if (!origin) return false;
  try {
    const url = new URL(origin);
    const host = String(url.hostname || "").trim().toLowerCase();
    if (!host) return false;
    if (host === "localhost" || host === "127.0.0.1" || host === "::1") return false;
    if (host.endsWith(".local")) return false;
    return true;
  } catch {
    return false;
  }
}

const originReachabilityCache = new Map<string, { reachable: boolean; checkedAt: number }>();
const originReachabilityInflight = new Map<string, Promise<boolean>>();

async function isOriginReachable(origin: string | null | undefined): Promise<boolean> {
  const normalized = normalizeOrigin(origin);
  if (!normalized) return false;
  const now = Date.now();
  const cached = originReachabilityCache.get(normalized);
  if (cached && now - cached.checkedAt < 15000) return cached.reachable;
  const inflight = originReachabilityInflight.get(normalized);
  if (inflight) return inflight;

  const work = (async () => {
    const endpoints = [`${normalized}/api/health`, `${normalized}/health`, `${normalized}/public/ping`];
    let reachable = false;
    for (const url of endpoints) {
      try {
        const res = await fetchWithTimeout(url, { method: "GET" } as any, 2500);
        if (res.ok) {
          reachable = true;
          break;
        }
      } catch {}
    }
    originReachabilityCache.set(normalized, { reachable, checkedAt: Date.now() });
    return reachable;
  })();
  originReachabilityInflight.set(normalized, work);
  try {
    return await work;
  } finally {
    originReachabilityInflight.delete(normalized);
  }
}

async function resolveShareableInviteOrigin(req: any): Promise<string | null> {
  const configuredShared =
    normalizeOrigin(process.env.PUBLIC_INVITE_ORIGIN) || normalizeOrigin(process.env.PUBLIC_BASE_ORIGIN);
  if (isShareablePublicOrigin(configuredShared) && (await isOriginReachable(configuredShared))) return configuredShared!;

  const publicStatus = getPublicStatus();
  const statusOrigin = normalizeOrigin(String(publicStatus.canonicalOrigin || publicStatus.publicOrigin || "").trim());
  if (isShareablePublicOrigin(statusOrigin) && (await isOriginReachable(statusOrigin))) return statusOrigin!;

  const activeOrigin = normalizeOrigin(getActivePublicOrigin());
  if (isShareablePublicOrigin(activeOrigin) && (await isOriginReachable(activeOrigin))) return activeOrigin!;

  const requestOrigin = normalizeOrigin(getPublicOrigin(req));
  if (isShareablePublicOrigin(requestOrigin) && (await isOriginReachable(requestOrigin))) return requestOrigin!;

  return null;
}

function getPublicOrigin(req: any): string {
  const envOrigin =
    normalizeOrigin(process.env.CONTENTBOX_PUBLIC_ORIGIN) ||
    normalizeOrigin(process.env.PUBLIC_ORIGIN) ||
    normalizeOrigin(process.env.APP_PUBLIC_ORIGIN);
  if (envOrigin) {
    if (process.env.NODE_ENV === "production" && !envOrigin.startsWith("https://")) {
      app.log.warn({ publicOrigin: envOrigin }, "PUBLIC_ORIGIN should be https in production");
    }
    return envOrigin;
  }

  // BASIC mode: prefer public link (tunnel) when available.
  try {
    const nodeMode = resolveRuntimeConfig().nodeMode;
    if (nodeMode === "basic") {
      const state = getPublicLinkState();
      const hasPublicOrigin = Boolean(state.canonicalOrigin);
      if (hasPublicOrigin) {
        return String(state.canonicalOrigin).replace(/\/+$/, "");
      }
    }
  } catch {}

  const xfProtoRaw = asString(req?.headers?.["x-forwarded-proto"] || "");
  const xfHostRaw = asString(req?.headers?.["x-forwarded-host"] || "");
  const xfProto = xfProtoRaw.split(",")[0].trim().toLowerCase();
  const xfHost = xfHostRaw.split(",")[0].trim();
  const protoOk = xfProto === "http" || xfProto === "https";
  const hostOk = xfHost && !/[\s]/.test(xfHost) && /^[a-z0-9.\-:\[\]]+$/i.test(xfHost);
  if (protoOk && hostOk) return `${xfProto}://${xfHost}`.replace(/\/+$/, "");

  const host = asString(req?.headers?.host || "").trim();
  const proto =
    (protoOk ? xfProto : "") ||
    (req as any)?.protocol ||
    (req?.raw?.socket?.encrypted ? "https" : "http");
  if (host) return `${proto}://${host}`.replace(/\/+$/, "");

  return APP_BASE_URL.replace(/\/+$/, "");
}

function isLoopbackIp(ip: string): boolean {
  const value = String(ip || "");
  if (!value) return false;
  if (value === "127.0.0.1" || value === "::1") return true;
  if (value.startsWith("::ffff:127.0.0.1")) return true;
  return false;
}

function setPublicDebugHeaders(req: any, reply: any): void {
  try {
    const origin = getPublicOrigin(req);
    if (origin) {
      reply.header("X-ContentBox-Origin", String(origin).replace(/\/+$/, ""));
    }
  } catch {}
  try {
    const node = String(process.env.NODE_ID || os.hostname() || "").trim();
    if (node) reply.header("X-ContentBox-Node", node);
  } catch {}
}

function round3(n: number): number {
  return Math.round(n * 1000) / 1000;
}

function percentToPrimitive(x: unknown): string | number | null {
  if (x === null || x === undefined) return null;
  if (typeof x === "number" || typeof x === "string") return x;
  try {
    if (typeof (x as any).toString === "function") return (x as any).toString();
  } catch {}
  return String(x);
}

function jsonSafe<T>(value: T): T {
  if (typeof value === "bigint") return value.toString() as unknown as T;
  if (Array.isArray(value)) return value.map((v) => jsonSafe(v)) as unknown as T;
  if (value && typeof value === "object") {
    const out: any = {};
    for (const [k, v] of Object.entries(value as any)) out[k] = jsonSafe(v);
    return out as T;
  }
  return value;
}

function jsonStringifySafe(value: unknown): string {
  return JSON.stringify(value, (_k, v) => (typeof v === "bigint" ? v.toString() : v));
}

function slugify(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 32) || "user";
}

function execFileAsync(cmd: string, args: string[], options?: Parameters<typeof execFile>[2]) {
  return new Promise<{ stdout: string; stderr: string }>((resolve, reject) => {
    execFile(cmd, args, options as any, (err, stdout, stderr) => {
      if (err) return reject(Object.assign(err, { stdout, stderr }));
      resolve({ stdout: String(stdout || ""), stderr: String(stderr || "") });
    });
  });
}

type HistoryActor =
  | { kind: "user"; id: string; email?: string | null; displayName?: string | null }
  | { kind: "external"; email?: string | null }
  | { kind: "system"; id?: string | null };

type HistoryEvent = {
  id: string;
  ts: string;
  category: string;
  type: string;
  title: string;
  summary?: string | null;
  actor?: HistoryActor | null;
  details?: any;
  diff?: any;
};

type AuditEventOut = {
  id: string;
  ts: string;
  type: string;
  archetype?: string;
  summary?: string | null;
  actor?: HistoryActor | null;
  details?: any;
  diff?: any;
};

function resolveAuditArchetype(scopeType: string, type: string): string {
  const scope = String(scopeType || "").trim().toLowerCase();
  const action = String(type || "").trim().toLowerCase();
  const isCommerce =
    action.startsWith("sale.") ||
    action.startsWith("sales.") ||
    action.startsWith("payment.") ||
    action.startsWith("payments.") ||
    action.startsWith("invoice.") ||
    action.startsWith("invoices.") ||
    action.startsWith("settlement.") ||
    action.startsWith("settlements.") ||
    action.startsWith("revenue.");
  if (scope === "split" || action.startsWith("split.") || action.startsWith("splits.")) return "rights_and_splits";
  if (scope === "invite" || action.startsWith("invite.") || action === "invite") return "identity_and_access";
  if (scope === "identity" || action.startsWith("identity.")) return "identity_and_access";
  if (scope === "clearance" || action.startsWith("clearance.")) return "clearance";
  if (scope === "library" || action.startsWith("library.")) return "content_lifecycle";
  if (action.startsWith("payout.") || action.startsWith("payouts.")) return "payout_execution";
  if (scope === "royalty" || action.startsWith("royalty.") || action.startsWith("royalties.")) return "commerce";
  if (isCommerce) return "commerce";
  if (scope === "content" || action.startsWith("content.")) return "content_lifecycle";
  return "system";
}

function actorFromUser(u: { id: string; email?: string | null; displayName?: string | null } | null): HistoryActor | null {
  if (!u) return null;
  return { kind: "user", id: u.id, email: u.email || null, displayName: u.displayName || null };
}

function actorExternal(email?: string | null): HistoryActor {
  return { kind: "external", email: email || null };
}

function createPreviewToken(app: any, userId: string, contentId: string, objectKey: string) {
  return app.jwt.sign(
    { sub: userId, contentId, objectKey, scope: "preview" },
    { expiresIn: "15m" }
  );
}

function badRequest(reply: any, msg: string) {
  return reply.code(400).send({ error: msg });
}

function notFound(reply: any, msg: string) {
  return reply.code(404).send({ error: msg });
}

function forbidden(reply: any) {
  return reply.code(403).send({ error: "Forbidden" });
}

function unauthorized(reply: any) {
  return reply.code(401).send({ error: "Unauthorized" });
}

function isIntegratedDashboardBuilt(): boolean {
  return fsSync.existsSync(DASHBOARD_INDEX_FILE) && fsSync.existsSync(DASHBOARD_DIST_DIR);
}

function contentTypeForAsset(filePath: string): string {
  const ext = path.extname(filePath).toLowerCase();
  if (ext === ".html") return "text/html; charset=utf-8";
  if (ext === ".js" || ext === ".mjs") return "application/javascript; charset=utf-8";
  if (ext === ".css") return "text/css; charset=utf-8";
  if (ext === ".json") return "application/json; charset=utf-8";
  if (ext === ".svg") return "image/svg+xml";
  if (ext === ".png") return "image/png";
  if (ext === ".jpg" || ext === ".jpeg") return "image/jpeg";
  if (ext === ".webp") return "image/webp";
  if (ext === ".ico") return "image/x-icon";
  if (ext === ".woff2") return "font/woff2";
  if (ext === ".woff") return "font/woff";
  if (ext === ".ttf") return "font/ttf";
  if (ext === ".map") return "application/json; charset=utf-8";
  return "application/octet-stream";
}

function sendFastifyRouteNotFound(req: any, reply: any, pathname: string) {
  return reply.code(404).send({
    message: `Route ${req.method}:${pathname} not found`,
    error: "Not Found",
    statusCode: 404
  });
}

function requestWantsHtml(req: any): boolean {
  const accept = String(req?.headers?.accept || "").toLowerCase();
  return accept.includes("text/html");
}

async function maybeHandleSplitEditorDocumentRequest(req: any, reply: any): Promise<boolean> {
  const method = String(req?.method || "").toUpperCase();
  if (method !== "GET") return false;
  if (!requestWantsHtml(req)) return false;

  // Browser navigation to /content/:id/splits should render dashboard UI,
  // not hit the protected JSON API route.
  if (isIntegratedDashboardBuilt()) {
    return await tryServeIntegratedDashboard(req, reply);
  }

  const rawContentId = asString((req?.params as any)?.id || "");
  const contentId = encodeURIComponent(rawContentId);
  const target = `${APP_BASE_URL.replace(/\/$/, "")}/content/${contentId}/splits`;
  reply.redirect(target);
  return true;
}

async function tryServeIntegratedDashboard(req: any, reply: any): Promise<boolean> {
  if (!isIntegratedDashboardBuilt()) return false;
  const method = String(req.method || "").toUpperCase();
  if (method !== "GET" && method !== "HEAD") return false;

  const rawPath = String(req.raw?.url || req.url || "/");
  const pathname = rawPath.split("?")[0] || "/";
  if (pathname.startsWith("/api/")) return false;
  if (/^\/public\/users\/[^/]+\/payout-destination\/?$/.test(pathname)) return false;

  const relative = pathname === "/" ? "index.html" : pathname.replace(/^\/+/, "");
  const candidate = path.resolve(DASHBOARD_DIST_DIR, relative);

  if (candidate.startsWith(DASHBOARD_DIST_DIR) && fsSync.existsSync(candidate) && fsSync.statSync(candidate).isFile()) {
    reply.type(contentTypeForAsset(candidate));
    if (method === "HEAD") {
      reply.code(200).send();
      return true;
    }
    reply.send(fsSync.readFileSync(candidate));
    return true;
  }

  reply.type("text/html; charset=utf-8");
  if (method === "HEAD") {
    reply.code(200).send();
    return true;
  }
  reply.send(fsSync.readFileSync(DASHBOARD_INDEX_FILE));
  return true;
}

const BUYER_SESSION_COOKIE = "cb_buyer_session";
const BUYER_SESSION_DAYS = 30;
const AUDIENCE_SESSION_COOKIE = "cb_audience_session";
const AUDIENCE_DEDUPE_WINDOW_MS = 30 * 60 * 1000;

function getCookie(req: any, name: string): string | null {
  try {
    const raw = String(req?.headers?.cookie || "");
    if (!raw) return null;
    const parts = raw.split(";").map((p) => p.trim());
    for (const p of parts) {
      const idx = p.indexOf("=");
      if (idx === -1) continue;
      const k = p.slice(0, idx).trim();
      if (k === name) return decodeURIComponent(p.slice(idx + 1));
    }
    return null;
  } catch {
    return null;
  }
}

function isSecureRequest(req: any): boolean {
  try {
    const xf = String(req?.headers?.["x-forwarded-proto"] || "").toLowerCase();
    if (xf.includes("https")) return true;
    const proto = String(req?.protocol || "").toLowerCase();
    if (proto === "https") return true;
  } catch {}
  return false;
}

function buildBuyerSessionCookie(sessionId: string, req: any, maxAgeSeconds: number): string {
  const maxAge = Math.max(1, Math.floor(maxAgeSeconds));
  const expMs = Date.now() + maxAge * 1000;
  const token = createBuyerSessionToken(sessionId, JWT_SECRET, expMs);
  const secure = isSecureRequest(req) || String(process.env.NODE_ENV || "").trim() === "production";
  const parts = [
    `${BUYER_SESSION_COOKIE}=${encodeURIComponent(token)}`,
    "Path=/",
    "HttpOnly",
    "SameSite=Lax",
    `Max-Age=${maxAge}`
  ];
  if (secure) parts.push("Secure");
  return parts.join("; ");
}

function buildBuyerClearCookie(req: any): string {
  const secure = isSecureRequest(req) || String(process.env.NODE_ENV || "").trim() === "production";
  const parts = [
    `${BUYER_SESSION_COOKIE}=`,
    "Path=/",
    "HttpOnly",
    "SameSite=Lax",
    "Max-Age=0",
    "Expires=Thu, 01 Jan 1970 00:00:00 GMT"
  ];
  if (secure) parts.push("Secure");
  return parts.join("; ");
}

function buildAudienceSessionCookie(sessionId: string, req: any, maxAgeSeconds: number): string {
  const maxAge = Math.max(1, Math.floor(maxAgeSeconds));
  const secure = isSecureRequest(req) || String(process.env.NODE_ENV || "").trim() === "production";
  const parts = [
    `${AUDIENCE_SESSION_COOKIE}=${encodeURIComponent(sessionId)}`,
    "Path=/",
    "HttpOnly",
    "SameSite=Lax",
    `Max-Age=${maxAge}`
  ];
  if (secure) parts.push("Secure");
  return parts.join("; ");
}

function getOrCreateAudienceSessionId(req: any, reply: any): string {
  const existing = asString(getCookie(req, AUDIENCE_SESSION_COOKIE) || "").trim();
  if (existing) return existing;
  const sessionId = `aud_${crypto.randomUUID().replace(/-/g, "")}`;
  // Keep audience session longer than dedupe window; rotate naturally with browser/session hygiene.
  const cookie = buildAudienceSessionCookie(sessionId, req, 60 * 60 * 24 * 30);
  reply.header("set-cookie", cookie);
  return sessionId;
}

/** ---------- app init ---------- */

const app = Fastify({ logger: true });

// Allow empty JSON bodies (treat as {})
const jsonParser = (_req: any, body: string, done: (err: Error | null, value?: any) => void) => {
  const raw = String(body || "").trim();
  if (!raw) return done(null, {});
  try {
    return done(null, JSON.parse(raw));
  } catch (e: any) {
    return done(e);
  }
};
app.addContentTypeParser("application/json", { parseAs: "string" }, jsonParser);
app.addContentTypeParser("application/*+json", { parseAs: "string" }, jsonParser);

app.addHook("onRequest", async (req, reply) => {
  const existing = (req.headers["x-request-id"] as string | undefined) || null;
  const id = existing || crypto.randomUUID();
  (req as any).requestId = id;
  reply.header("x-request-id", id);
});

app.setErrorHandler((error, req, reply) => {
  const id = (req as any).requestId || null;
  try {
    app.log.error({ requestId: id, message: String((error as any)?.message || error) }, "Unhandled error");
  } catch {}
  const status = Number((error as any)?.statusCode || (error as any)?.status) || 500;
  const payload: any = {
    error: "Internal Server Error",
    requestId: id
  };
  if (process.env.NODE_ENV !== "production") {
    payload.message = String((error as any)?.message || error);
    payload.name = (error as any)?.name || "Error";
    if ((error as any)?.code) payload.code = (error as any)?.code;
  }
  const safe = jsonSafe(payload);
  reply.type("application/json");
  reply.code(status).send(jsonStringifySafe(safe));
});

