type RemoteDiscoveryCacheEntry = {
  origin: string;
  publicKeyPem: string;
  fetchedAt: number;
};

const remoteDiscoveryKeyCache = new Map<string, RemoteDiscoveryCacheEntry>();
const REMOTE_DISCOVERY_CACHE_TTL_MS = 6 * 60 * 60 * 1000;

function getCachedRemoteDiscoveryKey(origin: string): string | null {
  const key = normalizeOrigin(origin || "");
  if (!key) return null;
  const entry = remoteDiscoveryKeyCache.get(key);
  if (!entry) return null;
  if (Date.now() - entry.fetchedAt > REMOTE_DISCOVERY_CACHE_TTL_MS) {
    remoteDiscoveryKeyCache.delete(key);
    return null;
  }
  return entry.publicKeyPem || null;
}

function setCachedRemoteDiscoveryKey(origin: string, publicKeyPem: string) {
  const key = normalizeOrigin(origin || "");
  const pem = asString(publicKeyPem || "").trim();
  if (!key || !pem) return;
  remoteDiscoveryKeyCache.set(key, {
    origin: key,
    publicKeyPem: pem,
    fetchedAt: Date.now()
  });
}

async function signInviteAcceptancePayload(
  token: string,
  userId: string,
  opts?: { audienceOrigin?: string | null }
): Promise<{ payload: any; signature: string }> {
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { email: true }
  });
  const hasDiscoveryKey = async (originRaw: string | null | undefined): Promise<boolean> => {
    const origin = normalizeOrigin(originRaw || "");
    if (!origin) return false;
    try {
      const host = new URL(origin).hostname.toLowerCase();
      if (host === "localhost" || host === "127.0.0.1" || host === "::1") return false;
    } catch {
      return false;
    }
    try {
      const discoveryRes = await fetchWithTimeout(
        `${origin}/.well-known/contentbox`,
        { method: "GET", headers: { Accept: "application/json" } as any } as any,
        4000
      );
      if (!discoveryRes.ok) return false;
      const discoveryPayload: any = await discoveryRes.json().catch(() => null);
      const discoveredNodeUrl = normalizeOrigin(asString(discoveryPayload?.nodeUrl || "").trim());
      const discoveredPub = asString(discoveryPayload?.publicKeyPem || "").trim();
      return Boolean(discoveredNodeUrl && discoveredPub);
    } catch {
      return false;
    }
  };
  const originCandidates = Array.from(
    new Set(
      [
        normalizeOrigin(getActivePublicOrigin() || ""),
        normalizeOrigin(String(getPublicStatus()?.canonicalOrigin || "").trim()),
        normalizeOrigin(String(getPublicStatus()?.publicOrigin || "").trim()),
        normalizeOrigin(process.env.CONTENTBOX_PUBLIC_ORIGIN || ""),
        normalizeOrigin(process.env.PUBLIC_ORIGIN || ""),
        normalizeOrigin(process.env.APP_PUBLIC_ORIGIN || "")
      ].filter(Boolean) as string[]
    )
  );
  let signingNodeUrl: string | null = null;
  const discoveryChecks: Array<{ origin: string; ok: boolean }> = [];
  for (const candidate of originCandidates) {
    const ok = await hasDiscoveryKey(candidate);
    discoveryChecks.push({ origin: candidate, ok });
    if (ok) {
      signingNodeUrl = candidate;
      break;
    }
  }
  if (!signingNodeUrl) {
    const err: any = new Error("INVITE_NODE_URL_UNREACHABLE");
    err.code = "INVITE_NODE_URL_UNREACHABLE";
    err.discoveryChecks = discoveryChecks;
    err.originCandidates = originCandidates;
    throw err;
  }
  const payload = {
    token,
    remoteUserId: userId,
    remoteUserEmail: user?.email || null,
    nodeUrl: signingNodeUrl,
    ts: new Date().toISOString(),
    nonce: crypto.randomUUID(),
    aud: normalizeOrigin(opts?.audienceOrigin || "") || null
  };
  const payloadStr = JSON.stringify(payload);
  const privPath = path.join(CONTENTBOX_ROOT, ".node", "node_private.pem");
  const privPem = await fs.readFile(privPath, "utf8");
  const sigBuf = (crypto.sign as any)(null, Buffer.from(payloadStr), privPem) as Buffer;
  return { payload, signature: sigBuf.toString("base64") };
}

app.get("/api/local/signing-capability", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = asString((req.user as JwtUser)?.sub || "").trim();
  const user = await prisma.user.findUnique({ where: { id: userId }, select: { id: true, email: true } });
  const keyVerified = await hasVerifiedParticipantKey(userId);
  let canSign = false;
  let reason: string | null = null;
  try {
    await fs.access(path.join(CONTENTBOX_ROOT, ".node", "node_private.pem"), fsSync.constants.R_OK);
    canSign = true;
  } catch {
    canSign = false;
    reason = "INVITE_KEY_MISSING";
  }
  return reply.send({
    ok: true,
    userId,
    email: user?.email || null,
    keyVerified,
    canSign,
    reason
  });
});

// Local node: sign an acceptance payload for a token (used when accepting on a remote owner node)
app.post("/local/sign-acceptance", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const token = asString((req.body ?? {})?.token || "");
  const audienceOrigin = asString((req.body ?? {})?.audienceOrigin || "");
  if (!token) return badRequest(reply, "token required");

  const userId = (req.user as JwtUser).sub;

  try {
    const signed = await signInviteAcceptancePayload(token, userId, { audienceOrigin });
    return reply.send(signed);
  } catch (e: any) {
    return reply.code(500).send({ error: String((e as any)?.message || String(e)) });
  }
});

// Get audit events for a split version
app.get("/split-versions/:id/audit", { preHandler: [requireAuth, requireFeature("splits")] }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const splitVersionId = asString((req.params as any).id);

  const sv = await prisma.splitVersion.findUnique({ where: { id: splitVersionId }, include: { content: true } });
  if (!sv) return notFound(reply, "Split version not found");
  if (sv.content.ownerUserId !== userId) {
    const ok = await isAcceptedParticipant(userId, sv.contentId);
    if (!ok) return forbidden(reply);
  }

  const events = await prisma.auditEvent.findMany({
    where: { entityType: "SplitVersion", entityId: splitVersionId },
    orderBy: { createdAt: "desc" },
    include: { user: { select: { id: true, email: true, displayName: true } } }
  });

  return reply.send(
    events.map((e) => ({
      id: e.id,
      action: e.action,
      payload: e.payloadJson || null,
      userId: e.userId,
      user: e.user ? { id: e.user.id, email: e.user.email, displayName: e.user.displayName } : null,
      createdAt: e.createdAt ? e.createdAt.toISOString() : null
    }))
  );
});

