// Scoped royalty history for current user
app.get("/me/royalty-history", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const me = await prisma.user.findUnique({ where: { id: userId }, select: { id: true, email: true, displayName: true } });
  if (!me) return reply.send([]);

  const participantRows = await prisma.splitParticipant.findMany({
    where: {
      OR: [
        { participantUserId: userId },
        me.email ? { participantEmail: emailEquals(me.email) } : undefined
      ].filter(Boolean) as any
    },
    select: { id: true }
  });
  const participantIds = participantRows.map((p) => p.id);
  if (participantIds.length === 0 && !me.email) {
    return reply.send([]);
  }

  const settlementLines = await prisma.settlementLine.findMany({
    where: {
      OR: [
        participantIds.length ? { participantId: { in: participantIds } } : undefined,
        me.email ? { participantEmail: emailEquals(me.email) } : undefined
      ].filter(Boolean) as any
    },
    include: {
      settlement: { include: { payment: true, content: { include: { owner: true } }, lines: true } }
    }
  });

  const settlementMap = new Map<string, typeof settlementLines[0]["settlement"]>();
  for (const l of settlementLines) {
    if (l.settlement) settlementMap.set(l.settlement.id, l.settlement);
  }

  const settlementEvents: HistoryEvent[] = Array.from(settlementMap.values()).map((s) => {
    const total = s.payment?.amountSats ? BigInt(s.payment.amountSats as any) : BigInt(0);
    const sumLines = s.lines.reduce((acc, ln) => acc + BigInt(ln.amountSats as any), BigInt(0));
    const totalsMatch = total === sumLines;
    return {
      id: `settlement:${s.id}`,
      ts: s.createdAt.toISOString(),
      category: "royalty",
      type: "settlement.created",
      title: `Settlement • ${s.content?.title || "Content"}`,
      summary: `${sumLines.toString()} sats`,
      actor: actorFromUser(s.content?.owner ? { id: s.content.owner.id, email: s.content.owner.email, displayName: s.content.owner.displayName } : null),
      details: {
        paymentIntentId: s.paymentIntentId,
        amountSats: total.toString(),
        lines: s.lines.map((ln) => ({
          participantId: ln.participantId || null,
          participantEmail: ln.participantEmail || null,
          role: ln.role || null,
          amountSats: BigInt(ln.amountSats as any).toString()
        }))
      },
      diff: { totalsMatch }
    };
  });

  const paymentIntents = await prisma.paymentIntent.findMany({
    where: { buyerUserId: userId },
    include: { content: true }
  });

  const paymentEvents: HistoryEvent[] = paymentIntents.map((p) => ({
    id: `payment:${p.id}`,
    ts: p.createdAt.toISOString(),
    category: "royalty",
    type: "payment.intent",
    title: `Purchase • ${p.content?.title || "Content"}`,
    summary: `${BigInt(p.amountSats as any).toString()} sats • ${p.status}`,
    actor: actorFromUser(me),
    details: {
      amountSats: BigInt(p.amountSats as any).toString(),
      status: p.status,
      purpose: p.purpose,
      paidAt: p.paidAt ? p.paidAt.toISOString() : null
    }
  }));

  const out = [...settlementEvents, ...paymentEvents].sort((a, b) => (a.ts < b.ts ? 1 : -1));
  return reply.send(jsonSafe(out));
});

// Scoped clearance history for a derivative link
app.get("/content-links/:id/clearance-history", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const linkId = asString((req.params as any).id);

  const link = await prisma.contentLink.findUnique({
    where: { id: linkId },
    include: {
      parentContent: { select: { id: true, title: true, ownerUserId: true } },
      childContent: { select: { id: true, title: true, ownerUserId: true } },
      approvedBy: { select: { id: true, email: true, displayName: true } }
    }
  });
  if (!link) return notFound(reply, "Link not found");
  if (link.parentContent?.ownerUserId !== userId && link.childContent?.ownerUserId !== userId) return forbidden(reply);

  const requests = await prisma.clearanceRequest.findMany({
    where: { contentLinkId: linkId },
    orderBy: { createdAt: "desc" }
  });
  const tokens = await prisma.approvalToken.findMany({
    where: { contentLinkId: linkId },
    orderBy: { createdAt: "desc" }
  });

  const events: HistoryEvent[] = [];
  for (const r of requests) {
    events.push({
      id: `clearance.request:${r.id}`,
      ts: r.createdAt.toISOString(),
      category: "clearance",
      type: "clearance.requested",
      title: `Clearance requested • ${link.childContent?.title || "Derivative"}`,
      summary: r.status,
      actor: actorFromUser(r.requestedByUserId ? { id: r.requestedByUserId } as any : null),
      details: { status: r.status }
    });
    if (r.reviewGrantedAt) {
      events.push({
        id: `clearance.reviewGranted:${r.id}`,
        ts: r.reviewGrantedAt.toISOString(),
        category: "clearance",
        type: "clearance.reviewGranted",
        title: "Preview access granted",
        summary: null,
        actor: r.reviewGrantedByUserId ? actorFromUser({ id: r.reviewGrantedByUserId } as any) : null
      });
    }
  }

  for (const t of tokens) {
    events.push({
      id: `clearance.token:${t.id}`,
      ts: t.createdAt.toISOString(),
      category: "clearance",
      type: "clearance.token.created",
      title: "Approval token issued",
      summary: t.approverEmail,
      actor: actorExternal(t.approverEmail),
      details: { expiresAt: t.expiresAt.toISOString() }
    });
    if (t.usedAt) {
      events.push({
        id: `clearance.vote:${t.id}`,
        ts: t.usedAt.toISOString(),
        category: "clearance",
        type: "clearance.vote",
        title: `Vote ${t.decision || "UNKNOWN"}`,
        summary: t.approverEmail,
        actor: actorExternal(t.approverEmail),
        details: {
          decision: t.decision,
          upstreamRatePercent: t.upstreamRatePercent ? String(t.upstreamRatePercent) : null
        }
      });
    }
  }

  if (link.approvedAt) {
    events.push({
      id: `clearance.cleared:${link.id}`,
      ts: link.approvedAt.toISOString(),
      category: "clearance",
      type: "clearance.cleared",
      title: "Cleared for public release",
      summary: `${(link.upstreamBps || 0) / 100}% upstream`,
      actor: actorFromUser(link.approvedBy ? { id: link.approvedBy.id, email: link.approvedBy.email, displayName: link.approvedBy.displayName } : null),
      details: { upstreamBps: link.upstreamBps }
    });
  }

  events.sort((a, b) => (a.ts < b.ts ? 1 : -1));
  return reply.send(jsonSafe(events));
});

// Scoped invite history for current user
app.get("/me/invite-history", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const me = await prisma.user.findUnique({ where: { id: userId }, select: { id: true, email: true, displayName: true } });
  if (!me) return reply.send([]);

  const invites = await prisma.invitation.findMany({
    where: {
      OR: [
        { splitParticipant: { splitVersion: { content: { ownerUserId: userId } } } },
        { splitParticipant: { participantUserId: userId } },
        me.email ? { splitParticipant: { participantEmail: emailEquals(me.email) } } : undefined
      ].filter(Boolean) as any
    },
    include: {
      splitParticipant: { include: { splitVersion: { include: { content: true } } } }
    },
    orderBy: { createdAt: "desc" }
  });

  const events: HistoryEvent[] = [];
  for (const inv of invites) {
    const contentTitle = inv.splitParticipant?.splitVersion?.content?.title || "Content";
    const ownerId = inv.splitParticipant?.splitVersion?.content?.ownerUserId || null;
    if (ownerId === userId) {
      events.push({
        id: `invite.sent:${inv.id}`,
        ts: inv.createdAt.toISOString(),
        category: "invite",
        type: "invite.sent",
        title: `Invite sent • ${contentTitle}`,
        summary: inv.splitParticipant?.participantEmail || null,
        actor: actorFromUser(me),
        details: { expiresAt: inv.expiresAt.toISOString() }
      });
    }
    events.push({
      id: `invite.received:${inv.id}`,
      ts: inv.createdAt.toISOString(),
      category: "invite",
      type: "invite.received",
      title: `Invite received • ${contentTitle}`,
      summary: inv.splitParticipant?.participantEmail || null,
      actor: actorFromUser(me),
      details: { expiresAt: inv.expiresAt.toISOString() }
    });
    if (inv.acceptedAt) {
      events.push({
        id: `invite.accepted:${inv.id}`,
        ts: inv.acceptedAt.toISOString(),
        category: "invite",
        type: "invite.accepted",
        title: `Invite accepted • ${contentTitle}`,
        summary: inv.splitParticipant?.participantEmail || null,
        actor: actorFromUser(me)
      });
    }
  }

  const remoteInvites = await prisma.remoteInvite.findMany({
    where: { userId },
    orderBy: { createdAt: "desc" }
  });
  for (const inv of remoteInvites) {
    const contentTitle = inv.contentTitle || "Remote content";
    events.push({
      id: `invite.remote.received:${inv.id}`,
      ts: inv.createdAt.toISOString(),
      category: "invite",
      type: "invite.remote.received",
      title: `Remote invite received • ${contentTitle}`,
      summary: inv.participantEmail || null,
      actor: actorFromUser(me),
      details: { remoteOrigin: inv.remoteOrigin, inviteUrl: inv.inviteUrl }
    });
    if (inv.acceptedAt) {
      events.push({
        id: `invite.remote.accepted:${inv.id}`,
        ts: inv.acceptedAt.toISOString(),
        category: "invite",
        type: "invite.remote.accepted",
        title: `Remote invite accepted • ${contentTitle}`,
        summary: inv.participantEmail || null,
        actor: actorFromUser(me),
        details: { remoteOrigin: inv.remoteOrigin, inviteUrl: inv.inviteUrl }
      });
    }
  }

  events.sort((a, b) => (a.ts < b.ts ? 1 : -1));
  return reply.send(jsonSafe(events));
});

// Unified audit endpoint (evidence-grade)
app.get("/audit", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const q = (req.query || {}) as { scopeType?: string; scopeId?: string };
  const scopeType = asString(q.scopeType || "").trim();
  const scopeId = asString(q.scopeId || "").trim() || null;

  if (!scopeType) return badRequest(reply, "scopeType required");

  const events: AuditEventOut[] = [];

  if (scopeType === "content" && scopeId) {
    const content = await prisma.contentItem.findUnique({ where: { id: scopeId }, include: { owner: true } });
    if (!content) return notFound(reply, "Content not found");
    if (content.ownerUserId !== userId) {
      const ok = await isAcceptedParticipant(userId, content.id);
      if (!ok) return forbidden(reply);
    }

    events.push({
      id: `content.snapshot:${content.id}`,
      ts: content.createdAt.toISOString(),
      type: "content.snapshot",
      summary: content.title,
      actor: actorFromUser(content.owner ? { id: content.owner.id, email: content.owner.email, displayName: content.owner.displayName } : null),
      details: {
        id: content.id,
        ownerUserId: content.ownerUserId,
        type: content.type,
        status: content.status,
        storefrontStatus: content.storefrontStatus,
        createdAt: content.createdAt.toISOString()
      }
    });

    const files = await prisma.contentFile.findMany({ where: { contentId: content.id }, orderBy: { createdAt: "desc" } });
    files.forEach((f) => {
      events.push({
        id: `file:${f.id}`,
        ts: f.createdAt.toISOString(),
        type: "content.file",
        summary: f.originalName || f.objectKey,
        details: {
          objectKey: f.objectKey,
          originalName: f.originalName,
          mime: f.mime,
          sizeBytes: f.sizeBytes ? f.sizeBytes.toString() : null,
          sha256: f.sha256,
          createdAt: f.createdAt.toISOString()
        }
      });
    });

    const audits = await prisma.auditEvent.findMany({
      where: { entityType: "ContentItem", entityId: content.id },
      orderBy: { createdAt: "desc" },
      include: { user: { select: { id: true, email: true, displayName: true } } }
    });
    audits.forEach((e) => {
      events.push({
        id: `content.audit:${e.id}`,
        ts: e.createdAt.toISOString(),
        type: e.action,
        summary: content.title,
        actor: actorFromUser(e.user),
        details: e.payloadJson || null
      });
    });

    // Commerce evidence enrichment (read-only, owner-only):
    // Adds sale/payment/settlement/payout snapshots so content-scoped audit can explain money flow
    // without changing settlement logic or payout execution behavior.
    if (content.ownerUserId === userId) {
      const [salesRows, paymentIntentRows, settlementRows, participantPayoutRows] = await Promise.all([
        prisma.sale.findMany({
          where: { contentId: content.id },
          orderBy: { recognizedAt: "desc" },
          take: 50,
          select: {
            id: true,
            intentId: true,
            amountSats: true,
            currency: true,
            rail: true,
            memo: true,
            recognizedAt: true
          }
        }),
        prisma.paymentIntent.findMany({
          where: { contentId: content.id, purpose: "CONTENT_PURCHASE" as any },
          orderBy: { createdAt: "desc" },
          take: 50,
          select: {
            id: true,
            status: true,
            amountSats: true,
            providerId: true,
            paidAt: true,
            createdAt: true,
            updatedAt: true
          }
        }),
        prisma.settlement.findMany({
          where: { contentId: content.id },
          orderBy: { createdAt: "desc" },
          take: 50,
          select: {
            id: true,
            paymentIntentId: true,
            netAmountSats: true,
            createdAt: true
          }
        }),
        prisma.participantPayout
          .findMany({
            where: {
              allocation: {
                contentId: content.id
              }
            },
            orderBy: { updatedAt: "desc" },
            take: 100,
            select: {
              id: true,
              paymentIntentId: true,
              providerPaymentIntentId: true,
              amountSats: true,
              status: true,
              payoutRail: true,
              destinationType: true,
              destinationSummary: true,
              payoutReference: true,
              remittedAt: true,
              updatedAt: true,
              allocation: {
                select: {
                  role: true,
                  participantEmail: true,
                  participantUserId: true
                }
              }
            }
          })
          .catch((err: any) => {
            if (isMissingParticipantPayoutTableError(err)) return [];
            throw err;
          })
      ]);

      salesRows.forEach((row) => {
        events.push({
          id: `sale:${row.id}`,
          ts: row.recognizedAt.toISOString(),
          type: "sale.recognized",
          summary: content.title,
          details: {
            saleId: row.id,
            paymentIntentId: row.intentId,
            amountSats: String(row.amountSats || "0"),
            currency: row.currency,
            rail: row.rail,
            memo: row.memo || null
          }
        });
      });

      paymentIntentRows.forEach((row) => {
        events.push({
          id: `payment.intent:${row.id}`,
          ts: (row.paidAt || row.updatedAt || row.createdAt).toISOString(),
          type: "payment.intent",
          summary: content.title,
          details: {
            paymentIntentId: row.id,
            status: String(row.status || "").toLowerCase(),
            amountSats: String(row.amountSats || "0"),
            providerId: row.providerId || null,
            paidAt: row.paidAt ? row.paidAt.toISOString() : null
          }
        });
      });

      settlementRows.forEach((row) => {
        events.push({
          id: `settlement:${row.id}`,
          ts: row.createdAt.toISOString(),
          type: "settlement.created",
          summary: content.title,
          details: {
            settlementId: row.id,
            paymentIntentId: row.paymentIntentId,
            netAmountSats: String(row.netAmountSats || "0")
          }
        });
      });

      participantPayoutRows.forEach((row) => {
        events.push({
          id: `participant_payout:${row.id}`,
          ts: (row.remittedAt || row.updatedAt).toISOString(),
          type: "payout.participant",
          summary: content.title,
          details: {
            participantPayoutId: row.id,
            paymentIntentId: row.paymentIntentId,
            providerPaymentIntentId: row.providerPaymentIntentId || null,
            amountSats: String(row.amountSats || "0"),
            status: parseParticipantPayoutStatus(row.status),
            payoutRail: row.payoutRail || null,
            destinationType: row.destinationType || null,
            destinationSummary: row.destinationSummary || null,
            payoutReference: row.payoutReference || null,
            remittedAt: row.remittedAt ? row.remittedAt.toISOString() : null,
            participant: {
              role: row.allocation?.role || null,
              participantEmail: row.allocation?.participantEmail || null,
              participantUserId: row.allocation?.participantUserId || null
            }
          }
        });
      });
    }
  } else if (scopeType === "split") {
    if (!scopeId) {
      const splitVersions = await prisma.splitVersion.findMany({
        where: {
          content: {
            OR: [
              { ownerUserId: userId },
              { splitVersions: { some: { participants: { some: { participantUserId: userId, acceptedAt: { not: null } } } } } }
            ]
          }
        },
        include: { content: true, participants: true },
        orderBy: { createdAt: "desc" },
        take: 25
      });

      splitVersions.forEach((sv) => {
        events.push({
          id: `split.snapshot:${sv.id}`,
          ts: sv.createdAt.toISOString(),
          type: "split.snapshot",
          summary: sv.content.title,
          details: {
            splitVersionId: sv.id,
            versionNumber: sv.versionNumber,
            status: sv.status,
            lockedAt: sv.lockedAt ? sv.lockedAt.toISOString() : null,
            participants: sv.participants.map((p) => ({
              id: p.id,
              participantEmail: p.participantEmail,
              participantUserId: p.participantUserId,
              role: p.role,
              bps: p.bps,
              percent: String(p.percent),
              acceptedAt: p.acceptedAt ? p.acceptedAt.toISOString() : null
            }))
          }
        });
      });
    } else {
      const sv = await prisma.splitVersion.findUnique({
        where: { id: scopeId },
        include: { content: true, participants: true }
      });
      if (!sv) return notFound(reply, "Split version not found");
    if (sv.content.ownerUserId !== userId) {
      const ok = await isAcceptedParticipant(userId, sv.contentId);
      if (!ok) return forbidden(reply);
    }

    events.push({
      id: `split.snapshot:${sv.id}`,
      ts: sv.createdAt.toISOString(),
      type: "split.snapshot",
      summary: sv.content.title,
      details: {
        splitVersionId: sv.id,
        versionNumber: sv.versionNumber,
        status: sv.status,
        lockedAt: sv.lockedAt ? sv.lockedAt.toISOString() : null,
        participants: sv.participants.map((p) => ({
          id: p.id,
          participantEmail: p.participantEmail,
          participantUserId: p.participantUserId,
          role: p.role,
          bps: p.bps,
          percent: String(p.percent),
          acceptedAt: p.acceptedAt ? p.acceptedAt.toISOString() : null
        }))
      }
    });

      const audits = await prisma.auditEvent.findMany({
        where: { entityType: "SplitVersion", entityId: sv.id },
        orderBy: { createdAt: "desc" },
        include: { user: { select: { id: true, email: true, displayName: true } } }
      });
      audits.forEach((e) => {
        events.push({
          id: `split.audit:${e.id}`,
          ts: e.createdAt.toISOString(),
          type: e.action,
          summary: sv.content.title,
          actor: actorFromUser(e.user),
          details: e.payloadJson || null,
          diff: (e.payloadJson as any)?.diff || null
        });
      });
    }
  } else if (scopeType === "invite") {
    const me = await prisma.user.findUnique({ where: { id: userId }, select: { id: true, email: true, displayName: true } });
    const invites = await prisma.invitation.findMany({
      where: {
        OR: [
          { splitParticipant: { splitVersion: { content: { ownerUserId: userId } } } },
          { splitParticipant: { participantUserId: userId } },
          me?.email ? { splitParticipant: { participantEmail: emailEquals(me.email) } } : undefined
        ].filter(Boolean) as any
      },
      include: { splitParticipant: { include: { splitVersion: { include: { content: true } } } } },
      orderBy: { createdAt: "desc" }
    });

    invites.forEach((inv) => {
      events.push({
        id: `invite:${inv.id}`,
        ts: inv.createdAt.toISOString(),
        type: "invite",
        summary: inv.splitParticipant?.participantEmail || null,
        actor: actorFromUser(me ? { id: me.id, email: me.email, displayName: me.displayName } : null),
        details: {
          id: inv.id,
          splitParticipantId: inv.splitParticipantId,
          contentId: inv.splitParticipant?.splitVersion?.contentId,
          contentTitle: inv.splitParticipant?.splitVersion?.content?.title,
          expiresAt: inv.expiresAt.toISOString(),
          acceptedAt: inv.acceptedAt ? inv.acceptedAt.toISOString() : null
        }
      });
    });

    const remoteInvites = await prisma.remoteInvite.findMany({
      where: { userId },
      orderBy: { createdAt: "desc" }
    });
    remoteInvites.forEach((inv) => {
      events.push({
        id: `invite.remote:${inv.id}`,
        ts: inv.createdAt.toISOString(),
        type: inv.acceptedAt ? "invite.remote.accepted" : "invite.remote.received",
        summary: inv.participantEmail || null,
        actor: actorFromUser(me ? { id: me.id, email: me.email, displayName: me.displayName } : null),
        details: {
          id: inv.id,
          contentId: inv.contentId,
          contentTitle: inv.contentTitle,
          remoteOrigin: inv.remoteOrigin,
          inviteUrl: inv.inviteUrl,
          acceptedAt: inv.acceptedAt ? inv.acceptedAt.toISOString() : null
        }
      });
    });

    // Invite evidence enrichment (read-only):
    // Include persisted invitation audit trail rows when present.
    const inviteIds = Array.from(new Set(invites.map((inv) => String(inv.id || "").trim()).filter(Boolean)));
    if (inviteIds.length) {
      const inviteAudits = await prisma.auditEvent.findMany({
        where: { entityType: "Invitation", entityId: { in: inviteIds } as any },
        orderBy: { createdAt: "desc" },
        take: 200,
        include: { user: { select: { id: true, email: true, displayName: true } } }
      });
      inviteAudits.forEach((e) => {
        events.push({
          id: `invite.audit:${e.id}`,
          ts: e.createdAt.toISOString(),
          type: e.action,
          actor: actorFromUser(e.user),
          details: e.payloadJson || null
        });
      });
    }
  } else if (scopeType === "royalty") {
    const me = await prisma.user.findUnique({ where: { id: userId }, select: { id: true, email: true, displayName: true } });
    const participantRows = await prisma.splitParticipant.findMany({
      where: {
        OR: [
          { participantUserId: userId },
          me?.email ? { participantEmail: emailEquals(me.email) } : undefined
        ].filter(Boolean) as any
      },
      select: { id: true }
    });
    const participantIds = participantRows.map((p) => p.id);
    const lines = await prisma.settlementLine.findMany({
      where: {
        OR: [
          participantIds.length ? { participantId: { in: participantIds } } : undefined,
          me?.email ? { participantEmail: emailEquals(me.email) } : undefined
        ].filter(Boolean) as any
      },
      include: {
        settlement: { include: { payment: true, content: true, lines: true } }
      }
    });
    const settlementMap = new Map<string, typeof lines[0]["settlement"]>();
    lines.forEach((l) => {
      if (l.settlement) settlementMap.set(l.settlement.id, l.settlement);
    });
    for (const s of settlementMap.values()) {
      const total = s.payment?.amountSats ? BigInt(s.payment.amountSats as any) : BigInt(0);
      const sumLines = s.lines.reduce((acc, ln) => acc + BigInt(ln.amountSats as any), BigInt(0));
      events.push({
        id: `settlement:${s.id}`,
        ts: s.createdAt.toISOString(),
        type: "settlement",
        summary: s.content?.title || null,
        details: {
          amountSats: total.toString(),
          totalsMatch: total === sumLines,
          lines: s.lines.map((ln) => ({
            participantId: ln.participantId || null,
            participantEmail: ln.participantEmail || null,
            role: ln.role || null,
            amountSats: BigInt(ln.amountSats as any).toString()
          }))
        }
      });
    }

    // Royalty evidence enrichment (read-only):
    // Append participant payout execution rows for this account so payable/paid state is auditable.
    const payoutRows = await prisma.participantPayout
      .findMany({
        where: {
          allocation: {
            ...participantPayoutUserAllocationWhere(userId, me?.email || "")
          }
        },
        orderBy: [{ remittedAt: "desc" }, { updatedAt: "desc" }],
        take: 200,
        select: {
          id: true,
          paymentIntentId: true,
          providerPaymentIntentId: true,
          amountSats: true,
          status: true,
          payoutRail: true,
          destinationType: true,
          destinationSummary: true,
          payoutReference: true,
          remittedAt: true,
          updatedAt: true,
          allocation: {
            select: {
              contentId: true,
              role: true,
              participantEmail: true,
              participantUserId: true
            }
          }
        }
      })
      .catch((err: any) => {
        if (isMissingParticipantPayoutTableError(err)) return [];
        throw err;
      });
    payoutRows.forEach((row) => {
      events.push({
        id: `royalty.payout:${row.id}`,
        ts: (row.remittedAt || row.updatedAt).toISOString(),
        type: "payout.participant",
        summary: row.allocation?.contentId || null,
        details: {
          participantPayoutId: row.id,
          paymentIntentId: row.paymentIntentId,
          providerPaymentIntentId: row.providerPaymentIntentId || null,
          amountSats: String(row.amountSats || "0"),
          status: parseParticipantPayoutStatus(row.status),
          payoutRail: row.payoutRail || null,
          destinationType: row.destinationType || null,
          destinationSummary: row.destinationSummary || null,
          payoutReference: row.payoutReference || null,
          remittedAt: row.remittedAt ? row.remittedAt.toISOString() : null,
          participant: {
            role: row.allocation?.role || null,
            participantEmail: row.allocation?.participantEmail || null,
            participantUserId: row.allocation?.participantUserId || null
          }
        }
      });
    });
  } else if (scopeType === "clearance" && scopeId) {
    const link = await prisma.contentLink.findUnique({
      where: { id: scopeId },
      include: { parentContent: true, childContent: true }
    });
    if (!link) return notFound(reply, "Link not found");
    if (link.parentContent?.ownerUserId !== userId && link.childContent?.ownerUserId !== userId) return forbidden(reply);

    events.push({
      id: `clearance.link:${link.id}`,
      ts: (link.approvedAt || link.childContent?.createdAt || new Date()).toISOString(),
      type: "clearance.link",
      summary: link.childContent?.title || null,
      details: {
        contentLinkId: link.id,
        parentContentId: link.parentContentId,
        childContentId: link.childContentId,
        requiresApproval: link.requiresApproval,
        upstreamBps: link.upstreamBps,
        approvedAt: link.approvedAt ? link.approvedAt.toISOString() : null
      }
    });

    const tokens = await prisma.approvalToken.findMany({ where: { contentLinkId: link.id }, orderBy: { createdAt: "desc" } });
    tokens.forEach((t) => {
      events.push({
        id: `clearance.token:${t.id}`,
        ts: t.createdAt.toISOString(),
        type: "clearance.vote",
        summary: t.approverEmail,
        actor: actorExternal(t.approverEmail),
        details: {
          decision: t.decision,
          weightBps: t.weightBps,
          upstreamRatePercent: t.upstreamRatePercent ? String(t.upstreamRatePercent) : null,
          usedAt: t.usedAt ? t.usedAt.toISOString() : null
        }
      });
    });
  } else if (scopeType === "identity") {
    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user) return reply.send({ ok: true, scopeType, scopeId, audit: [] });
    events.push({
      id: `identity:${user.id}`,
      ts: user.createdAt.toISOString(),
      type: "identity.snapshot",
      summary: user.email,
      details: {
        id: user.id,
        email: user.email,
        displayName: user.displayName || null,
        avatarUrl: user.avatarUrl || null
      }
    });

    // Identity evidence enrichment (read-only):
    // Include payout destination/config changes already captured as Identity audit rows.
    const identityAudits = await prisma.auditEvent.findMany({
      where: { entityType: "Identity", entityId: user.id },
      orderBy: { createdAt: "desc" },
      take: 200,
      include: { user: { select: { id: true, email: true, displayName: true } } }
    });
    identityAudits.forEach((e) => {
      events.push({
        id: `identity.audit:${e.id}`,
        ts: e.createdAt.toISOString(),
        type: e.action,
        actor: actorFromUser(e.user),
        details: e.payloadJson || null
      });
    });
  } else if (scopeType === "library") {
    const content = await prisma.contentItem.findMany({
      where: { ownerUserId: userId, deletedAt: null },
      orderBy: { createdAt: "desc" },
      take: 25
    });
    content.forEach((c) => {
      events.push({
        id: `library:${c.id}`,
        ts: c.createdAt.toISOString(),
        type: "content.created",
        summary: c.title,
        details: { id: c.id, type: c.type, status: c.status, storefrontStatus: c.storefrontStatus }
      });
    });

    // Library evidence enrichment (read-only):
    // Include latest content-level audit actions across the current owner's catalog.
    const contentIds = content.map((c) => c.id);
    if (contentIds.length) {
      const contentAudits = await prisma.auditEvent.findMany({
        where: { entityType: "ContentItem", entityId: { in: contentIds } as any },
        orderBy: { createdAt: "desc" },
        take: 250,
        include: { user: { select: { id: true, email: true, displayName: true } } }
      });
      contentAudits.forEach((e) => {
        events.push({
          id: `library.audit:${e.id}`,
          ts: e.createdAt.toISOString(),
          type: e.action,
          actor: actorFromUser(e.user),
          details: e.payloadJson || null
        });
      });
    }
  } else {
    return badRequest(reply, "Unsupported scopeType");
  }

  events.sort((a, b) => (a.ts < b.ts ? 1 : -1));
  const typedEvents = events.map((event) => ({
    ...event,
    archetype: resolveAuditArchetype(scopeType, event.type)
  }));
  return reply.send(jsonSafe({ ok: true, scopeType, scopeId, audit: typedEvents }));
});

// Invite audit history (owner only)
app.get("/invites/:id/audit", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const inviteId = asString((req.params as any).id);

  const inv = await prisma.invitation.findUnique({
    where: { id: inviteId },
    include: { splitParticipant: { include: { splitVersion: { include: { content: true } } } } }
  });
  if (!inv) return notFound(reply, "Invite not found");

  // If expired, log once for audit (owner id)
  try {
    if (inv.expiresAt.getTime() < Date.now()) {
      const ownerId = inv.splitParticipant?.splitVersion?.content?.ownerUserId || "";
      if (ownerId) {
        const prior = await prisma.auditEvent.findFirst({
          where: { entityType: "Invitation", entityId: inv.id, action: "invite.expire" }
        });
        if (!prior) {
          await prisma.auditEvent.create({
            data: {
              userId: ownerId,
              action: "invite.expire",
              entityType: "Invitation",
              entityId: inv.id,
              payloadJson: { expiresAt: inv.expiresAt } as any
            }
          });
        }
      }
    }
  } catch {}
  if (inv.splitParticipant?.splitVersion?.content?.ownerUserId !== userId) return forbidden(reply);

  const events = await prisma.auditEvent.findMany({
    where: { entityType: "Invitation", entityId: inviteId },
    orderBy: { createdAt: "desc" },
    include: { user: { select: { id: true, email: true, displayName: true } } }
  });

  return reply.send(
    events.map((e) => ({
      id: e.id,
      action: e.action,
      payload: e.payloadJson || null,
      userId: e.userId,
      user: e.user ? { id: e.user.id, email: e.user.email, displayName: e.user.displayName } : null,
      createdAt: e.createdAt
    }))
  );
});

// Export proof bundle for a content item (owner only)
app.get("/api/proofs/content/:contentId", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const proofCtx = getCapabilityContext();
  if (sendAdvancedInactive(reply, proofCtx)) return;
  if (!canUseProofBundles(proofCtx)) {
    return reply.code(403).send({
      code: "proofs_not_allowed",
      reason: capabilityReason(proofCtx, "proofs", capabilityReasonContext(proofCtx))
    });
  }
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);
  const includeSettlement = asString((req.query as any)?.includeSettlement || "").trim();

  const content = await prisma.contentItem.findUnique({
    where: { id: contentId },
    include: {
      manifest: true,
      splitVersions: { include: { participants: true } }
    }
  });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) return forbidden(reply);
  if (!content.manifest) return reply.code(409).send({ error: "Manifest not found" });

  const split =
    content.splitVersions.find((s: any) => s.id === content.currentSplitId) ||
    content.splitVersions.find((s: any) => s.status === "locked") ||
    content.splitVersions.sort((a: any, b: any) => b.versionNumber - a.versionNumber)[0];
  if (!split) return reply.code(409).send({ error: "Split version not found" });

  const { anchor: splitAnchor, participants } = await buildSplitAnchorFromVersion(split);
  const publishAnchor = buildPublishAnchor(content, splitAnchor, content.manifest);

  let settlement: SettlementReceipt | undefined;
  let lines: ProofSettlementLine[] | undefined;

  if (includeSettlement) {
    const settlementRec = await prisma.settlement.findUnique({
      where: { id: includeSettlement },
      include: { lines: true, payment: true }
    });
    if (!settlementRec) return notFound(reply, "Settlement not found");

    const manifestSha256 = String(settlementRec.payment?.manifestSha256 || content.manifest.sha256);
    settlement = {
      settlementId: settlementRec.id,
      paymentRef: settlementRec.paymentIntentId,
      amountSats: toSatsNumber(settlementRec.netAmountSats),
      paidAt: settlementRec.payment?.paidAt
        ? new Date(settlementRec.payment.paidAt as any).toISOString()
        : settlementRec.createdAt.toISOString(),
      contentId: settlementRec.contentId,
      manifestSha256,
      splitVersionId: settlementRec.splitVersionId,
      splitsHash: splitAnchor.splitsHash
    };

    const byId = new Map<string, SplitParticipantRef>();
    const byEmail = new Map<string, SplitParticipantRef>();
    for (const p of participants) {
      if (p.recipientRef.startsWith("email:")) {
        byEmail.set(p.recipientRef.slice(6).toLowerCase(), p);
      }
    }
    for (const p of split.participants || []) {
      if (p.id) {
        byId.set(String(p.id), {
          recipientRef: recipientRefForParticipant(p),
          bps: Math.floor(Number(p.bps || 0)),
          recipientDisplay: recipientDisplayForParticipant(p)
        });
      }
    }

    const rawLines = (settlementRec.lines || []).map((line) => {
      let ref: SplitParticipantRef | undefined;
      if (line.participantId) ref = byId.get(String(line.participantId));
      if (!ref && line.participantEmail) ref = byEmail.get(String(line.participantEmail).toLowerCase());
      const recipientRef = ref?.recipientRef || (line.participantEmail ? `email:${String(line.participantEmail).toLowerCase()}` : "unknown");
      const recipientDisplay = ref?.recipientDisplay || (line.participantEmail ? String(line.participantEmail) : undefined);
      return {
        recipientRef,
        bps: Math.floor(Number(ref?.bps || 0)),
        amountSats: toSatsNumber(line.amountSats as any),
        recipientDisplay
      };
    });
    lines = sortLines(rawLines);
  }

  const parentPublishAnchor = await buildParentPublishAnchor(contentId);

  const bundle: ProofBundleV1 = buildBundle({
    version: "v1",
    generatedAt: new Date().toISOString(),
    publish: publishAnchor,
    split: splitAnchor,
    settlement,
    lines,
    canonicalOrigin: getPublicLinkState().canonicalOrigin,
    parentPublishAnchor
  });

  return reply.send(bundle);
});

/**
 * AUTH
 */
app.get("/auth/recovery/status", async (_req, reply) => {
  const userCount = await prisma.user.count();
  const firstUser =
    userCount > 0
      ? await prisma.user.findFirst({ orderBy: { createdAt: "asc" }, select: { id: true, recoveryKeyHash: true } })
      : null;
  return reply.send({
    hasUsers: userCount > 0,
    hasOwner: Boolean(firstUser?.id),
    recoveryAvailable: Boolean(firstUser?.recoveryKeyHash)
  });
});

app.post("/auth/recovery/reset", async (req, reply) => {
  if (!rateLimit(req, "auth.recovery", 5, 5 * 60_000)) {
    return reply.code(429).send({ error: "Too many attempts. Try again shortly." });
  }
  const body = (req.body ?? {}) as { email?: string; recoveryKey?: string; newPassword?: string };
  const recoveryKey = String(body?.recoveryKey || "").trim();
  const newPassword = String(body?.newPassword || "");
  const email = body?.email ? normalizeEmail(body.email) : "";

  if (!recoveryKey || !newPassword) return badRequest(reply, "recoveryKey and newPassword are required");
  if (newPassword.length < 10) return badRequest(reply, "password must be at least 10 characters");

  const nodeMode = getNodeMode();
  let user = null as any;
  if (nodeMode === "advanced" && !allowMultiUserOverride()) {
    user = await prisma.user.findFirst({ orderBy: { createdAt: "asc" } });
    if (!user) return reply.code(404).send({ code: "user_not_found" });
    if (email && normalizeEmail(email) !== normalizeEmail(user.email)) {
      return reply.code(403).send({ code: "invalid_recovery_key" });
    }
  } else {
    if (email) {
      user = await prisma.user.findUnique({ where: { email } });
    } else {
      const count = await prisma.user.count();
      if (count === 1) user = await prisma.user.findFirst({ orderBy: { createdAt: "asc" } });
    }
    if (!user) return reply.code(404).send({ code: "user_not_found" });
  }

  if (!user.recoveryKeyHash) {
    return reply.code(409).send({ code: "recovery_not_configured", reason: "Recovery is not configured for this user." });
  }
  if (!verifyRecoveryKey(recoveryKey, user.recoveryKeyHash)) {
    return reply.code(403).send({ code: "invalid_recovery_key", reason: "Recovery key is invalid." });
  }

  const passwordHash = await bcrypt.hash(newPassword, 10);
  const updated = await prisma.user.update({
    where: { id: user.id },
    data: { passwordHash, tokenVersion: { increment: 1 } },
    select: { id: true, email: true, displayName: true, createdAt: true, tokenVersion: true }
  });

  const token = app.jwt.sign({ sub: updated.id, tokenVersion: updated.tokenVersion ?? 0 });
  return reply.send({ ok: true, token, user: { id: updated.id, email: updated.email, displayName: updated.displayName, createdAt: updated.createdAt } });
});

app.post("/auth/signup", async (req, reply) => {
  const body = (req.body ?? {}) as { email?: string; password?: string; displayName?: string };

  const email = normalizeEmail(body?.email);
  const password = body?.password;

  if (!email || !password) return badRequest(reply, "email and password are required");
  if (password.length < 8) return badRequest(reply, "password must be at least 8 characters");

  const existing = await prisma.user.findUnique({ where: { email } });
  if (existing) return reply.code(409).send({ error: "email already in use" });
  const nodeMode = getNodeMode();
  if (nodeMode === "advanced" && !allowMultiUserOverride()) {
    const anyUser = await prisma.user.findFirst({ select: { id: true } });
    if (anyUser?.id) {
      return reply.code(403).send({
        error: "SINGLE_IDENTITY_NODE",
        message: "Advanced nodes are single-identity. Log in as the owner or use LAN mode for multi-user."
      });
    }
  }

  const passwordHash = await bcrypt.hash(password, 10);
  const userCount = await prisma.user.count();

  const user = await prisma.user.create({
    data: {
      email,
      displayName: body.displayName?.trim() || null,
      passwordHash
    },
    select: { id: true, email: true, displayName: true, createdAt: true, tokenVersion: true }
  });

  let recoveryKey: string | null = null;
  if (userCount === 0) {
    recoveryKey = generateRecoveryKey();
    const recoveryKeyHash = hashRecoveryKey(recoveryKey);
    await prisma.user.update({
      where: { id: user.id },
      data: { recoveryKeyHash, recoveryKeyCreatedAt: new Date() }
    });
  }

  const token = app.jwt.sign({ sub: user.id, tokenVersion: user.tokenVersion ?? 0 });
  return reply.send({ token, user, recoveryKey: recoveryKey || undefined });
});

// List invitations for content owned by the authenticated user.
app.get("/my/invitations", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const includeHistory = parseBooleanFlag((req.query as any)?.includeHistory, false);
  await pruneOldInvites();

  const invites = await prisma.invitation.findMany({
    where: {
      inviterUserId: userId
    },
    include: {
      splitParticipant: { include: { splitVersion: { include: { content: true } } } }
    },
    orderBy: { createdAt: "desc" }
  });

  const visibleInvites = includeHistory ? invites : invites.filter((inv) => shouldShowInviteInActiveLists(inv as any));
  const displayIds = Array.from(
    new Set(
      visibleInvites.flatMap((inv) => {
        const ids: string[] = [];
        const participantUserId = asString(inv.splitParticipant?.participantUserId || "").trim();
        if (participantUserId) ids.push(participantUserId);
        const targetType = normalizeInviteTargetType(inv.targetType);
        const targetValue = asString(inv.targetValue).trim();
        if ((targetType === "local_user" || targetType === "identity_ref") && targetValue) ids.push(targetValue);
        return ids;
      })
    )
  );
  const displayByUserId = await buildUserDisplayMap(displayIds);
  const inviteBase = await resolveShareableInviteOrigin(req);
  const out = visibleInvites.map((inv) => ({
    ...(() => {
      const participantUserId = asString(inv.splitParticipant?.participantUserId || "").trim();
      const targetType = normalizeInviteTargetType(inv.targetType);
      const targetValue = asString(inv.targetValue).trim();
      const preferredUserId =
        participantUserId || (targetType === "local_user" || targetType === "identity_ref" ? targetValue : "");
      const display = preferredUserId ? displayByUserId.get(preferredUserId) : null;
      const participantDisplayName = resolvePrivateParticipantDisplayLabel({
        participantUserId: participantUserId || null,
        targetType,
        targetValue,
        participantEmail: inv.splitParticipant?.participantEmail || null,
        userDisplayName: display?.displayName || null
      });
      const targetDisplayName = resolvePrivateParticipantDisplayLabel({
        participantUserId: participantUserId || null,
        targetType,
        targetValue,
        participantEmail: inv.splitParticipant?.participantEmail || null,
        userDisplayName:
          targetType === "local_user" || targetType === "identity_ref"
            ? displayByUserId.get(targetValue)?.displayName || null
            : display?.displayName || null
      });
      return { participantDisplayName, targetDisplayName };
    })(),
    token: inv.token,
    id: inv.id,
    splitParticipantId: inv.splitParticipantId,
    participantEmail: inv.splitParticipant?.participantEmail || null,
    participantUserId: inv.splitParticipant?.participantUserId || null,
    targetType: normalizeInviteTargetType(inv.targetType),
    targetValue: asString(inv.targetValue),
    deliveryMethod: normalizeInviteDeliveryMethod(inv.deliveryMethod),
    role: inv.splitParticipant?.role || null,
    percent: percentToPrimitive(inv.splitParticipant?.percent ?? null),
    status:
      normalizeInviteInviteStatusForList(inv),
    inviteUrl: inviteBase ? `${inviteBase.replace(/\/+$/, "")}/invite/${inv.token}` : null,
    contentId: inv.splitParticipant?.splitVersion?.contentId || null,
    contentTitle: inv.splitParticipant?.splitVersion?.content?.title || null,
    contentType: inv.splitParticipant?.splitVersion?.content?.type || null,
    contentStatus: inv.splitParticipant?.splitVersion?.content?.status || null,
    contentDeletedAt: inv.splitParticipant?.splitVersion?.content?.deletedAt
      ? inv.splitParticipant.splitVersion.content.deletedAt.toISOString()
      : null,
    splitVersionId: inv.splitParticipant?.splitVersionId || null,
    splitVersionNum: inv.splitParticipant?.splitVersion?.versionNumber ?? null,
    splitStatus: inv.splitParticipant?.splitVersion?.status || null,
    expiresAt: inv.expiresAt.toISOString(),
    acceptedAt: inv.acceptedAt ? inv.acceptedAt.toISOString() : null,
    acceptedByUserId: inv.acceptedByUserId || null,
    revokedAt: inv.revokedAt ? inv.revokedAt.toISOString() : null,
    tombstonedAt: inv.tombstonedAt ? inv.tombstonedAt.toISOString() : null,
    createdAt: inv.createdAt.toISOString()
  }));

  return reply.send(out);
});

