app.post("/api/buyer/logout", async (req: any, reply: any) => {
  const rawToken = getCookie(req, BUYER_SESSION_COOKIE);
  const sessionId = verifyBuyerSessionToken(rawToken, JWT_SECRET)?.sid || resolveBuyerSessionIdFromToken(rawToken, JWT_SECRET);
  if (sessionId) {
    await prisma.buyerSession.delete({ where: { id: sessionId } }).catch(() => {});
  }
  reply.header("Set-Cookie", buildBuyerClearCookie(req));
  return reply.send({ ok: true });
});

async function requireBuyerSession(req: any, reply: any) {
  const session = await resolveBuyerSession(req, reply);
  if (!session) {
    reply.code(401).send({ error: "Buyer session required" });
    return null;
  }
  return session;
}

const SELF_CLAIM_PER_BUYER_PER_HOUR = Math.max(
  1,
  Number(process.env.SELF_CLAIM_PER_BUYER_PER_HOUR || 10)
);
const SELF_CLAIM_PER_IP_PER_HOUR = Math.max(
  1,
  Number(process.env.SELF_CLAIM_PER_IP_PER_HOUR || 30)
);
const SELF_CLAIM_IP_SALT = String(process.env.SELF_CLAIM_IP_SALT || JWT_SECRET || "").trim();
if (!String(process.env.SELF_CLAIM_IP_SALT || "").trim()) {
  app.log.warn("SELF_CLAIM_IP_SALT not set; falling back to JWT_SECRET for IP hashing.");
}

function getRequestIp(req: any): string | null {
  const headers = req?.headers || {};
  const cf = asString(headers["cf-connecting-ip"]);
  if (cf) return cf;
  const xff = asString(headers["x-forwarded-for"]);
  if (xff) return xff.split(",")[0].trim();
  const sock = req?.socket?.remoteAddress || req?.connection?.remoteAddress;
  return sock ? String(sock) : null;
}

function hashIp(ip: string | null): string | null {
  if (!ip) return null;
  if (!SELF_CLAIM_IP_SALT) return crypto.createHash("sha256").update(ip).digest("hex");
  return crypto.createHmac("sha256", SELF_CLAIM_IP_SALT).update(ip).digest("hex");
}

async function handleBuyerBuys(req: any, reply: any) {
  const session = await requireBuyerSession(req, reply);
  if (!session) return;

  const body = (req.body ?? {}) as { contentId?: string; amountSats?: unknown };
  const contentId = asString(body.contentId || "").trim();
  if (!contentId) return badRequest(reply, "contentId required");

  const { productTier } = resolveProductTier();
  if (productTier !== "basic") {
    app.log.info(
      {
        route: "/api/buyer/buys",
        buyerId: session.buyer.id,
        contentId,
        productTier,
        mappedCode: "PAYMENT_REQUIRED"
      },
      "buyerBuys.self_claim_blocked_non_basic"
    );
    return reply.code(409).send({ code: "PAYMENT_REQUIRED", error: "Payment required in this mode" });
  }

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (!isSaleable(content)) {
    app.log.info(
      {
        route: "/api/buyer/buys",
        buyerId: session.buyer.id,
        contentId,
        productTier,
        mappedCode: "NOT_FOR_SALE"
      },
      "buyerBuys.self_claim_blocked_not_for_sale"
    );
    return reply.code(409).send({ code: "NOT_FOR_SALE", error: "This content is no longer for sale." });
  }
  await reconcileBuyerEntitlementsFromPurchaseHistory({
    buyerId: session.buyer.id,
    contentId
  }).catch(() => {});

  const manifest = await ensureManifestForContent(content);
  if (!manifest?.sha256) return notFound(reply, "Manifest not found");

  // Guardrail: priced releases must be unlocked by real payment flow.
  // Self-claim is only allowed for free/tip-style content.
  const listedPriceSats = content.priceSats == null ? 0n : BigInt(content.priceSats);
  if (listedPriceSats > 0n) {
    app.log.info(
      {
        route: "/api/buyer/buys",
        buyerId: session.buyer.id,
        contentId,
        productTier,
        listedPriceSats: listedPriceSats.toString(),
        mappedCode: "PAYMENT_REQUIRED"
      },
      "buyerBuys.self_claim_blocked_priced_content"
    );
    return reply.code(409).send({ code: "PAYMENT_REQUIRED", error: "Payment required for priced content." });
  }

  const amountSats = parseSats(body.amountSats ?? listedPriceSats);
  if (amountSats < 0n) return badRequest(reply, "amountSats must be >= 0");
  if (amountSats !== listedPriceSats) {
    return reply.code(409).send({ code: "AMOUNT_MISMATCH", error: "Amount must match creator price." });
  }

  const existing = await prisma.entitlement.findFirst({
    where: { buyerId: session.buyer.id, contentId }
  });
  if (existing) {
    return reply.send({ ok: true, alreadyOwned: true, entitlementId: existing.id, redirectUrl: "/library" });
  }

  const ipHash = hashIp(getRequestIp(req));
  const since = new Date(Date.now() - 60 * 60 * 1000);

  const buyerCount = await prisma.paymentIntent.count({
    where: {
      status: "self_claimed",
      createdAt: { gte: since },
      entitlements: { some: { buyerId: session.buyer.id } }
    }
  });
  if (buyerCount >= SELF_CLAIM_PER_BUYER_PER_HOUR) {
    return reply.code(429).send({ error: "Too many self-claims. Try again later." });
  }

  if (ipHash) {
    const ipCount = await prisma.paymentIntent.count({
      where: { status: "self_claimed", createdAt: { gte: since }, ipHash }
    });
    if (ipCount >= SELF_CLAIM_PER_IP_PER_HOUR) {
      return reply.code(429).send({ error: "Too many self-claims. Try again later." });
    }
  }

  try {
    const created = await prisma.$transaction(async (tx) => {
      const existingInside = await tx.entitlement.findFirst({
        where: { buyerId: session.buyer.id, contentId }
      });
      if (existingInside) {
        return { alreadyOwned: true, entitlementId: existingInside.id };
      }

      const intent = await tx.paymentIntent.create({
        data: {
          buyerUserId: null,
          contentId,
          manifestSha256: manifest.sha256,
          amountSats,
          status: "self_claimed" as any,
          purpose: "CONTENT_PURCHASE" as any,
          subjectType: "CONTENT" as any,
          subjectId: contentId,
          memo: "SELF_CLAIM",
          paidAt: null,
          ipHash
        }
      });

      const entitlement = await tx.entitlement.create({
        data: {
          buyerId: session.buyer.id,
          buyerUserId: null,
          contentId,
          manifestSha256: manifest.sha256,
          paymentIntentId: intent.id
        }
      });

      return { alreadyOwned: false, entitlementId: entitlement.id };
    });

    return reply.send({ ok: true, alreadyOwned: created.alreadyOwned, entitlementId: created.entitlementId, redirectUrl: "/library" });
  } catch (e: any) {
    if (e?.code === "P2002") {
      const fallback = await prisma.entitlement.findFirst({
        where: { buyerId: session.buyer.id, contentId }
      });
      if (fallback) {
        return reply.send({ ok: true, alreadyOwned: true, entitlementId: fallback.id, redirectUrl: "/library" });
      }
    }
    throw e;
  }
}

// Record a self-claimed purchase for Basic mode buyers
app.post("/api/buyer/buys", handleBuyerBuys);

// Public delegated provider invoice routes (machine-to-machine, trust-gated by provider relationship records).
// These routes must remain publicly reachable because delegated creators call providerUrl/public/provider/* directly.
app.post("/public/provider/payment-intents", async (req: any, reply: any) => {
  const body = (req.body ?? {}) as {
    creatorNodeId?: string | null;
    contentId?: string | null;
    amountSats?: string | number | null;
    paymentIntentId?: string | null;
    buyerSessionId?: string | null;
    needsProviderInvoicing?: boolean;
    needsDurablePublicHosting?: boolean;
    payoutDestinationType?: CreatorPayoutDestinationType;
    payoutDestinationSummary?: string | null;
    providerRemitMode?: ProviderRemitMode;
    payoutPolicy?: ProviderPayoutPolicy;
    allowProviderFallback?: boolean;
    splitVersionId?: string | null;
    participantAllocations?: Array<{
      participantRef?: string | null;
      participantId?: string | null;
      splitParticipantId?: string | null;
      participantUserId?: string | null;
      participantEmail?: string | null;
      role?: string | null;
      roleKey?: string | null;
      bps?: number | string | null;
      destinationType?: string | null;
      destinationSummary?: string | null;
      destinationValue?: string | null;
      destinationVerified?: boolean | null;
      destinationVerificationError?: string | null;
    }>;
  };
  const creatorNodeId = String(body.creatorNodeId || "").trim();
  const contentId = String(body.contentId || "").trim();
  const amountSats = String(body.amountSats ?? "").trim();
  const paymentIntentId = String(body.paymentIntentId || "").trim();
  if (!creatorNodeId || !contentId || !paymentIntentId) return badRequest(reply, "creatorNodeId, contentId, paymentIntentId required");
  if (!/^\d+$/.test(amountSats) || Number(amountSats) <= 0) return badRequest(reply, "amountSats must be a positive integer");
  const providerAuthority = await resolveProviderExecutionAuthorityOnCurrentNode();
  if (!providerAuthority.ok) {
    return reply.code(409).send({
      error: providerAuthority.code || "PROVIDER_NOT_READY",
      message: providerAuthority.message || "Provider execution is not ready on this node."
    });
  }

  const link = getProviderCreatorLink(creatorNodeId);
  if (!link || link.trustStatus !== "verified" || !link.executionAllowed) {
    return reply.code(409).send({ error: "PROVIDER_CREATOR_RELATIONSHIP_REQUIRED", message: "Provider relationship is not ready." });
  }
  const delegated = listProviderDelegatedPublishes().find((row) => row.contentId === contentId && row.creatorNodeId === creatorNodeId);
  if (!delegated) {
    return reply.code(409).send({ error: "DELEGATED_PUBLISH_REQUIRED", message: "Delegated publish record is required." });
  }

  const existing = findProviderPaymentIntentByPaymentIntentId(paymentIntentId);
  if (existing) {
    return reply.send({
      ok: true,
      paymentIntentId: existing.paymentIntentId,
      bolt11: existing.bolt11,
      providerInvoiceRef: existing.providerInvoiceRef,
      status: existing.status,
      providerFeeSats: existing.providerFeeSats,
      providerInvoicingFeeSats: existing.providerInvoicingFeeSats,
      providerDurableHostingFeeSats: existing.providerDurableHostingFeeSats,
      creatorNetSats: existing.creatorNetSats,
      payoutDestinationType: existing.payoutDestinationType,
      payoutDestinationSummary: existing.payoutDestinationSummary,
      providerRemitMode: existing.providerRemitMode
    });
  }

  const providerIdentity = await buildLocalNodeIdentityDoc().catch(() => null);
  const providerNodeId = providerIdentity?.nodeId || "node:provider-unavailable";
  const memo = await buildRemittanceMemo({
    prefix: "Certifyd delegated",
    paymentIntentId,
    contentId
  });
  let bolt11: string | null = null;
  let providerInvoiceRef: string | null = null;
  try {
    const invoice = await createLightningInvoiceWithRetry(BigInt(amountSats), memo, {
      route: "/public/provider/payment-intents",
      paymentIntentId,
      contentId
    });
    bolt11 = invoice?.bolt11 || null;
    providerInvoiceRef = invoice?.providerId || null;
  } catch {}
  const fee = computeProviderFeeBreakdown(amountSats, {
    providerInvoicing: body.needsProviderInvoicing !== false,
    durablePublicHosting: Boolean(body.needsDurablePublicHosting)
  });
  const providerRemitMode = parseProviderRemitMode(body.providerRemitMode || null) || "auto_forward";
  const payoutRail: ProviderPayoutRail = providerRemitMode === "auto_forward" ? "forwarded" : "provider_custody";
  const payoutPolicy = normalizeProviderFallbackPolicy(body.payoutPolicy, body.allowProviderFallback);
  const created = createProviderPaymentIntent({
    providerNodeId,
    creatorNodeId,
    contentId,
    paymentIntentId,
    bolt11,
    providerInvoiceRef,
    amountSats,
    ...fee,
    status: bolt11 ? "issued" : "created",
    payoutStatus: "pending",
    payoutRail,
    payoutDestinationType: parsePayoutDestinationType(body.payoutDestinationType || null),
    payoutDestinationSummary: String(body.payoutDestinationSummary || "").trim() || null,
    providerRemitMode,
    payoutExecutionMode: resolveNewIntentPayoutExecutionMode(),
    payoutPolicy: payoutPolicy.payoutPolicy,
    allowProviderFallback: payoutPolicy.allowProviderFallback,
    payoutSummaryStatus: "pending",
    payoutReference: null,
    remittedAt: null,
    payoutLastError: null,
    remittanceAttemptId: null,
    remittanceLockedAt: null,
    remittanceLastCheckedAt: null,
    remittanceAttempts: 0,
    paymentReceiptId: null,
    buyerSessionId: String(body.buyerSessionId || "").trim() || null,
    paidAt: null
  });
  const participantAllocations = Array.isArray(body.participantAllocations)
    ? body.participantAllocations
    : [];
  if (participantAllocations.length > 0) {
    upsertProviderDelegatedAllocationBlueprintByPaymentIntentId(paymentIntentId, {
      creatorNodeId,
      contentId,
      splitVersionId: String(body.splitVersionId || "").trim() || null,
      allocationVersion: 1,
      participants: participantAllocations.map((row) => ({
        participantRef: String(row?.participantRef || "").trim(),
        participantId: String(row?.participantId || "").trim() || null,
        splitParticipantId: String(row?.splitParticipantId || "").trim() || null,
        participantUserId: String(row?.participantUserId || "").trim() || null,
        participantEmail: String(row?.participantEmail || "").trim() || null,
        role: String(row?.role || "").trim() || null,
        roleKey: String(row?.roleKey || "").trim(),
        bps: Math.max(0, Math.round(Number(row?.bps || 0))),
        destinationType: String(row?.destinationType || "").trim() || null,
        destinationSummary: String(row?.destinationSummary || "").trim() || null,
        destinationValue: String(row?.destinationValue || "").trim() || null,
        destinationVerified: Boolean(row?.destinationVerified),
        destinationVerificationError: String(row?.destinationVerificationError || "").trim() || null
      }))
    });
  }
  return reply.send({
    ok: true,
    paymentIntentId: created.paymentIntentId,
    bolt11: created.bolt11,
    providerInvoiceRef: created.providerInvoiceRef,
    status: created.status,
    providerFeeSats: created.providerFeeSats,
    providerInvoicingFeeSats: created.providerInvoicingFeeSats,
    providerDurableHostingFeeSats: created.providerDurableHostingFeeSats,
    creatorNetSats: created.creatorNetSats,
    payoutDestinationType: created.payoutDestinationType,
    payoutDestinationSummary: created.payoutDestinationSummary,
    providerRemitMode: created.providerRemitMode
  });
});

app.get("/public/provider/payment-intents/:paymentIntentId/status", async (req: any, reply: any) => {
  const paymentIntentId = String((req.params as any)?.paymentIntentId || "").trim();
  if (!paymentIntentId) return badRequest(reply, "paymentIntentId required");
  const providerAuthority = await resolveProviderExecutionAuthorityOnCurrentNode();
  if (!providerAuthority.ok) {
    return reply.code(409).send({
      error: providerAuthority.code || "PROVIDER_NOT_READY",
      message: providerAuthority.message || "Provider execution is not ready on this node."
    });
  }
  let current = findProviderPaymentIntentByPaymentIntentId(paymentIntentId);
  if (!current) return notFound(reply, "Provider payment intent not found");
  if (current.status !== "paid" && current.providerInvoiceRef) {
    const invoiceStatus = await checkLightningInvoice(prisma as any, current.providerInvoiceRef).catch(() => null);
    if (invoiceStatus?.paid) {
      const patched = updateProviderPaymentIntent(current.id, {
        status: "paid",
        paidAt: invoiceStatus.paidAt || new Date().toISOString()
      });
      current = await ensureProviderPaymentSettlement(patched || current);
    }
  }
  if (current.status === "paid") {
    current = await ensureProviderPaymentSettlement(current);
    if (current.payoutExecutionMode === "participant" && current.providerRemitMode === "auto_forward") {
      try {
        await executeParticipantPayoutRowsForIntent(current, "provider_status_participant_reconcile");
        current = await syncProviderIntentPayoutTruthFromParticipantRows(current);
      } catch (error: any) {
        app.log.warn(
          {
            paymentIntentId: current.paymentIntentId,
            providerPaymentIntentId: current.id,
            error: String(error?.message || error || "participant_reconcile_failed")
          },
          "providerRemittance.participant_reconcile_failed"
        );
      }
    }
  }
  return reply.send({
    ok: true,
    paymentIntentId: current.paymentIntentId,
    status: current.status,
    paid: current.status === "paid",
    paidAt: current.paidAt || null,
    paymentReceiptId: current.paymentReceiptId || null,
    payoutStatus: current.payoutStatus || null,
    payoutSummaryStatus: current.payoutSummaryStatus || null,
    payoutRail: current.payoutRail || null,
    payoutExecutionMode: current.payoutExecutionMode || null,
    payoutDestinationType: current.payoutDestinationType || null,
    payoutDestinationSummary: current.payoutDestinationSummary || null,
    providerRemitMode: current.providerRemitMode || null,
    payoutReference: current.payoutReference || null,
    remittedAt: current.remittedAt || null,
    payoutLastError: current.payoutLastError || null,
    remittanceAttempts: Number(current.remittanceAttempts || 0),
    remittanceLastCheckedAt: current.remittanceLastCheckedAt || null
  });
});

app.get("/public/provider/revenue/:creatorNodeId", async (req: any, reply: any) => {
  const creatorNodeId = String((req.params as any)?.creatorNodeId || "").trim();
  if (!creatorNodeId) return badRequest(reply, "creatorNodeId required");

  const link = getProviderCreatorLink(creatorNodeId);
  if (!link || link.trustStatus !== "verified" || !link.executionAllowed) {
    return reply.code(409).send({
      error: "PROVIDER_CREATOR_RELATIONSHIP_REQUIRED",
      message: "Provider relationship is not ready for delegated revenue snapshots."
    });
  }

  const providerIdentity = await buildLocalNodeIdentityDoc().catch(() => null);
  const providerNodeId = providerIdentity?.nodeId || null;
  const intents = listProviderPaymentIntents().filter((row) => row.creatorNodeId === creatorNodeId && Boolean(row.contentId));
  const grouped = new Map<
    string,
    {
      content_id: string;
      gross_sats: bigint;
      provider_invoicing_fee_sats: bigint;
      provider_durable_hosting_fee_sats: bigint;
      provider_fee_sats: bigint;
      creator_net_sats: bigint;
      payout_status: ProviderPayoutStatus;
      payout_rail: ProviderPayoutRail;
      payout_destination_type: CreatorPayoutDestinationType;
      payout_destination_summary: string | null;
      provider_remit_mode: ProviderRemitMode;
      payout_reference: string | null;
      remitted_at: string | null;
      last_updated: string;
    }
  >();

  for (const row of intents) {
    const contentId = String(row.contentId || "").trim();
    if (!contentId) continue;
    const current = grouped.get(contentId) || {
      content_id: contentId,
      gross_sats: 0n,
      provider_invoicing_fee_sats: 0n,
      provider_durable_hosting_fee_sats: 0n,
      provider_fee_sats: 0n,
      creator_net_sats: 0n,
      payout_status: "pending" as ProviderPayoutStatus,
      payout_rail: row.payoutRail ?? "provider_custody",
      payout_destination_type: parsePayoutDestinationType(row.payoutDestinationType || null),
      payout_destination_summary: row.payoutDestinationSummary || null,
      provider_remit_mode: parseProviderRemitMode(row.providerRemitMode || null),
      payout_reference: row.payoutReference || null,
      remitted_at: row.remittedAt || null,
      last_updated: row.updatedAt || row.createdAt
    };
    current.gross_sats += BigInt(String(row.grossAmountSats || row.amountSats || "0"));
    current.provider_invoicing_fee_sats += BigInt(String(row.providerInvoicingFeeSats || row.providerFeeSats || "0"));
    current.provider_durable_hosting_fee_sats += BigInt(String(row.providerDurableHostingFeeSats || "0"));
    current.provider_fee_sats += BigInt(String(row.providerFeeSats || "0"));
    current.creator_net_sats += BigInt(String(row.creatorNetSats || row.amountSats || "0"));
    if (row.payoutStatus === "failed") current.payout_status = "failed";
    else if (row.payoutStatus === "forwarding" && current.payout_status !== "failed") current.payout_status = "forwarding";
    else if (row.payoutStatus === "pending" && current.payout_status !== "failed") current.payout_status = "pending";
    else if (row.payoutStatus === "paid" && current.payout_status === "paid") current.payout_status = "paid";
    if (new Date(row.updatedAt || row.createdAt).getTime() > new Date(current.last_updated).getTime()) {
      current.last_updated = row.updatedAt || row.createdAt;
      current.payout_rail = row.payoutRail ?? current.payout_rail;
      if (current.payout_status !== "failed") current.payout_status = row.payoutStatus || current.payout_status;
      current.payout_destination_type = parsePayoutDestinationType(row.payoutDestinationType || null);
      current.payout_destination_summary = row.payoutDestinationSummary || null;
      current.provider_remit_mode = parseProviderRemitMode(row.providerRemitMode || null);
      current.payout_reference = row.payoutReference || null;
      current.remitted_at = row.remittedAt || null;
    }
    grouped.set(contentId, current);
  }

  return reply.send({
    ok: true,
    providerNodeId,
    creatorNodeId,
    asOf: new Date().toISOString(),
    items: Array.from(grouped.values())
      .map((row) => ({
        content_id: row.content_id,
        gross_sats: Number(row.gross_sats),
        provider_invoicing_fee_sats: Number(row.provider_invoicing_fee_sats),
        provider_durable_hosting_fee_sats: Number(row.provider_durable_hosting_fee_sats),
        provider_fee_sats: Number(row.provider_fee_sats),
        creator_net_sats: Number(row.creator_net_sats),
        payout_status: row.payout_status,
        payout_rail: row.payout_rail,
        payout_destination_type: row.payout_destination_type,
        payout_destination_summary: row.payout_destination_summary,
        provider_remit_mode: row.provider_remit_mode,
        payout_reference: row.payout_reference,
        remitted_at: row.remitted_at,
        last_updated: row.last_updated
      }))
      .sort((a, b) => String(b.last_updated).localeCompare(String(a.last_updated)))
  });
});

// Claim a free entitlement (for library) when content is free in Basic mode
app.post("/api/buyer/entitlements/claim", async (req: any, reply: any) => {
  const session = await requireBuyerSession(req, reply);
  if (!session) return;

  const body = (req.body ?? {}) as { contentId?: string };
  const contentId = asString(body.contentId || "").trim();
  if (!contentId) return badRequest(reply, "contentId required");

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");

  await reconcileBuyerEntitlementsFromPurchaseHistory({
    buyerId: session.buyer.id,
    contentId
  }).catch(() => {});

  const existing = await prisma.entitlement.findFirst({
    where: { buyerId: session.buyer.id, contentId }
  });
  if (existing) {
    return reply.send({ ok: true, alreadyOwned: true, entitlementId: existing.id });
  }

  if (content.priceSats != null && content.priceSats > 0n) {
    return reply.code(409).send({ error: "Payment required" });
  }

  const manifest = await ensureManifestForContent(content);
  if (!manifest?.sha256) return notFound(reply, "Manifest not found");

  const created = await prisma.entitlement.create({
    data: {
      buyerId: session.buyer.id,
      buyerUserId: null,
      contentId,
      manifestSha256: manifest.sha256,
      paymentIntentId: null
    }
  });

  return reply.send({ ok: true, entitlementId: created.id });
});

// Debug-only entitlement reset. Disabled in production.
app.post("/api/buyer/entitlements/reset", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const enabled = shouldAllowDebugEntitlementReset({
    nodeEnv: process.env.NODE_ENV,
    isAdmin: true
  });
  if (!enabled) return notFound(reply, "Not found");

  const body = (req.body ?? {}) as { buyerId?: string; contentId?: string };
  const buyerId = asString(body.buyerId || "").trim();
  const contentId = asString(body.contentId || "").trim();
  if (!buyerId || !contentId) return badRequest(reply, "buyerId and contentId required");

  const content = await prisma.contentItem.findUnique({ where: { id: contentId }, select: { ownerUserId: true } });
  if (!content) return notFound(reply, "Not found");
  if (content.ownerUserId !== userId) return forbidden(reply);

  const deleted = await prisma.entitlement.deleteMany({ where: { buyerId, contentId } });
  return reply.send({ ok: true, deleted: deleted.count });
});

// List buyer entitlements (buyer-session scoped)
app.get("/api/buyer/entitlements", async (req: any, reply: any) => {
  const session = await requireBuyerSession(req, reply);
  if (!session) return;

  const contentId = asString((req.query as any)?.contentId || "").trim();
  await reconcileBuyerEntitlementsFromPurchaseHistory({
    buyerId: session.buyer.id,
    contentId: contentId || undefined
  }).catch(() => {});

  const entitlements = await prisma.entitlement.findMany({
    where: {
      buyerId: session.buyer.id,
      ...(contentId ? { contentId } : {})
    },
    include: {
      content: {
        select: {
          id: true,
          title: true,
          description: true,
          type: true,
          status: true,
          storefrontStatus: true,
          deliveryMode: true,
          priceSats: true,
          createdAt: true,
          repoPath: true,
          owner: { select: { id: true, displayName: true, email: true } }
        }
      }
    },
    orderBy: { grantedAt: "desc" }
  });

  return reply.send(
    entitlements.map((e) => ({
      id: e.id,
      contentId: e.contentId,
      manifestSha256: e.manifestSha256,
      grantedAt: e.grantedAt.toISOString(),
      content: e.content
        ? (() => {
            const coverUrl = `${APP_BASE_URL}/public/content/${encodeURIComponent(e.content.id)}/cover`;
            let primaryFile: { path: string; mime?: string; sizeBytes?: number; sha256?: string } | null = null;
            try {
              if (e.content.repoPath) {
                // Best-effort read of manifest to expose primary file metadata.
                // Avoid heavy joins here; manifest is already stored on disk.
                const manifest = fsSync.existsSync(path.join(e.content.repoPath, "manifest.json"))
                  ? JSON.parse(fsSync.readFileSync(path.join(e.content.repoPath, "manifest.json"), "utf8"))
                  : null;
                const primaryKey = getPrimaryObjectKey(manifest || null);
                if (primaryKey && Array.isArray((manifest as any)?.files)) {
                  const entry = (manifest as any).files.find((f: any) => f?.path === primaryKey) || null;
                  primaryFile = {
                    path: primaryKey,
                    mime: entry?.mime,
                    sizeBytes: entry?.sizeBytes,
                    sha256: entry?.sha256
                  };
                }
              }
            } catch {
              primaryFile = null;
            }

            return {
              id: e.content.id,
              title: e.content.title,
              description: e.content.description || null,
              type: e.content.type,
              status: e.content.status,
              storefrontStatus: e.content.storefrontStatus,
              deliveryMode: e.content.deliveryMode || null,
              priceSats: e.content.priceSats != null ? String(e.content.priceSats) : null,
              createdAt: e.content.createdAt.toISOString(),
              coverUrl,
              primaryFile,
              owner: e.content.owner
                ? {
                    id: e.content.owner.id,
                    displayName: e.content.owner.displayName,
                    email: e.content.owner.email
                  }
                : null
            };
          })()
        : null
    }))
  );
});

// Buyer cover image for library cards (entitlement-gated)
app.get("/api/buyer/content/:id/cover", async (req: any, reply: any) => {
  const session = await requireBuyerSession(req, reply);
  if (!session) return;

  const contentId = asString((req.params as any).id || "").trim();
  if (!contentId) return notFound(reply, "Not found");

  const entitlement = await prisma.entitlement.findFirst({
    where: { buyerId: session.buyer.id, contentId }
  });
  if (!entitlement) return forbidden(reply);

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content?.repoPath) {
    return reply.redirect(`/card/${encodeURIComponent(contentId)}`);
  }

  const repoRoot = path.resolve(content.repoPath);
  const files = await prisma.contentFile.findMany({ where: { contentId }, orderBy: { createdAt: "asc" } });

  let coverKey: string | null = null;
  try {
    const manifest = await readManifest(content.repoPath);
    const fromManifest = (manifest as any)?.cover || null;
    if (fromManifest && typeof fromManifest === "string") {
      coverKey = String(fromManifest);
    }
  } catch {}

  if (!coverKey) {
    coverKey = await ensureCoverImage(content, files);
  }

  if (!coverKey) {
    return reply.redirect(`/card/${encodeURIComponent(contentId)}`);
  }

  const absPath = path.resolve(repoRoot, coverKey);
  if (!absPath.startsWith(repoRoot)) return forbidden(reply);
  if (!fsSync.existsSync(absPath)) return notFound(reply, "Not found");

  const file = await prisma.contentFile.findFirst({ where: { contentId, objectKey: coverKey } });
  if (file?.mime) reply.type(file.mime);
  const stream = fsSync.createReadStream(absPath);
  return reply.send(stream);
});

