// Public exposure control
app.get("/api/public/status", { preHandler: requireAuth }, async (_req: any, reply: any) => {
  const state = getPublicLinkState();
  const nodeMode = getNodeMode();
  if (state.mode === "quick" && nodeMode !== "advanced") {
    const consent = getPublicSharingConsent();
    const consentGranted = consent.granted || consent.dontAskAgain;
    if (consentGranted && getPublicSharingAutoStart()) {
      const st = tunnelManager.status();
      if (st.status === "STOPPED") {
        tunnelManager.startQuick().catch((e) => app.log.warn(String(e?.message || e)));
      }
    }
  }
  return reply.send(getPublicStatusCached());
});

function getNodeModeStatus() {
  const runtime = resolveRuntimeConfig();
  const productTierInfo = resolveProductTier();
  const lockVars: string[] = [];
  if (runtime.nodeModeSource === "env") lockVars.push("NODE_MODE");
  if (productTierInfo.source === "env") lockVars.push("PRODUCT_TIER");
  const tierLocked = lockVars.length > 0;
  const lockReason = tierLocked
    ? `Locked by environment variable ${lockVars.join(" and ")}`
    : "";
  return {
    nodeMode: runtime.nodeMode,
    nodeModeSource: runtime.nodeModeSource,
    productTier: productTierInfo.productTier,
    productTierSource: productTierInfo.source,
    tierLocked,
    lockReason,
    restartRequired: false
  };
}

function hasDetectedNamedTunnel(): boolean {
  const state = getPublicStatusCached();
  if (state.mode !== "named" || state.status !== "online") return false;
  const origin = normalizePublicOriginBase(String(state.canonicalOrigin || state.publicOrigin || "").trim());
  if (!origin) return false;
  return isPersistentOrigin(origin);
}

type LocalSovereignReadiness = {
  namedTunnelDetected: boolean;
  localBitcoinReady: boolean;
  localLndReady: boolean;
  localCommerceReady: boolean;
  ready: boolean;
  blockers: string[];
};

async function getLocalSovereignReadiness(): Promise<LocalSovereignReadiness> {
  const namedTunnelDetected = hasDetectedNamedTunnel();
  const [bitcoinHealth, lndHealth] = await Promise.all([bitcoindHealthCheck(), lndHealthCheck()]);
  const localBitcoinReady = bitcoinHealth.status === "healthy";
  const localLndReady = lndHealth.status === "healthy";
  // Local invoice/service readiness currently depends on local Lightning readiness.
  const localCommerceReady = localLndReady;
  const blockers: string[] = [];
  if (!namedTunnelDetected) blockers.push("named_tunnel_required");
  if (!localBitcoinReady) blockers.push("local_bitcoin_node_required");
  if (!localLndReady) blockers.push("local_lnd_required");
  if (!localCommerceReady) blockers.push("local_commerce_service_required");
  return {
    namedTunnelDetected,
    localBitcoinReady,
    localLndReady,
    localCommerceReady,
    ready: blockers.length === 0,
    blockers
  };
}

const LOCAL_SOVEREIGN_READINESS_CACHE_TTL_MS = Math.max(
  1000,
  Number(process.env.LOCAL_SOVEREIGN_READINESS_CACHE_TTL_MS || "10000")
);
let localSovereignReadinessCache:
  | {
      expiresAt: number;
      value: LocalSovereignReadiness;
    }
  | null = null;
let localSovereignReadinessInflight: Promise<LocalSovereignReadiness> | null = null;

async function getLocalSovereignReadinessCached(force = false): Promise<LocalSovereignReadiness> {
  const now = Date.now();
  if (!force && localSovereignReadinessCache && localSovereignReadinessCache.expiresAt > now) {
    return localSovereignReadinessCache.value;
  }
  if (!force && localSovereignReadinessInflight) {
    return localSovereignReadinessInflight;
  }
  localSovereignReadinessInflight = getLocalSovereignReadiness()
    .then((value) => {
      localSovereignReadinessCache = {
        expiresAt: Date.now() + LOCAL_SOVEREIGN_READINESS_CACHE_TTL_MS,
        value
      };
      return value;
    })
    .finally(() => {
      localSovereignReadinessInflight = null;
    });
  return localSovereignReadinessInflight;
}

async function resolveCommerceAuthorityForUser(
  userId: string,
  input?: {
    providerConnection?: ProviderCommerceConnectionState;
    sovereignReadiness?: LocalSovereignReadiness;
  }
): Promise<{
  authority: boolean;
  providerAuthority: boolean;
  localAuthority: boolean;
  namedTunnelDetected: boolean;
  providerConnected: boolean;
  providerConnectionReason: ProviderCommerceConnectionState["reason"];
  sovereignReadiness: LocalSovereignReadiness;
}> {
  const providerConnection = input?.providerConnection || deriveProviderCommerceConnectionState();
  const modeStatus = getNodeModeStatus();
  if (modeStatus.nodeMode === "basic") {
    const sovereignReadiness = input?.sovereignReadiness || (await getLocalSovereignReadinessCached());
    return {
      authority: false,
      providerAuthority: false,
      localAuthority: false,
      namedTunnelDetected: sovereignReadiness.namedTunnelDetected,
      providerConnected: providerConnection.providerConnected,
      providerConnectionReason: providerConnection.reason,
      sovereignReadiness
    };
  }
  const sovereignReadiness = input?.sovereignReadiness || (await getLocalSovereignReadinessCached());
  const namedTunnelDetected = sovereignReadiness.namedTunnelDetected;
  const providerConnected = providerConnection.providerConnected;
  const providerAuthority = namedTunnelDetected && providerConnected;
  // Local commerce authority is only active in Sovereign Node (lan), never in
  // Sovereign Creator (advanced) without provider-backed commerce.
  const localAuthority = modeStatus.nodeMode === "lan" && sovereignReadiness.ready;
  if (String(process.env.CERTIFYD_DEBUG_COMMERCE_TRUTH || "").trim() === "1") {
    console.info(
      "[commerce-authority]",
      JSON.stringify({
        userId,
        selectedMode: modeStatus.nodeMode,
        namedTunnelDetected,
        providerConnected,
        providerConnectionReason: providerConnection.reason,
        providerConfigured: providerConnection.providerConfigured,
        providerTrustReady: providerConnection.trustReady,
        providerAcknowledgmentReady: providerConnection.acknowledgmentReady,
        providerPermitReady: providerConnection.permitReady,
        localSovereignReady: localAuthority,
        localBitcoinReady: sovereignReadiness.localBitcoinReady,
        localLndReady: sovereignReadiness.localLndReady,
        localCommerceReady: sovereignReadiness.localCommerceReady
      })
    );
  }
  return {
    authority: providerAuthority || localAuthority,
    providerAuthority,
    localAuthority,
    namedTunnelDetected,
    providerConnected,
    providerConnectionReason: providerConnection.reason,
    sovereignReadiness
  };
}

app.get("/api/node/mode", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const modeStatus = getNodeModeStatus();
  const providerConnection = deriveProviderCommerceConnectionState();
  const readiness = await getLocalSovereignReadinessCached();
  const authority = await resolveCommerceAuthorityForUser(userId, {
    providerConnection,
    sovereignReadiness: readiness
  });
  const sovereignCreatorEligible = readiness.namedTunnelDetected;
  const sovereignNodeEligible = readiness.ready;
  const selectedMode = modeStatus.nodeMode;
  const effectiveMode: "basic" | "advanced" | "lan" =
    selectedMode === "lan"
      ? sovereignNodeEligible
        ? "lan"
        : sovereignCreatorEligible
          ? "advanced"
          : "basic"
      : selectedMode === "advanced"
        ? sovereignCreatorEligible
          ? "advanced"
          : "basic"
        : "basic";
  return reply.send({
    ...modeStatus,
    selectedMode,
    effectiveMode,
    modeReadiness: {
      sovereignCreatorEligible,
      sovereignNodeEligible,
      ...readiness
    },
    commerceAuthorityAvailable: authority.authority,
    providerCommerceConnected: authority.providerConnected,
    providerCommerceConnectionReason: authority.providerConnectionReason,
    localSovereignReady: authority.localAuthority
  });
});

app.post("/api/node/mode", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const modeStatus = getNodeModeStatus();
  if (modeStatus.tierLocked) {
    return reply.code(403).send({
      error: "NODE_MODE_LOCKED",
      reason: modeStatus.lockReason,
      message: modeStatus.lockReason
    });
  }
  const body = (req.body ?? {}) as { nodeMode?: string };
  const next = validateNodeMode(body?.nodeMode);
  if (!next) return badRequest(reply, "Invalid node mode");
  const providerConnection = deriveProviderCommerceConnectionState();
  const readiness = await getLocalSovereignReadinessCached();
  if ((next === "advanced" || next === "lan") && !readiness.namedTunnelDetected) {
    return reply.code(409).send({
      error: "NAMED_TUNNEL_REQUIRED",
      message: "Sovereign modes require a reachable canonical public origin (stable host route)."
    });
  }
  if (next === "lan" && !readiness.ready) {
    return reply.code(409).send({
      error: "LOCAL_SOVEREIGN_STACK_REQUIRED",
      blockers: readiness.blockers,
      message:
        "Sovereign Node requires a reachable canonical public origin plus local Bitcoin, local LND, and local commerce service readiness."
    });
  }
  try {
    await writeNodeConfig(next);
    await writeProductTier(next);
  } catch (e: any) {
    return reply.code(500).send({ error: "Failed to persist node mode", message: String(e?.message || e) });
  }
  const updatedStatus = getNodeModeStatus();
  const authority = await resolveCommerceAuthorityForUser(userId, {
    providerConnection,
    sovereignReadiness: readiness
  });
  return reply.send({
    ...updatedStatus,
    selectedMode: updatedStatus.nodeMode,
    effectiveMode: updatedStatus.nodeMode,
    modeReadiness: {
      sovereignCreatorEligible: readiness.namedTunnelDetected,
      sovereignNodeEligible: readiness.ready,
      ...readiness
    },
    commerceAuthorityAvailable: authority.authority,
    providerCommerceConnected: authority.providerConnected,
    providerCommerceConnectionReason: authority.providerConnectionReason,
    localSovereignReady: authority.localAuthority
  });
});

