app.post("/api/remote/invites/:token/accept", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const inviteCtx = getCapabilityContext();
  if (!canUseSplits(inviteCtx)) {
    return reply.code(403).send({
      code: "invite_not_allowed",
      reason: capabilityReason(inviteCtx, "invite", capabilityReasonContext(inviteCtx))
    });
  }
  const token = asString((req.params as any).token);
  const origin = normalizeRemoteOrigin(asString((req.query as any)?.origin || ""));
  const localUserId = asString((req.user as JwtUser)?.sub || "").trim();
  const authHeaderPresent = Boolean(asString(req?.headers?.authorization || "").trim());
  if (!token) return badRequest(reply, "token required");
  if (!origin) return badRequest(reply, "invalid origin");
  if (!(await isOriginReachable(origin))) {
    return reply.code(409).send({ error: "Remote invite host unreachable", origin });
  }

  try {
    app.log.info(
      {
        tokenId: safeInviteTokenId(token),
        origin,
        localUserId: localUserId || null
      },
      "invite.remote_accept_attempt"
    );
    let audienceOrigin = origin;
    try {
      const discoveryRes = await fetchWithTimeout(
        `${origin}/.well-known/contentbox`,
        { method: "GET", headers: { Accept: "application/json" } as any } as any,
        4000
      );
      if (discoveryRes.ok) {
        const discoveryPayload: any = await discoveryRes.json().catch(() => null);
        const discoveredNodeUrl = normalizeOrigin(asString(discoveryPayload?.nodeUrl || "").trim());
        if (discoveredNodeUrl) audienceOrigin = discoveredNodeUrl;
      }
    } catch {
      audienceOrigin = origin;
    }

    let signedPayload: { payload: any; signature: string } | null = null;
    try {
      signedPayload = await signInviteAcceptancePayload(token, localUserId, { audienceOrigin });
    } catch (e: any) {
      const errCode = asString(e?.code || "").trim();
      const signingError = String(e?.message || e || "");
      app.log.warn(
        {
          token,
          origin,
          audienceOrigin,
          authHeaderPresent,
          localUserId: localUserId || null,
          signingError,
          errCode: errCode || null,
          originCandidates: Array.isArray(e?.originCandidates) ? e.originCandidates : null,
          discoveryChecks: Array.isArray(e?.discoveryChecks) ? e.discoveryChecks : null
        },
        "remoteInvite.accept.signingUnavailable"
      );
      if (errCode === "INVITE_NODE_URL_UNREACHABLE") {
        return reply.code(409).send({
          error: "This node public origin discovery is unreachable or invalid for remote invite signature verification.",
          code: "INVITE_NODE_URL_UNREACHABLE"
        });
      }
      return reply.code(409).send({
        error: "This device cannot sign invite acceptance payloads.",
        code: "INVITE_KEY_MISSING",
        details: signingError
      });
    }
    const advertisedNodeUrl = normalizeOrigin(String(signedPayload?.payload?.nodeUrl || ""));
    try {
      const host = advertisedNodeUrl ? new URL(advertisedNodeUrl).hostname.toLowerCase() : "";
      const loopbackHost = host === "localhost" || host === "127.0.0.1" || host === "::1";
      if (!advertisedNodeUrl || loopbackHost) {
        return reply.code(409).send({
          error: "This node is not advertising a shareable public origin for invite acceptance.",
          code: "INVITE_NODE_URL_NOT_SHAREABLE",
          nodeUrl: advertisedNodeUrl || null
        });
      }
    } catch {
      return reply.code(409).send({
        error: "This node is not advertising a valid public origin for invite acceptance.",
        code: "INVITE_NODE_URL_NOT_SHAREABLE",
        nodeUrl: advertisedNodeUrl || null
      });
    }
    // Do not hard-block on local preflight discovery checks here.
    // The remote owner node is the final authority for forwarded identity trust validation.
    const outboundBody = {
      ...(req.body ?? {}),
      payload: signedPayload.payload,
      signature: signedPayload.signature,
      remoteNodeUrl: signedPayload.payload.nodeUrl,
      remoteUserId: signedPayload.payload.remoteUserId
    };
    app.log.info(
      {
        tokenId: safeInviteTokenId(token),
        origin,
        localUserId: localUserId || null,
        state: "accept_submitted"
      },
      "invite.remote_accept_submitted"
    );
    const res = await fetchWithTimeout(
      `${origin}/invites/${encodeURIComponent(token)}/accept`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" } as any,
        body: JSON.stringify(outboundBody)
      } as any,
      8000
    );
    const text = await res.text();
    let payload: any = null;
    try {
      payload = text ? JSON.parse(text) : null;
    } catch {
      payload = { error: text || `HTTP_${res.status}` };
    }
    if (!res.ok && (!payload || typeof payload !== "object")) {
      payload = { error: text || `HTTP_${res.status}` };
    }
    if (!res.ok) {
      payload = {
        ...(payload && typeof payload === "object" ? payload : {}),
        code: mapRemoteInviteAcceptErrorCode(res.status, asString(payload?.code || ""))
      };
      app.log.info(
        {
          tokenId: safeInviteTokenId(token),
          origin,
          localUserId: localUserId || null,
          state: "rejected_authoritative",
          code: asString(payload?.code || payload?.error || ""),
          reason: asString(payload?.reason || "")
        },
        "invite.remote_accept_denied"
      );
    }
    let mirrorSeedOk: boolean | null = null;
    let mirrorRefreshOk: boolean | null = null;
    let projectedVisible = false;
    if (res.ok) {
      try {
        await upsertRemoteInviteMirrorFromPayload({
          userId: localUserId,
          remoteOrigin: origin,
          token,
          payload,
          forceAccepted: true
        });
        mirrorSeedOk = true;
      } catch (mirrorErr: any) {
        mirrorSeedOk = false;
        app.log.warn(
          {
            tokenId: safeInviteTokenId(token),
            origin,
            localUserId: localUserId || null,
            error: String(mirrorErr?.message || mirrorErr)
          },
          "invite.remote_accept_mirror_seed_failed"
        );
      }
      try {
        await mirrorRemoteInviteAcceptance({
          userId: localUserId,
          remoteOrigin: origin,
          token,
          acceptedAtOverride:
            asString(payload?.acceptedAt || payload?.invitation?.acceptedAt || "").trim() ||
            new Date().toISOString()
        });
        mirrorRefreshOk = true;
      } catch (mirrorErr: any) {
        mirrorRefreshOk = false;
        app.log.warn(
          {
            tokenId: safeInviteTokenId(token),
            origin,
            localUserId: localUserId || null,
            error: String(mirrorErr?.message || mirrorErr)
          },
          "invite.remote_accept_mirror_failed"
        );
      }
      try {
        const tokenHash = hashInviteToken(token);
        const mirrored = await prisma.remoteInvite.findUnique({
          where: { remoteOrigin_tokenHash: { remoteOrigin: origin, tokenHash } },
          select: { id: true, status: true, acceptedAt: true, contentId: true, revokedAt: true, tombstonedAt: true }
        });
        projectedVisible = Boolean(
          mirrored &&
            !mirrored.revokedAt &&
            !mirrored.tombstonedAt &&
            Boolean(mirrored.contentId) &&
            (normalizeInviteStatus(mirrored.status) === "accepted" || Boolean(mirrored.acceptedAt))
        );
      } catch {
        projectedVisible = false;
      }
      app.log.info(
        {
          tokenId: safeInviteTokenId(token),
          origin,
          localUserId: localUserId || null,
          authoritativeAcceptSuccess: true,
          mirrorWriteSuccess: mirrorSeedOk === true && mirrorRefreshOk !== false,
          mirrorSeedSuccess: mirrorSeedOk,
          mirrorRefreshSuccess: mirrorRefreshOk,
          projectedVisible,
          bindingSource: asString(payload?.bindingSource || payload?.acceptanceAuthMode || "").trim() || null,
          state: "accepted_authoritative"
        },
        "invite.remote_accept_authoritative"
      );
      app.log.info(
        {
          tokenId: safeInviteTokenId(token),
          origin,
          localUserId: localUserId || null,
          state: mirrorSeedOk === true && mirrorRefreshOk !== false ? "mirrored_local" : "mirror_failed"
        },
        mirrorSeedOk === true && mirrorRefreshOk !== false
          ? "invite.remote_accept_mirrored"
          : "invite.remote_accept_mirror_failed"
      );
      app.log.info(
        {
          tokenId: safeInviteTokenId(token),
          origin,
          localUserId: localUserId || null,
          state: projectedVisible ? "projected_visible" : "projection_failed",
          projectedVisible
        },
        projectedVisible ? "invite.remote_accept_projected" : "invite.remote_accept_projection_failed"
      );
    }
    app.log.info(
      {
        tokenId: safeInviteTokenId(token),
        origin,
        audienceOrigin,
        authHeaderPresent,
        localUserId: localUserId || null,
        remoteStatus: res.status,
        remoteCode: asString(payload?.code || payload?.error || ""),
        remoteReason: asString(payload?.reason || "")
      },
      "remoteInvite.accept.proxyResult"
    );
    app.log.info(
      {
        tokenId: safeInviteTokenId(token),
        origin,
        localUserId: localUserId || null,
        status: res.status,
        code: asString(payload?.code || payload?.error || ""),
        reason: asString(payload?.reason || "")
      },
      res.ok ? "invite.remote_accept_result" : "invite.remote_accept_denied"
    );
    return reply.code(res.status).send(payload);
  } catch (e: any) {
    app.log.warn(
      {
        tokenId: safeInviteTokenId(token),
        origin,
        audienceOrigin: null,
        authHeaderPresent,
        localUserId: localUserId || null,
        error: String(e?.message || e)
      },
      "remoteInvite.accept.proxyFailed"
    );
    return reply.code(502).send({
      error: "Remote invite accept failed",
      code: "INVITE_REMOTE_ACCEPT_PROXY_FAILED",
      reason: "UPSTREAM_REQUEST_FAILED",
      details: String(e?.message || e)
    });
  }
});

