app.post("/api/participant/payout-destinations", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const body = (req.body ?? {}) as {
    destinationType?: string;
    destinationValue?: string;
    isPrimary?: boolean;
    isActive?: boolean;
  };
  const destinationType = parseParticipantDestinationType(body.destinationType || null);
  if (!destinationType) return badRequest(reply, "destinationType must be lightning_address, lnurl, or lnd");
  const destinationValue = normalizeParticipantDestinationValue(destinationType, body.destinationValue || "");
  if (!destinationValue) return badRequest(reply, "destinationValue required");
  if (destinationType === "lightning_address" && !isValidLightningAddress(destinationValue)) {
    return badRequest(reply, "lightning address is invalid");
  }

  try {
    const created = await prisma.participantPayoutDestination.create({
      data: {
        userId,
        destinationType,
        destinationValue,
        destinationSummary: summarizeParticipantDestination(destinationType, destinationValue),
        isPrimary: Boolean(body.isPrimary),
        isActive: body.isActive === undefined ? true : Boolean(body.isActive),
        isVerified: false,
        verifiedAt: null,
        lastCheckedAt: null,
        verificationMethod: null,
        verificationStatus: "pending",
        verificationError: null
      }
    });
    const verification = await verifyParticipantDestination(destinationType, destinationValue);
    const verified = await prisma.participantPayoutDestination.update({
      where: { id: created.id },
      data: {
        isVerified: verification.isVerified,
        verifiedAt: verification.isVerified ? verification.checkedAt : null,
        lastVerifiedAt: verification.checkedAt,
        lastCheckedAt: verification.checkedAt,
        verificationMethod: verification.verificationMethod,
        verificationStatus: verification.verificationStatus,
        verificationError: verification.verificationError
      }
    });
    if (created.isPrimary) {
      await setPrimaryParticipantDestinationForUser(userId, created.id);
    }
    const destination = await prisma.participantPayoutDestination.findUnique({ where: { id: verified.id } });
    return reply.send({ ok: true, destination });
  } catch (err: any) {
    if (isMissingParticipantPayoutTableError(err)) {
      return reply.code(409).send({ error: "PAYOUT_DESTINATION_REGISTRY_UNAVAILABLE" });
    }
    throw err;
  }
});

app.put("/my/payout-destinations/lightning", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const body = (req.body ?? {}) as {
    destinationValue?: string;
    isPrimary?: boolean;
    isActive?: boolean;
  };
  const destinationType: ParticipantDestinationType = "lightning_address";
  const destinationValue = normalizeParticipantDestinationValue(destinationType, body.destinationValue || "");
  if (!destinationValue) return badRequest(reply, "destinationValue required");
  if (!isValidLightningAddress(destinationValue)) return badRequest(reply, "lightning address is invalid");

  try {
    const existing = await prisma.participantPayoutDestination.findFirst({
      where: { userId, destinationType, destinationValue },
      orderBy: [{ updatedAt: "desc" }]
    });
    const destination = existing
      ? await prisma.participantPayoutDestination.update({
          where: { id: existing.id },
          data: {
            isActive: body.isActive === undefined ? true : Boolean(body.isActive),
            destinationSummary: summarizeParticipantDestination(destinationType, destinationValue),
            verificationStatus: "pending",
            verificationError: null
          }
        })
      : await prisma.participantPayoutDestination.create({
          data: {
            userId,
            destinationType,
            destinationValue,
            destinationSummary: summarizeParticipantDestination(destinationType, destinationValue),
            isPrimary: false,
            isActive: body.isActive === undefined ? true : Boolean(body.isActive),
            isVerified: false,
            verifiedAt: null,
            lastCheckedAt: null,
            verificationMethod: null,
            verificationStatus: "pending",
            verificationError: null
          }
        });
    const verification = await verifyParticipantDestination(destinationType, destinationValue);
    const refreshed = await prisma.participantPayoutDestination.update({
      where: { id: destination.id },
      data: {
        isVerified: verification.isVerified,
        verifiedAt: verification.isVerified ? verification.checkedAt : null,
        lastVerifiedAt: verification.checkedAt,
        lastCheckedAt: verification.checkedAt,
        verificationMethod: verification.verificationMethod,
        verificationStatus: verification.verificationStatus,
        verificationError: verification.verificationError
      }
    });

    if (body.isPrimary === undefined || Boolean(body.isPrimary)) {
      await setPrimaryParticipantDestinationForUser(userId, refreshed.id);
    }
    const updated = await prisma.participantPayoutDestination.findUnique({ where: { id: refreshed.id } });
    return reply.send({ ok: true, destination: updated });
  } catch (err: any) {
    if (isMissingParticipantPayoutTableError(err)) {
      return reply.code(409).send({ error: "PAYOUT_DESTINATION_REGISTRY_UNAVAILABLE" });
    }
    throw err;
  }
});

