app.get("/api/network/debug/relationship", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const providerTarget = getNetworkProviderConfig();
  const verification = getProviderVerificationStatus(providerTarget);
  const acknowledgment = getProviderAcknowledgmentStatus(providerTarget);
  const permit = getProviderOperationIntentStatus(providerTarget);
  const userStatus = await deriveUserNetworkStatus();
  const activation = getProfileNetworkActivationStatus(providerTarget);
  const publishReadiness = await evaluatePublishReadiness();
  const ctx = getCapabilityContext();
  const userId = (req.user as JwtUser).sub;
  const paymentsReadiness = await getPaymentsReadiness(userId).catch(() => null);
  const lightningRuntime = await resolveLightningCapabilityRuntime(userId).catch(() => null);
  const serviceProfile = resolveProviderServiceProfile({
    hasLocalInvoiceMinting:
      ctx.paymentsMode === "node" &&
      Boolean(lightningRuntime?.canReceive ?? paymentsReadiness?.lightning?.ready),
    providerCfg: providerTarget,
    ctx
  });
  const payoutDestination = await resolveEffectivePayoutDestination(userId, {
    localLndReady:
      ctx.paymentsMode === "node" &&
      Boolean(lightningRuntime?.canReceive ?? paymentsReadiness?.lightning?.ready),
    paymentsReadiness
  });

  return reply.send({
    providerTarget: {
      providerUrl: providerTarget.providerUrl,
      providerNodeId: providerTarget.providerNodeId,
      providerPubKey: providerTarget.providerPubKey,
      enabled: providerTarget.enabled
    },
    verification,
    acknowledgment,
    permit,
    lightningRuntime,
    serviceProfile,
    payoutDestination,
    userStatus,
    activation,
    publishReadiness
  });
});

app.post("/api/publish/profile", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const readiness = await evaluatePublishReadiness();
  if (!readiness.allowed) {
    const status = readiness.readiness === "activation_required" ? "activation_required" : "not_ready";
    return reply.send({
      status,
      message: readiness.message
    });
  }

  const body = (req.body ?? {}) as {
    name?: unknown;
    bio?: unknown;
    links?: unknown;
  };

  const name = typeof body.name === "string" ? body.name.trim() : "";
  const bio = typeof body.bio === "string" ? body.bio.trim() : "";

  let links: string[] = [];
  if (body.links !== undefined) {
    if (!Array.isArray(body.links)) return badRequest(reply, "links must be an array of strings");
    const normalized: string[] = [];
    for (const v of body.links) {
      if (typeof v !== "string") return badRequest(reply, "links must contain only strings");
      const s = v.trim();
      if (!s) continue;
      normalized.push(s);
    }
    links = normalized;
  }

  if (!name && !bio && links.length === 0) {
    return badRequest(reply, "Provide at least one of name, bio, or links");
  }

  const userId = (req.user as JwtUser).sub;
  const publishedAt = new Date().toISOString();
  const providerConfig = getNetworkProviderConfig();
  const payloadHash = crypto
    .createHash("sha256")
    .update(JSON.stringify({ userId, name, bio, links }))
    .digest("hex");
  const publishId = `pub_${crypto
    .createHash("sha256")
    .update(JSON.stringify({ userId, publishedAt, payloadHash }))
    .digest("hex")
    .slice(0, 16)}`;

  appendPublishLog({
    publishId,
    type: "profile",
    publishedAt,
    providerNodeId: providerConfig.providerNodeId || null,
    hash: payloadHash
  });

  try {
    const localNode = await buildLocalNodeIdentityDoc(userId);
    appendLifecycleReceiptSafe({
      type: "profile_publish",
      subjectNodeId: localNode.nodeId,
      providerNodeId: providerConfig.providerNodeId || null,
      objectId: publishId,
      payload: {
        publishId,
        publishedAt,
        name: name || null,
        bio: bio || null,
        links,
        hash: payloadHash
      }
    });
  } catch {}

  return reply.send({
    status: "published",
    publishId,
    publishedAt,
    message: "Profile published."
  });
});

app.get("/api/network/activate-profile/status", { preHandler: requireAuth }, async (_req: any, reply: any) => {
  const cfg = getNetworkProviderConfig();
  const current = getProfileNetworkActivationStatus(cfg);
  if (current.activation.status === "activated") return reply.send(current);
  const network = await deriveUserNetworkStatus();
  const nextMessage = deriveActivationStatusMessageFromNetwork(network);
  if (String(current.activation.message || "") === nextMessage) return reply.send(current);
  const updated = persistProfileNetworkActivationState(
    buildProfileNetworkActivationState(cfg, {
      status: "not_ready",
      message: nextMessage,
      checkedAt: new Date().toISOString(),
      activatedAt: null
    })
  );
  return reply.send(updated);
});

app.post("/api/network/activate-profile", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const cfg = getNetworkProviderConfig();
  const checkedAt = new Date().toISOString();
  const userStatus = await deriveUserNetworkStatus();
  if (userStatus.status !== "ready") {
    const state = persistProfileNetworkActivationState(
      buildProfileNetworkActivationState(cfg, {
        status: "not_ready",
        message: userStatus.message || "Network prerequisites are not ready.",
        checkedAt,
        activatedAt: null
      })
    );
    return reply.send({
      status: "not_ready",
      message: state.activation.message,
      activatedAt: null,
      checkedAt
    });
  }
  const prev = getProfileNetworkActivationStatus(cfg);
  const activatedAt = prev.activation.status === "activated" && prev.activation.activatedAt
    ? prev.activation.activatedAt
    : checkedAt;
  const state = persistProfileNetworkActivationState(
    buildProfileNetworkActivationState(cfg, {
      status: "activated",
      message: "Your profile is now ready on the network.",
      checkedAt,
      activatedAt
    })
  );
  try {
    const userId = (req.user as JwtUser).sub;
    const localNode = await buildLocalNodeIdentityDoc(userId);
    appendLifecycleReceiptSafe({
      type: "profile_activation",
      subjectNodeId: localNode.nodeId,
      providerNodeId: cfg.providerNodeId || null,
      objectId: state.activation.activatedAt || null,
      payload: {
        status: state.activation.status,
        message: state.activation.message,
        checkedAt: state.activation.checkedAt,
        activatedAt: state.activation.activatedAt
      }
    });
  } catch {}
  return reply.send({
    status: state.activation.status,
    message: state.activation.message,
    activatedAt: state.activation.activatedAt,
    checkedAt: state.activation.checkedAt
  });
});

