app.post("/api/network/provider/acknowledge-client", async (req: any, reply: any) => {
  const body = (req.body ?? {}) as ProviderAcknowledgmentRequest;
  const clientNodeId = String(body?.clientNodeId || "").trim();
  const clientNodePubKey = String(body?.clientNodePubKey || "").trim() || null;
  const requestedAt = String(body?.requestedAt || "").trim() || null;
  const intent = String(body?.intent || "").trim() || "provider_handshake";
  if (!clientNodeId) {
    return badRequest(reply, "clientNodeId is required");
  }
  if (clientNodePubKey) {
    const derived = deriveNodeIdFromNodePubKey(clientNodePubKey);
    if (!derived || derived !== clientNodeId) {
      return badRequest(reply, "client node identity is inconsistent with provided public key");
    }
  }

  const identity = await buildLocalNodeIdentityDoc();
  const issuedAt = new Date().toISOString();
  const responsePayload = buildProviderAcknowledgmentPayload({
    provider: {
      nodeId: identity.nodeId,
      nodePubKey: identity.nodePubKey
    },
    client: {
      nodeId: clientNodeId,
      nodePubKey: clientNodePubKey
    },
    acknowledgment: {
      status: "accepted",
      intent,
      issuedAt
    }
  });
  const sig = signStablePayloadWithLocalNodeKey(responsePayload);
  if (!sig) {
    return reply.code(503).send({
      error: "PROVIDER_ACK_SIGNATURE_UNAVAILABLE",
      message: "Provider acknowledgment signature unavailable."
    });
  }
  const out: ProviderAcknowledgmentResponse & { requestedAt: string | null } = {
    ...responsePayload,
    signature: {
      alg: "ed25519",
      value: sig
    },
    requestedAt
  };
  upsertProviderCreatorLink({
    providerNodeId: identity.nodeId,
    creatorNodeId: clientNodeId,
    providerEndpoint: getPublicStatus().canonicalOrigin || getPublicStatus().publicOrigin || null,
    trustStatus: "verified",
    handshakeStatus: "accepted",
    executionAllowed: false,
    lastSeenAt: issuedAt
  });
  return reply.send(out);
});

app.post("/api/network/provider/accept-operation-intent", async (req: any, reply: any) => {
  const body = (req.body ?? {}) as ProviderOperationIntentRequest;
  const clientNodeId = String(body?.clientNodeId || "").trim();
  const clientNodePubKey = String(body?.clientNodePubKey || "").trim() || null;
  const intent = String(body?.intent || "").trim();
  if (!clientNodeId) return badRequest(reply, "clientNodeId is required");
  if (!intent) return badRequest(reply, "intent is required");
  if (clientNodePubKey) {
    const derived = deriveNodeIdFromNodePubKey(clientNodePubKey);
    if (!derived || derived !== clientNodeId) {
      return badRequest(reply, "client node identity is inconsistent with provided public key");
    }
  }

  const identity = await buildLocalNodeIdentityDoc();
  const issuedAt = new Date().toISOString();
  const expiresAt = new Date(Date.parse(issuedAt) + PROVIDER_PERMIT_DEFAULT_TTL_MS).toISOString();
  const permitId = buildPermitId({
    providerNodeId: identity.nodeId,
    clientNodeId,
    intent,
    issuedAt
  });
  const responsePayload = buildProviderOperationIntentPayload({
    provider: {
      nodeId: identity.nodeId,
      nodePubKey: identity.nodePubKey
    },
    client: {
      nodeId: clientNodeId,
      nodePubKey: clientNodePubKey
    },
    permit: {
      permitId,
      status: "accepted",
      intent,
      issuedAt,
      expiresAt
    }
  });
  const sig = signStablePayloadWithLocalNodeKey(responsePayload);
  if (!sig) {
    return reply.code(503).send({
      error: "PROVIDER_OPERATION_SIGNATURE_UNAVAILABLE",
      message: "Provider operation intent signature unavailable."
    });
  }
  const out: ProviderExecutionPermitResponse = {
    ...responsePayload,
    signature: {
      alg: "ed25519",
      value: sig
    }
  };
  upsertProviderCreatorLink({
    providerNodeId: identity.nodeId,
    creatorNodeId: clientNodeId,
    providerEndpoint: getPublicStatus().canonicalOrigin || getPublicStatus().publicOrigin || null,
    trustStatus: "verified",
    handshakeStatus: "accepted",
    executionAllowed: true,
    lastSeenAt: issuedAt
  });
  return reply.send(out);
});

app.post("/api/network/provider/delegated-publish", async (req: any, reply: any) => {
  const body = (req.body ?? {}) as {
    creatorNodeId?: string | null;
    creatorNodePubKey?: string | null;
    creatorDisplayName?: string | null;
    contentId?: string | null;
    title?: string | null;
    contentType?: string | null;
    manifestHash?: string | null;
    visibility?: "DISABLED" | "UNLISTED" | "LISTED" | null;
    primaryFile?: string | null;
    publishedAt?: string | null;
  };
  const creatorNodeId = String(body.creatorNodeId || "").trim();
  const creatorNodePubKey = String(body.creatorNodePubKey || "").trim() || null;
  const contentId = String(body.contentId || "").trim();
  const manifestHash = String(body.manifestHash || "").trim();
  if (!creatorNodeId) return badRequest(reply, "creatorNodeId is required");
  if (!contentId) return badRequest(reply, "contentId is required");
  if (!manifestHash) return badRequest(reply, "manifestHash is required");
  if (creatorNodePubKey) {
    const derived = deriveNodeIdFromNodePubKey(creatorNodePubKey);
    if (!derived || derived !== creatorNodeId) {
      return badRequest(reply, "creator node identity is inconsistent with provided public key");
    }
  }
  const existingLink = getProviderCreatorLink(creatorNodeId);
  if (!existingLink || existingLink.trustStatus !== "verified" || !existingLink.executionAllowed) {
    return reply.code(409).send({
      error: "PROVIDER_CREATOR_RELATIONSHIP_REQUIRED",
      message: "Provider relationship is not ready for delegated publish."
    });
  }

  const providerIdentity = await buildLocalNodeIdentityDoc();
  const publishedAt = String(body.publishedAt || "").trim() || new Date().toISOString();
  const visibility =
    body.visibility === "DISABLED" || body.visibility === "LISTED" || body.visibility === "UNLISTED"
      ? body.visibility
      : "UNLISTED";
  const receiptPayload = buildContentPublishReceiptPayload({
    contentId,
    manifestHash,
    title: String(body.title || "").trim() || null,
    type: String(body.contentType || "").trim() || null,
    primaryFile: String(body.primaryFile || "").trim() || null,
    publishedAt,
    creatorNodeId,
    providerNodeId: providerIdentity.nodeId
  });
  let publishReceiptId: string | null = null;
  try {
    const receipt = appendLifecycleReceipt(RECEIPTS_DIR, {
      type: "content_publish",
      subjectNodeId: creatorNodeId,
      providerNodeId: providerIdentity.nodeId,
      objectId: contentId,
      payload: receiptPayload
    });
    publishReceiptId = receipt.id;
  } catch {}

  const delegatedPublish = createProviderDelegatedPublish({
    providerNodeId: providerIdentity.nodeId,
    creatorNodeId,
    contentId,
    title: String(body.title || "").trim() || null,
    contentType: String(body.contentType || "").trim() || null,
    manifestHash,
    visibility,
    publishReceiptId,
    publishedAt,
    status: "published"
  });

  upsertProviderCreatorLink({
    providerNodeId: providerIdentity.nodeId,
    creatorNodeId,
    creatorDisplayName: String(body.creatorDisplayName || "").trim() || null,
    providerEndpoint: getPublicStatus().canonicalOrigin || getPublicStatus().publicOrigin || null,
    trustStatus: "verified",
    handshakeStatus: "accepted",
    executionAllowed: true,
    lastSeenAt: publishedAt
  });

  return reply.send({
    ok: true,
    provider: {
      nodeId: providerIdentity.nodeId,
      nodePubKey: providerIdentity.nodePubKey
    },
    delegatedPublish,
    receipt: publishReceiptId
      ? {
          id: publishReceiptId,
          type: "content_publish",
          payload: receiptPayload
        }
      : null
  });
});

app.get("/api/provider/summary", { preHandler: requireAuth }, async (_req: any, reply: any) => {
  const links = listProviderCreatorLinks();
  const publishes = listProviderDelegatedPublishes();
  const intents = listProviderPaymentIntents();
  const activePaymentIntents = intents.filter((intent) => intent.status === "created" || intent.status === "issued").length;
  const settledPayments = intents.filter((intent) => intent.status === "paid").length;
  const payoutRows = await prisma.participantPayout
    .findMany({
      select: {
        providerPaymentIntentId: true,
        status: true,
        amountSats: true,
        lastError: true,
        payoutReference: true,
        remittedAt: true,
        updatedAt: true
      }
    })
    .catch((err: any) => {
      if (isMissingParticipantPayoutTableError(err)) return [];
      throw err;
    });
  const payoutByIntent = new Map<
    string,
    {
      counts: Record<ParticipantPayoutStatus, number>;
      amounts: Record<ParticipantPayoutStatus, bigint>;
      latestError: string | null;
      latestReference: string | null;
      latestRemittedAt: string | null;
      latestUpdatedAtMs: number;
    }
  >();
  for (const row of payoutRows) {
    const key = String(row.providerPaymentIntentId || "").trim();
    if (!key) continue;
    const status = parseParticipantPayoutStatus(row.status);
    const amount = BigInt(String(row.amountSats || "0"));
    const updatedAtMs = row.updatedAt ? row.updatedAt.getTime() : 0;
    const current =
      payoutByIntent.get(key) ||
      {
        counts: { pending: 0, ready: 0, forwarding: 0, paid: 0, failed: 0, blocked: 0 },
        amounts: { pending: 0n, ready: 0n, forwarding: 0n, paid: 0n, failed: 0n, blocked: 0n },
        latestError: null,
        latestReference: null,
        latestRemittedAt: null,
        latestUpdatedAtMs: 0
      };
    current.counts[status] += 1;
    current.amounts[status] += amount;
    if (updatedAtMs >= current.latestUpdatedAtMs) {
      current.latestUpdatedAtMs = updatedAtMs;
      current.latestError = String(row.lastError || "").trim() || null;
      current.latestReference = String(row.payoutReference || "").trim() || null;
      current.latestRemittedAt = row.remittedAt ? row.remittedAt.toISOString() : null;
    }
    payoutByIntent.set(key, current);
  }
  const totals = intents.reduce(
    (acc, intent) => {
      const gross = BigInt(String(intent.grossAmountSats || intent.amountSats || "0"));
      const invoicingFee = BigInt(String(intent.providerInvoicingFeeSats || intent.providerFeeSats || "0"));
      const durableHostingFee = BigInt(String(intent.providerDurableHostingFeeSats || "0"));
      const fee = BigInt(String(intent.providerFeeSats || "0"));
      const net = BigInt(String(intent.creatorNetSats || intent.amountSats || "0"));
      const payoutTruth = payoutByIntent.get(intent.id) || null;
      const paidAmount = payoutTruth ? payoutTruth.amounts.paid : 0n;
      const pendingAmount = payoutTruth
        ? payoutTruth.amounts.pending + payoutTruth.amounts.ready + payoutTruth.amounts.forwarding
        : 0n;
      const failedAmount = payoutTruth ? payoutTruth.amounts.failed + payoutTruth.amounts.blocked : 0n;
      const accounted = paidAmount + pendingAmount + failedAmount;
      const residualPending = net > accounted ? net - accounted : 0n;
      acc.grossCollectedSats += gross;
      acc.providerInvoicingFeeEarnedSats += invoicingFee;
      acc.providerDurableHostingFeeEarnedSats += durableHostingFee;
      acc.providerFeeEarnedSats += fee;
      acc.creatorNetOwedSats += net;
      if (payoutTruth) {
        acc.creatorNetPaidSats += paidAmount;
        acc.creatorNetPendingSats += pendingAmount + residualPending;
        acc.creatorNetFailedSats += failedAmount;
      } else if (intent.status === "paid") {
        // No participant rows yet: keep owed amount visible as pending.
        acc.creatorNetPendingSats += net;
      }
      return acc;
    },
    {
      grossCollectedSats: 0n,
      providerInvoicingFeeEarnedSats: 0n,
      providerDurableHostingFeeEarnedSats: 0n,
      providerFeeEarnedSats: 0n,
      creatorNetOwedSats: 0n,
      creatorNetPaidSats: 0n,
      creatorNetPendingSats: 0n,
      creatorNetFailedSats: 0n
    }
  );
  const participantPayoutSummary = payoutRows.reduce(
    (acc, row) => {
      const status = parseParticipantPayoutStatus((row as any)?.status);
      acc[status] = Number(acc[status] || 0) + 1;
      return acc;
    },
    {
      pending: 0,
      ready: 0,
      forwarding: 0,
      paid: 0,
      failed: 0,
      blocked: 0
    } as Record<ParticipantPayoutStatus, number>
  );
  return reply.send({
    delegatedCreators: links.length,
    publishedItems: publishes.length,
    activePaymentIntents,
    settledPayments,
    totals: {
      grossCollectedSats: totals.grossCollectedSats.toString(),
      providerInvoicingFeeEarnedSats: totals.providerInvoicingFeeEarnedSats.toString(),
      providerDurableHostingFeeEarnedSats: totals.providerDurableHostingFeeEarnedSats.toString(),
      providerFeeEarnedSats: totals.providerFeeEarnedSats.toString(),
      creatorNetOwedSats: totals.creatorNetOwedSats.toString(),
      creatorNetPaidSats: totals.creatorNetPaidSats.toString(),
      creatorNetPendingSats: totals.creatorNetPendingSats.toString(),
      creatorNetFailedSats: totals.creatorNetFailedSats.toString()
    },
    participantPayouts: participantPayoutSummary
  });
});

