app.get("/api/provider/participant-payouts", { preHandler: requireAuth }, async (_req: any, reply: any) => {
  const intentCreatorById = new Map<string, string>();
  for (const intent of listProviderPaymentIntents()) {
    const intentId = String(intent.id || "").trim();
    const creatorNodeId = String(intent.creatorNodeId || "").trim();
    if (!intentId || !creatorNodeId) continue;
    intentCreatorById.set(intentId, creatorNodeId);
  }
  const rows = await prisma.participantPayout
    .findMany({
      include: {
        allocation: {
          select: {
            contentId: true,
            participantRef: true,
            participantUserId: true,
            participantEmail: true,
            role: true,
            bps: true,
            amountSats: true,
            allocationSource: true
          }
        }
      },
      orderBy: [{ updatedAt: "desc" }]
    })
    .catch((err: any) => {
      if (isMissingParticipantPayoutTableError(err)) return [];
      throw err;
    });
  const paymentIntentIds = Array.from(
    new Set(rows.map((row) => String((row as any)?.paymentIntentId || "").trim()).filter(Boolean))
  );
  const accountingByIntent = await buildIntentParticipantAccountingMap(paymentIntentIds);
  const contentIds = Array.from(
    new Set(rows.map((row) => String((row as any)?.allocation?.contentId || "").trim()).filter(Boolean))
  );
  const childLinks = contentIds.length
    ? await prisma.contentLink.findMany({
        where: { childContentId: { in: contentIds } },
        select: { childContentId: true, parentContentId: true }
      })
    : [];
  const parentContentIds = Array.from(new Set(childLinks.map((row) => String(row.parentContentId || "").trim()).filter(Boolean)));
  const allContentIds = Array.from(new Set([...contentIds, ...parentContentIds]));
  const contents = allContentIds.length
    ? await prisma.contentItem.findMany({
        where: { id: { in: allContentIds } },
        select: { id: true, title: true, type: true }
      })
    : [];
  const contentById = new Map(contents.map((row) => [row.id, row]));
  const parentByChild = new Map<string, string>();
  for (const row of childLinks) {
    const childId = String(row.childContentId || "").trim();
    const parentId = String(row.parentContentId || "").trim();
    if (!childId || !parentId || parentByChild.has(childId)) continue;
    parentByChild.set(childId, parentId);
  }

  const inferEarningSourceType = (
    participantRefRaw: string | null | undefined,
    roleRaw: string | null | undefined
  ): "catalog_earning" | "collaboration_earning" | "derivative_creator_earning" | "upstream_royalty_earning" => {
    const participantRef = String(participantRefRaw || "").trim().toLowerCase();
    const role = String(roleRaw || "").trim().toLowerCase();
    if (participantRef.startsWith("upstream") || role === "upstream") return "upstream_royalty_earning";
    if (participantRef.startsWith("derivative:") || role.startsWith("derivative")) return "derivative_creator_earning";
    if (role === "owner") return "catalog_earning";
    return "collaboration_earning";
  };

  const items = rows.map((row) => {
    const creatorNodeId = intentCreatorById.get(String(row.providerPaymentIntentId || "").trim()) || null;
    const contentId = String((row as any)?.allocation?.contentId || "").trim() || null;
    const content = contentId ? contentById.get(contentId) : null;
    const parentContentId = contentId ? parentByChild.get(contentId) || null : null;
    const parentContent = parentContentId ? contentById.get(parentContentId) : null;
    const participantRef = String((row as any)?.allocation?.participantRef || "").trim() || null;
    const allocationRole = String((row as any)?.allocation?.role || "").trim() || null;
    const allocationBps = Number((row as any)?.allocation?.bps || 0);
    const allocationSource = String((row as any)?.allocation?.allocationSource || "").trim() || null;
    const sourceType = inferEarningSourceType(participantRef, allocationRole);
    const paymentIntentId = String((row as any)?.paymentIntentId || "").trim();
    const allocationId = String((row as any)?.allocationId || "").trim();
    const accounting = paymentIntentId ? accountingByIntent.get(paymentIntentId)?.get(allocationId) : undefined;
    return {
      ...row,
      creatorNodeId,
      sourceType,
      allocationRole,
      allocationBps: Number.isFinite(allocationBps) ? allocationBps : 0,
      allocationSource,
      soldWork: content
        ? { id: content.id, title: content.title, type: content.type }
        : null,
      sourceWork: parentContent
        ? { id: parentContent.id, title: parentContent.title, type: parentContent.type }
        : null,
      grossShareSats: accounting ? accounting.grossShareSats.toString() : String((row as any)?.amountSats || "0"),
      feeWithheldSats: accounting ? accounting.feeWithheldSats.toString() : "0",
      netAmountSats: String((row as any)?.amountSats || "0")
    };
  });
  return reply.send({ items });
});

app.get("/api/provider/payment-intents/:id/participant-payouts", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const id = String((req.params as any)?.id || "").trim();
  if (!id) return badRequest(reply, "id is required");
  const rows = await prisma.participantPayout
    .findMany({
      where: { providerPaymentIntentId: id },
      include: {
        allocation: {
          select: {
            participantRef: true,
            participantUserId: true,
            participantEmail: true,
            role: true,
            bps: true,
            amountSats: true
          }
        }
      },
      orderBy: [{ createdAt: "asc" }]
    })
    .catch((err: any) => {
      if (isMissingParticipantPayoutTableError(err)) return [];
      throw err;
    });
  return reply.send({ items: rows });
});

app.post("/api/provider/payment-intents", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const body = (req.body ?? {}) as {
    creatorNodeId?: string | null;
    contentId?: string | null;
    amountSats?: string | number | null;
    paymentIntentId?: string | null;
    buyerSessionId?: string | null;
    payoutDestinationType?: CreatorPayoutDestinationType;
    payoutDestinationSummary?: string | null;
    providerRemitMode?: ProviderRemitMode;
    payoutPolicy?: ProviderPayoutPolicy;
    allowProviderFallback?: boolean;
  };
  const provider = await buildLocalNodeIdentityDoc((req.user as JwtUser).sub);
  const creatorNodeId = String(body.creatorNodeId || "").trim();
  const contentId = String(body.contentId || "").trim() || null;
  const amountSats = String(body.amountSats ?? "").trim();
  const paymentIntentId = String(body.paymentIntentId || "").trim() || buildProviderRecordId("pi");
  if (!creatorNodeId) return badRequest(reply, "creatorNodeId is required");
  if (!/^\d+$/.test(amountSats)) return badRequest(reply, "amountSats must be a positive integer");
  if (!amountSats || Number(amountSats) <= 0) return badRequest(reply, "amountSats must be greater than zero");
  const link = getProviderCreatorLink(creatorNodeId);
  if (!link || link.trustStatus !== "verified" || !link.executionAllowed) {
    return reply.code(409).send({
      error: "PROVIDER_CREATOR_RELATIONSHIP_REQUIRED",
      message: "Provider relationship is not ready for payment intents."
    });
  }
  if (contentId) {
    const delegated = listProviderDelegatedPublishes().find(
      (row) => row.contentId === contentId && row.creatorNodeId === creatorNodeId
    );
    if (!delegated) {
      return reply.code(409).send({
        error: "DELEGATED_PUBLISH_REQUIRED",
        message: "Delegated publish record is required before creating payment intents."
      });
    }
  }
  const memo = await buildRemittanceMemo({
    prefix: "Certifyd delegated",
    paymentIntentId,
    contentId
  });
  let bolt11: string | null = null;
  let providerInvoiceRef: string | null = null;
  try {
    const invoice = await createLightningInvoiceWithRetry(BigInt(amountSats), memo, {
      route: "/api/provider/payment-intents",
      paymentIntentId,
      contentId
    });
    bolt11 = invoice?.bolt11 || null;
    providerInvoiceRef = invoice?.providerId || null;
  } catch {}
  const providerRemitMode = parseProviderRemitMode(body.providerRemitMode || null) || "auto_forward";
  const payoutRail: ProviderPayoutRail = providerRemitMode === "auto_forward" ? "forwarded" : "provider_custody";
  const payoutPolicy = normalizeProviderFallbackPolicy(body.payoutPolicy, body.allowProviderFallback);
  const created = createProviderPaymentIntent({
    providerNodeId: provider.nodeId,
    creatorNodeId,
    contentId,
    paymentIntentId,
    bolt11,
    providerInvoiceRef,
    amountSats,
    ...computeProviderFeeBreakdown(amountSats),
    status: bolt11 ? "issued" : "created",
    payoutStatus: "pending",
    payoutRail,
    payoutDestinationType: parsePayoutDestinationType(body.payoutDestinationType || null),
    payoutDestinationSummary: String(body.payoutDestinationSummary || "").trim() || null,
    providerRemitMode,
    payoutExecutionMode: resolveNewIntentPayoutExecutionMode(),
    payoutPolicy: payoutPolicy.payoutPolicy,
    allowProviderFallback: payoutPolicy.allowProviderFallback,
    payoutSummaryStatus: "pending",
    payoutReference: null,
    remittedAt: null,
    payoutLastError: null,
    remittanceAttemptId: null,
    remittanceLockedAt: null,
    remittanceLastCheckedAt: null,
    remittanceAttempts: 0,
    paymentReceiptId: null,
    buyerSessionId: String(body.buyerSessionId || "").trim() || null,
    paidAt: null
  });
  return reply.send(created);
});
