function toVersionSummary(content: {
  previousVersionContentId?: string | null;
  previousVersion?: { id: string; title: string; status: string } | null;
}) {
  return {
    previousVersionContentId: content.previousVersionContentId || null,
    previousVersion: content.previousVersion
      ? {
          id: content.previousVersion.id,
          title: content.previousVersion.title,
          status: content.previousVersion.status
        }
      : null
  };
}

/**
 * CONTENT (auth)
 */
app.get("/content", { preHandler: requireAuth }, async (req: any, reply: any) => {
  const userId = (req.user as JwtUser).sub;
  const commerceAuthority = await resolveCommerceAuthorityForUser(userId);

  const q = (req.query || {}) as { trash?: string; tombstones?: string; scope?: string; type?: string };
  const trash = q.trash === "1";
  const tombstones = q.tombstones === "1";
  const scope = String(q.scope || "mine").toLowerCase();
  const requestedType = String(q.type || "all").toLowerCase();
  const allowedTypeFilters = new Set(["all", "songs", "videos", "books", "files"]);
  if (!allowedTypeFilters.has(requestedType)) {
    return reply.code(400).send({
      error: "INVALID_TYPE",
      message: "Invalid type filter. Use one of: all, songs, videos, books, files."
    });
  }
  const contentTypeWhere =
    requestedType === "songs"
      ? { type: "song" as const }
      : requestedType === "videos"
        ? { type: "video" as const }
        : requestedType === "books"
          ? { type: "book" as const }
          : requestedType === "files"
            ? { type: "file" as const }
            : {};
  const stateWhere =
    tombstones
      ? {
          deletedAt: { not: null as any },
          status: "published" as const
        }
      : trash
        ? {
            deletedAt: { not: null as any },
            status: { not: "published" as const },
            deletedReason: { not: "hard" }
          }
        : { deletedAt: null as any };

  const selectBase = {
    id: true,
    title: true,
    type: true,
    status: true,
    previousVersionContentId: true,
    previousVersion: { select: { id: true, title: true, status: true } },
    featureOnProfile: true,
    storefrontStatus: true,
    deliveryMode: true,
    priceSats: true,
    createdAt: true,
    repoPath: true,
    deletedAt: true,
    ownerUserId: true,
    owner: { select: { displayName: true, email: true } },
    manifest: { select: { sha256: true } },
    _count: { select: { files: true, entitlements: true } }
  } as const;

  const items: any[] = [];

  if (scope === "local") {
    const local = await prisma.contentItem.findMany({
      where: { ...stateWhere, ...contentTypeWhere },
      orderBy: { createdAt: "desc" },
      select: selectBase
    });
    items.push(...local.map((i) => ({ ...i, ...toVersionSummary(i), libraryAccess: i.ownerUserId === userId ? "owned" : "local" })));
  } else if (scope === "mine") {
    const owned = await prisma.contentItem.findMany({
      where: { ownerUserId: userId, ...stateWhere, ...contentTypeWhere },
      orderBy: { createdAt: "desc" },
      select: selectBase
    });
    items.push(...owned.map((i) => ({ ...i, ...toVersionSummary(i), libraryAccess: "owned" })));
  } else {
    // library: owned + purchased (entitlements) + public preview
    const me = await prisma.user.findUnique({ where: { id: userId }, select: { email: true } });
    const meEmail = (me?.email || "").toLowerCase();
    const [owned, purchased, publicPreview, participantLinks] = await prisma.$transaction([
      prisma.contentItem.findMany({
        where: {
          ownerUserId: userId,
          status: "published",
          deletedAt: null,
          ...contentTypeWhere
        },
        orderBy: { createdAt: "desc" },
        select: selectBase
      }),
      prisma.entitlement.findMany({
        where: {
          buyerUserId: userId,
          content: { is: { status: "published", ...contentTypeWhere } } as any
        },
        include: { content: { select: selectBase } },
        orderBy: { grantedAt: "desc" }
      }),
      prisma.contentItem.findMany({
        where: {
          storefrontStatus: { in: ["LISTED", "UNLISTED"] },
          status: "published",
          deletedAt: null,
          ...contentTypeWhere
        },
        orderBy: { createdAt: "desc" },
        select: selectBase
      }),
      prisma.splitParticipant.findMany({
        where: {
          acceptedAt: { not: null },
          OR: [
            { participantUserId: userId },
            meEmail ? { participantEmail: emailEquals(meEmail) } : undefined
          ].filter(Boolean) as any
        },
        select: {
          splitVersion: { select: { contentId: true } }
        }
      })
    ]);

    items.push(...owned.map((i) => ({ ...i, ...toVersionSummary(i), libraryAccess: "owned" })));
    items.push(
      ...purchased
        .filter((p) => p.content)
        .map((p) => ({ ...p.content, ...toVersionSummary(p.content), libraryAccess: "purchased" }))
    );
    items.push(...publicPreview.map((i) => ({ ...i, ...toVersionSummary(i), libraryAccess: "preview" })));
    if (participantLinks.length > 0) {
      const participantIds = Array.from(
        new Set(participantLinks.map((p) => p.splitVersion?.contentId).filter(Boolean) as string[])
      );
      if (participantIds.length > 0) {
        const participantContent = await prisma.contentItem.findMany({
          where: {
            id: { in: participantIds },
            status: "published",
            deletedAt: null,
            ...contentTypeWhere
          },
          orderBy: { createdAt: "desc" },
          select: selectBase
        });
        items.push(...participantContent.map((i) => ({ ...i, ...toVersionSummary(i), libraryAccess: "participant" })));

        const derivativeChildren = await prisma.contentLink.findMany({
          where: {
            parentContentId: { in: participantIds },
            childContent: {
              is: {
                status: "published",
                deletedAt: null,
                ...contentTypeWhere
              } as any
            }
          },
          include: {
            childContent: { select: selectBase }
          }
        });
        items.push(
          ...derivativeChildren
            .map((link) => link.childContent)
            .filter(Boolean)
            .map((i: any) => ({ ...i, ...toVersionSummary(i), libraryAccess: "participant" }))
        );
      }
    }
  }

  // de-dupe by content id (keep first)
  const seen = new Set<string>();
  const unique = items.filter((i) => {
    if (seen.has(i.id)) return false;
    seen.add(i.id);
    return true;
  });

  return unique.map((i: any) => ({
    ...i,
    priceSats:
      i.ownerUserId === userId && !commerceAuthority.authority
        ? null
        : i.priceSats != null
          ? i.priceSats.toString()
          : null,
    coverUrl: `${APP_BASE_URL}/public/content/${encodeURIComponent(i.id)}/cover`,
    featureOnProfile: Boolean(i.featureOnProfile),
    tombstoned: isArchivedPublished(i)
  }));
});

// Create a new content item and initialize a repo for it
app.post("/content", { preHandler: requireAuth }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const body = (req.body ?? {}) as { title?: string; type?: string; description?: string | null };

  const title = asString(body.title).trim();
  const type = asString(body.type).trim() || "file";
  const description = body.description ? asString(body.description).trim() : null;
  if (!title) return badRequest(reply, "title required");

  // create DB row first
  const content = await prisma.contentItem.create({
    data: { ownerUserId: userId, title, type: type as any, description }
  });

  try {
    // init repo on disk
    const repoPath = await initContentRepo({ root: CONTENTBOX_ROOT, contentId: content.id, type, title });

    // update content with repoPath
    await prisma.contentItem.update({ where: { id: content.id }, data: { repoPath } });

    // create initial split version v1
    await prisma.splitVersion.create({
      data: { contentId: content.id, versionNumber: 1, createdByUserId: userId, status: "draft" }
    });

    // audit: content created + manifest created
    try {
      await prisma.auditEvent.create({
        data: {
          userId,
          action: "content.create",
          entityType: "ContentItem",
          entityId: content.id,
          payloadJson: { title, type } as any
        }
      });
      const manifest = await readManifest(repoPath);
      if (manifest) {
        const manifestHash = computeManifestHash(manifest);
        await prisma.auditEvent.create({
          data: {
            userId,
            action: "content.manifest.create",
            entityType: "ContentItem",
            entityId: content.id,
            payloadJson: { manifestHash } as any
          }
        });
      }
    } catch {}
  } catch (e: any) {
    // cleanup: delete DB row if repo init failed
    await prisma.contentItem.delete({ where: { id: content.id } }).catch(() => {});
    return reply.code(500).send({ error: String((e as any)?.message || String(e)) });
  }

  const created = await prisma.contentItem.findUnique({ where: { id: content.id } });
  return reply.send(created);
});

// Create a new draft version from an existing published content item.
app.post("/content/:id/new-version", { preHandler: requireAuth }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const sourceId = asString((req.params as any).id || "").trim();
  if (!sourceId) return badRequest(reply, "contentId required");

  const source = await prisma.contentItem.findUnique({
    where: { id: sourceId },
    select: {
      id: true,
      ownerUserId: true,
      title: true,
      description: true,
      type: true,
      status: true,
      deletedAt: true,
      priceSats: true,
      deliveryMode: true
    }
  });
  if (!source) return notFound(reply, "Content not found");
  if (source.ownerUserId !== userId) return forbidden(reply);
  if (source.deletedAt) return reply.code(409).send({ code: "SOURCE_DELETED", error: "Source content is deleted." });
  if (String(source.status || "").toLowerCase() !== "published") {
    return reply.code(409).send({
      code: "SOURCE_NOT_PUBLISHED",
      error: "Only published content can create a new version draft."
    });
  }

  const nextTitle = `${asString(source.title || "").trim() || "Untitled"} (New Version Draft)`;
  const draft = await prisma.contentItem.create({
    data: {
      ownerUserId: userId,
      previousVersionContentId: source.id,
      title: nextTitle,
      description: source.description || null,
      type: source.type as any,
      status: "draft" as any,
      priceSats: source.priceSats ?? null,
      deliveryMode: source.deliveryMode || null
    }
  });

  try {
    const repoPath = await initContentRepo({
      root: CONTENTBOX_ROOT,
      contentId: draft.id,
      type: String(source.type || "file"),
      title: nextTitle
    });
    await prisma.contentItem.update({ where: { id: draft.id }, data: { repoPath } });

    await prisma.splitVersion.create({
      data: { contentId: draft.id, versionNumber: 1, createdByUserId: userId, status: "draft" }
    });

    const sourceCredits = await prisma.contentCredit.findMany({
      where: { contentId: source.id },
      orderBy: [{ sortOrder: "asc" }, { createdAt: "asc" }]
    });
    if (sourceCredits.length) {
      await prisma.contentCredit.createMany({
        data: sourceCredits.map((c) => ({
          contentId: draft.id,
          name: c.name,
          role: c.role,
          userId: c.userId || null,
          sortOrder: c.sortOrder ?? 0
        }))
      });
    }

    try {
      await prisma.auditEvent.create({
        data: {
          userId,
          action: "content.new_version.create",
          entityType: "ContentItem",
          entityId: draft.id,
          payloadJson: { sourceContentId: source.id, sourceStatus: source.status } as any
        }
      });
    } catch {}
  } catch (e: any) {
    await prisma.contentItem.delete({ where: { id: draft.id } }).catch(() => {});
    return reply.code(500).send({ error: asString(e?.message || e || "Failed to create new version draft") });
  }

  const created = await prisma.contentItem.findUnique({ where: { id: draft.id } });
  return reply.send({
    ok: true,
    sourceContentId: source.id,
    content: created
  });
});

// Create derivative content (child) with parent links and draft split
app.post("/api/content/:parentId/derivative", { preHandler: [requireAuth, requireFeature("derivative_work")] }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const parentId = asString((req.params as any).parentId);
  const body = (req.body ?? {}) as {
    type?: string;
    title?: string;
    description?: string | null;
    splitDraft?: Array<{ participantEmail?: string; userId?: string; role: string; bps: number }>;
    parentOrigin?: string | null;
    upstreamRatePercent?: number;
    upstreamBps?: number;
  };

  const title = asString(body.title).trim();
  const typeRaw = asString(body.type || "derivative").trim().toLowerCase();
  const type = (["remix", "mashup", "derivative"] as const).includes(typeRaw as any) ? (typeRaw as any) : "derivative";
  const description = body.description ? asString(body.description).trim() : null;
  if (!title) return badRequest(reply, "title required");
  if (!hasExplicitUpstreamInput(body)) {
    return badRequest(
      reply,
      "upstreamRatePercent is required at derivative creation time (0-100). This value is fixed for later clearance votes."
    );
  }

  let parent = await prisma.contentItem.findUnique({ where: { id: parentId } });
  const parentOrigin = body.parentOrigin ? asString(body.parentOrigin).trim() : "";
  if (!parent && parentOrigin) {
    let remoteMeta: any = null;
    try {
      const ctrl = new AbortController();
      const timeout = setTimeout(() => ctrl.abort(), 5000);
      const originBase = parentOrigin.replace(/\/+$/, "");
      const url = `${originBase}/public/content/${encodeURIComponent(parentId)}/offer`;
      const res = await fetch(url, { signal: ctrl.signal as any });
      const data = await res.json().catch(() => null);
      clearTimeout(timeout);
      if (res.ok) {
        remoteMeta = data;
      }
    } catch {}

    const remoteTitle = asString(remoteMeta?.title || "").trim() || `Remote content ${parentId}`;
    const remoteTypeRaw = asString(remoteMeta?.type || "").trim().toLowerCase();
    const remoteType = (["song", "book", "video", "file"] as const).includes(remoteTypeRaw as any)
      ? (remoteTypeRaw as any)
      : "file";
    const remoteDesc =
      asString(remoteMeta?.description || "").trim() || `Remote origin: ${parentOrigin.replace(/\/+$/, "")}`;
    parent = await prisma.contentItem.create({
      data: {
        id: parentId,
        ownerUserId: userId,
        title: remoteTitle,
        description: remoteDesc,
        type: remoteType as any,
        status: "published" as any,
        deletedAt: new Date(),
        deletedReason: "hard"
      }
    });
  }
  if (!parent) return notFound(reply, "parent content not found");
  const parentLockedSplit = await getLockedSplitForContent(parent.id);
  if (!parentLockedSplit || parentLockedSplit.status !== "locked") {
    return reply.code(409).send({ code: "PARENT_SPLIT_NOT_LOCKED", message: "Parent split must be locked before creating derivative links." });
  }
  const fixedUpstreamBps = parseFixedUpstreamBps(body);

  let splitDraft = Array.isArray(body.splitDraft) ? body.splitDraft : [];
  if (splitDraft.length === 0) {
    const me = await prisma.user.findUnique({ where: { id: userId }, select: { email: true } });
    const meEmail = me?.email ? normalizeEmail(me.email) : null;
    splitDraft = [
      {
        participantEmail: meEmail || undefined,
        userId,
        role: "writer",
        bps: 10000
      }
    ];
  }

  const child = await prisma.contentItem.create({
    data: { ownerUserId: userId, title, type: type as any, description, status: "draft" as any }
  });

  try {
    const repoPath = await initContentRepo({ root: CONTENTBOX_ROOT, contentId: child.id, type, title });
    await prisma.contentItem.update({ where: { id: child.id }, data: { repoPath } });

    await prisma.$transaction(async (tx) => {
      const link = await tx.contentLink.create({
        data: {
          parentContentId: parentId,
          childContentId: child.id,
          parentSplitVersionId: parentLockedSplit.id,
          relation: type as any,
          upstreamBps: fixedUpstreamBps,
          requiresApproval: true
        }
      });

      // Create storefront authorization gate for derivative exposure
      const parentSplit = await tx.splitVersion.findFirst({
        where: { contentId: parentId, status: "locked" },
        orderBy: { versionNumber: "desc" },
        include: { participants: true }
      });
      const parentEmails = parentSplit?.participants
        ?.map((sp) => sp.participantEmail)
        .filter(Boolean)
        .map((e) => String(e).toLowerCase()) || [];
      const parentUsers = parentSplit?.participants?.map((sp) => sp.participantUserId).filter(Boolean) || [];
      const usersFromEmail = parentEmails.length
        ? await tx.user.findMany({ where: { email: emailIn(parentEmails) }, select: { id: true } })
        : [];
      const approverIds = Array.from(new Set([...parentUsers.map(String), ...usersFromEmail.map((u) => u.id)]));
      if (approverIds.length === 0) {
        if (parent?.ownerUserId) approverIds.push(parent.ownerUserId);
      }

      await tx.derivativeAuthorization.create({
        data: {
          derivativeLinkId: link.id,
          parentContentId: parentId,
          requiredApprovers: Math.max(1, approverIds.length),
          approvedApprovers: 0,
          approveWeightBps: 0,
          rejectWeightBps: 0,
          approvalPolicy: "BPS_MAJORITY",
          approvalBpsTarget: 6667,
          status: "PENDING"
        }
      });

      const sv = await tx.splitVersion.create({
        data: { contentId: child.id, versionNumber: 1, createdByUserId: userId, status: "draft" }
      });

      for (const sp of splitDraft) {
        const bps = Math.max(0, Math.floor(num(sp.bps)));
        const percent = bps / 100;
        await tx.splitParticipant.create({
          data: {
            splitVersionId: sv.id,
            participantEmail: sp.participantEmail ? normalizeEmail(sp.participantEmail) : null,
            participantUserId: sp.userId || null,
            role: asString(sp.role).trim() || "writer",
            roleCode: "writer" as any,
            percent,
            bps
          }
        });
      }
    });
  } catch (e: any) {
    await prisma.contentItem.delete({ where: { id: child.id } }).catch(() => {});
    return reply.code(500).send({ error: String((e as any)?.message || String(e)) });
  }

  return reply.send({ ok: true, childContentId: child.id });
});

// Build and store manifest for content
app.post("/api/content/:contentId/manifest", { preHandler: requireAuth }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) {
    const ok = await isAcceptedParticipant(userId, contentId);
    if (!ok) return forbidden(reply);
  }

  const files = await prisma.contentFile.findMany({ where: { contentId }, orderBy: { createdAt: "asc" } });
  const manifestJson = await buildManifestWithDerivedAssets(content, files);
  const manifestSha256 = hashManifestJson(manifestJson);

  let parentManifestSha256: string | null = null;
  let lineageRelation: any = null;
  const parentLinks = await prisma.contentLink.findMany({ where: { childContentId: contentId } });
  if (parentLinks.length === 1) {
    const parentManifest = await prisma.manifest.findUnique({ where: { contentId: parentLinks[0].parentContentId } });
    parentManifestSha256 = parentManifest?.sha256 || null;
    lineageRelation = parentLinks[0].relation as any;
  }

  const manifest = await prisma.manifest.upsert({
    where: { contentId },
    update: { json: manifestJson as any, sha256: manifestSha256, parentManifestSha256, lineageRelation },
    create: { contentId, json: manifestJson as any, sha256: manifestSha256, parentManifestSha256, lineageRelation }
  });

  await prisma.contentItem.update({ where: { id: contentId }, data: { manifestId: manifest.id } });

  return reply.send({ ok: true, manifestSha256 });
});

// Get manifest JSON for content
async function handleGetManifest(req: any, reply: any) {
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) {
    const ok = await isAcceptedParticipant(userId, contentId);
    if (!ok) return forbidden(reply);
  }

  let manifest = await prisma.manifest.findUnique({ where: { contentId } });
  if (!manifest) {
    try {
      manifest = await ensureManifestForContent(content);
    } catch {
      return notFound(reply, "Manifest not found");
    }
  }

  return reply.send({ ok: true, sha256: manifest.sha256, manifest: manifest.json });
}

app.get("/api/content/:contentId/manifest", { preHandler: requireAuth }, handleGetManifest);
app.get("/content/:contentId/manifest", { preHandler: requireAuth }, handleGetManifest);

function generateShareToken() {
  return crypto.randomBytes(18).toString("hex");
}

function isShareLinkTableMissing(err: any) {
  const msg = String(err?.message || "");
  const code = String(err?.code || "");
  return code === "P2021" || (msg.includes("ShareLink") && msg.includes("does not exist"));
}

async function getActiveShareLink(contentId: string, tx: PrismaClient = prisma) {
  return tx.shareLink.findFirst({
    where: { contentId, status: "ACTIVE" },
    orderBy: { createdAt: "desc" }
  });
}

async function rotateShareLink(contentId: string, tx: PrismaClient = prisma) {
  const now = new Date();
  await tx.shareLink.updateMany({
    where: { contentId, status: "ACTIVE" },
    data: { status: "REVOKED", revokedAt: now }
  });
  return tx.shareLink.create({
    data: { contentId, token: generateShareToken(), status: "ACTIVE" }
  });
}

async function getWalletReceiveReady(userId: string, productTier?: string) {
  const isBasic = String(productTier || "").toLowerCase() === "basic";
  const codes = isBasic ? ["lightning_address"] : ["lightning_address", "lnurl", "btc_onchain"];
  const methods = await prisma.payoutMethod.findMany({
    where: { code: { in: codes as any } },
    select: { id: true }
  });
  if (!methods.length) return false;
  const identity = await prisma.identity.findFirst({
    where: { userId, payoutMethodId: { in: methods.map((m) => m.id) } },
    orderBy: { createdAt: "desc" }
  });
  return Boolean(identity?.value);
}

async function resolveDerivativeInfo(contentId: string, contentType: string | null) {
  const isDerivativeType = ["derivative", "remix", "mashup"].includes(String(contentType || ""));
  const links = await prisma.contentLink.findMany({ where: { childContentId: contentId } });
  const isDerivative = isDerivativeType || links.length > 0;
  if (!isDerivative) return { isDerivative: false, clearanceCleared: true, clearanceId: null, link: null };
  if (links.length !== 1) return { isDerivative: true, clearanceCleared: false, clearanceId: null, link: links[0] || null };
  const link = links[0];
  const clearanceCleared = !link.requiresApproval || Boolean(link.approvedAt);
  let clearanceId: string | null = null;
  if (clearanceCleared) {
    const req = await prisma.clearanceRequest.findFirst({
      where: { contentLinkId: link.id },
      orderBy: { createdAt: "desc" }
    });
    clearanceId = req?.id || null;
  }
  return { isDerivative: true, clearanceCleared, clearanceId, link };
}

async function ensureManifestForContent(content: any) {
  let manifest = await prisma.manifest.findUnique({ where: { contentId: content.id } });
  if (manifest) return manifest;

  const files = await prisma.contentFile.findMany({ where: { contentId: content.id }, orderBy: { createdAt: "asc" } });
  const manifestJson = await buildManifestWithDerivedAssets(content, files);
  const manifestSha256 = hashManifestJson(manifestJson);

  let parentManifestSha256: string | null = null;
  let lineageRelation: any = null;
  const parentLinks = await prisma.contentLink.findMany({ where: { childContentId: content.id } });
  if (parentLinks.length === 1) {
    const parentManifest = await prisma.manifest.findUnique({ where: { contentId: parentLinks[0].parentContentId } });
    parentManifestSha256 = parentManifest?.sha256 || null;
    lineageRelation = parentLinks[0].relation as any;
  }

  manifest = await prisma.manifest.upsert({
    where: { contentId: content.id },
    update: { json: manifestJson as any, sha256: manifestSha256, parentManifestSha256, lineageRelation },
    create: { contentId: content.id, json: manifestJson as any, sha256: manifestSha256, parentManifestSha256, lineageRelation }
  });

  await prisma.contentItem.update({ where: { id: content.id }, data: { manifestId: manifest.id } });
  return manifest;
}

app.get("/api/content/:contentId/share-link", { preHandler: requireAuth }, async (req: any, reply) => {
  const tier = resolveProductTier().productTier;
  if (tier === "basic") {
    return reply.code(403).send({ code: "basic_public_only", reason: "Share links require Advanced." });
  }
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);
  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) return forbidden(reply);

  let shareLink = null as any;
  try {
    shareLink = await getActiveShareLink(contentId);
  } catch (e: any) {
    if (isShareLinkTableMissing(e)) {
      return reply.code(503).send({ code: "share_links_not_initialized", reason: "Share links are not initialized. Run migrations and restart the API." });
    }
    throw e;
  }
  if (!shareLink) return reply.send({ shareLink: null });
  const base = getPublicOrigin(req).replace(/\/$/, "");
  const url = `${base}/p/${shareLink.token}`;
  return reply.send({
    shareLink: {
      id: shareLink.id,
      token: shareLink.token,
      status: shareLink.status,
      createdAt: shareLink.createdAt,
      revokedAt: shareLink.revokedAt,
      url
    }
  });
});

app.post("/api/content/:contentId/share-link", { preHandler: requireAuth }, async (req: any, reply) => {
  const tier = resolveProductTier().productTier;
  if (tier === "basic") {
    return reply.code(403).send({ code: "basic_public_only", reason: "Share links require Advanced." });
  }
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) return forbidden(reply);

  const ctx = getCapabilityContext();
  if (!ctx || !buildCapabilitySet(ctx).publishToNetwork) {
    const reason = capabilityReason(ctx, "publish_network", capabilityReasonContext(ctx));
    return reply.code(403).send({
      code: "publish_network_not_allowed",
      reason,
      message: reason
    });
  }
  const derivativeInfo = await resolveDerivativeInfo(contentId, content.type);
  const forSale = content.priceSats != null && BigInt(content.priceSats as any) > 0n;
  const readiness = ctx.paymentsMode === "node" ? await getPaymentsReadiness(userId) : null;
  const paymentsReady =
    ctx.paymentsMode === "node"
      ? Boolean(readiness?.lightning.ready || readiness?.onchain.ready)
      : await getWalletReceiveReady(userId, resolveProductTier().productTier);
  try {
    assertCanPublish(
      ctx,
      { publishKind: "share_link", forSale },
      {
        isDerivative: derivativeInfo.isDerivative,
        clearanceCleared: derivativeInfo.clearanceCleared,
        splitLocked: true,
        targetLocked: true,
        paymentsReady
      }
    );
  } catch (e: any) {
    return reply.code(403).send({ code: e?.code || "share_link_not_allowed", reason: e?.reason || "Not allowed" });
  }

  const manifest = await ensureManifestForContent(content);
  await prisma.contentItem.update({
    where: { id: contentId },
    data: { status: "published", manifestId: manifest.id }
  });

  let shareLink = null as any;
  try {
    shareLink = await rotateShareLink(contentId);
  } catch (e: any) {
    if (isShareLinkTableMissing(e)) {
      return reply.code(503).send({ code: "share_links_not_initialized", reason: "Share links are not initialized. Run migrations and restart the API." });
    }
    throw e;
  }
  const base = getPublicOrigin(req).replace(/\/$/, "");
  const url = `${base}/p/${shareLink.token}`;
  return reply.send({
    ok: true,
    shareLink: {
      id: shareLink.id,
      token: shareLink.token,
      status: shareLink.status,
      createdAt: shareLink.createdAt,
      revokedAt: shareLink.revokedAt,
      url
    }
  });
});

app.post("/api/content/:contentId/share-link/revoke", { preHandler: requireAuth }, async (req: any, reply) => {
  const tier = resolveProductTier().productTier;
  if (tier === "basic") {
    return reply.code(403).send({ code: "basic_public_only", reason: "Share links require Advanced." });
  }
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);
  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) return forbidden(reply);
  try {
    await prisma.shareLink.updateMany({
      where: { contentId, status: "ACTIVE" },
      data: { status: "REVOKED", revokedAt: new Date() }
    });
  } catch (e: any) {
    if (isShareLinkTableMissing(e)) {
      return reply.code(503).send({ code: "share_links_not_initialized", reason: "Share links are not initialized. Run migrations and restart the API." });
    }
    throw e;
  }
  return reply.send({ ok: true });
});

// Publish content (advanced canonical public buy link)
app.post("/api/content/:contentId/publish", { preHandler: requireAuth }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).contentId);

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) {
    const ok = await isAcceptedParticipant(userId, contentId);
    if (!ok) return forbidden(reply);
  }
  const publishGuard = assertLifecycleCanPublish(content);
  if (!publishGuard.ok) {
    return reply.code(409).send({ code: publishGuard.code, message: publishGuard.message });
  }

  const ctx = getCapabilityContext();
  const derivativeInfo = await resolveDerivativeInfo(contentId, content.type);
  const manifest = await ensureManifestForContent(content);
  const creatorIdentity = await buildLocalNodeIdentityDoc(userId);
  const canonicalManifestJson = normalizeManifestForPublish((manifest as any)?.json || {});
  const canonicalManifestHash = computeCanonicalManifestHash(canonicalManifestJson);

  const parents = await prisma.contentLink.findMany({ where: { childContentId: contentId } });
  const upstreamSum = sumBps(parents.map((p) => ({ bps: p.upstreamBps })));
  if (upstreamSum > 10000) return badRequest(reply, "upstreamBps sum must be <= 10000");

  let sv = await prisma.splitVersion.findFirst({
    where: { contentId },
    orderBy: { versionNumber: "desc" },
    include: { participants: true }
  });
  if (!sv) return badRequest(reply, "Split version missing");

  if (ctx.productTier === "basic") {
    const owner = await prisma.user.findUnique({
      where: { id: content.ownerUserId },
      select: { email: true }
    });
    const ownerEmail = normalizeEmail(owner?.email);
    if (!ownerEmail) return badRequest(reply, "Owner email missing");

    const curTotalBps = sumBps(sv.participants.map((p) => ({ bps: toBps(p) })));
    const ownerOnly =
      sv.participants.length === 1 && normalizeEmail(sv.participants[0]?.participantEmail || "") === ownerEmail;
    const needsBasicSplit = sv.status !== "locked" || curTotalBps !== 10000 || !ownerOnly;

    if (needsBasicSplit) {
      const now = new Date();
      const currentVersionNumber = sv.versionNumber;
      const created = await prisma.$transaction(async (tx) => {
        const newSv = await tx.splitVersion.create({
          data: {
            contentId,
            versionNumber: currentVersionNumber + 1,
            createdByUserId: content.ownerUserId,
            status: "locked",
            lockedAt: now
          }
        });
        await tx.splitParticipant.create({
          data: {
            splitVersionId: newSv.id,
            participantEmail: ownerEmail,
            role: "owner",
            percent: "100"
          }
        });
        await tx.auditEvent.create({
          data: {
            userId: content.ownerUserId,
            action: "split.lock",
            entityType: "SplitVersion",
            entityId: newSv.id,
            payloadJson: { lockedAt: now, reason: "basic_publish" } as any
          }
        });
        return newSv;
      });

      const refreshed = await prisma.splitVersion.findUnique({
        where: { id: created.id },
        include: { participants: true }
      });
      if (!refreshed) return badRequest(reply, "Split version missing");
      sv = refreshed;
    }
  }

  const totalBps = sumBps(sv.participants.map((p) => ({ bps: toBps(p) })));
  if (totalBps !== 10000) return badRequest(reply, "Split bps must total 10000 to publish");

  const readiness = ctx.paymentsMode === "node" ? await getPaymentsReadiness(content.ownerUserId) : null;
  const paymentsReady =
    ctx.paymentsMode === "node"
      ? Boolean(readiness?.lightning.ready || readiness?.onchain.ready)
      : await getWalletReceiveReady(content.ownerUserId, resolveProductTier().productTier);
  const forSale = content.priceSats != null && BigInt(content.priceSats as any) > 0n;

  try {
    assertCanPublish(
      ctx,
      { publishKind: "public_buy_link", forSale },
      {
        isDerivative: derivativeInfo.isDerivative,
        clearanceCleared: derivativeInfo.clearanceCleared,
        splitLocked: sv.status === "locked",
        targetLocked: Boolean(canonicalManifestHash),
        paymentsReady
      }
    );
  } catch (e: any) {
    return reply.code(403).send({ code: e?.code || "publish_not_allowed", reason: e?.reason || "Not allowed" });
  }

  const providerCfg = getNetworkProviderConfig();
  let delegatedReceipt:
    | {
        id: string;
        type: "content_publish";
        payload: ReturnType<typeof buildContentPublishReceiptPayload>;
      }
    | null = null;
  let delegatedPublishRecord: ProviderDelegatedPublishRecord | null = null;
  let delegatedPublishWarning: string | null = null;
  const shouldDelegatePublish =
    isNetworkProviderConfigured(providerCfg) &&
    evaluateProviderExecutionTrustReadiness().allowed &&
    String(providerCfg.providerUrl || "").trim().length > 0;
  if (shouldDelegatePublish) {
    const owner = await prisma.user.findUnique({
      where: { id: content.ownerUserId },
      select: { displayName: true, email: true }
    });
    const creatorDisplayName = String(owner?.displayName || "").trim() || String(owner?.email || "").trim() || null;
    const target = `${String(providerCfg.providerUrl || "").trim().replace(/\/+$/, "")}/api/network/provider/delegated-publish`;
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 8000);
    try {
      const providerResponse = await fetch(target, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          creatorNodeId: creatorIdentity.nodeId,
          creatorNodePubKey: creatorIdentity.nodePubKey,
          creatorDisplayName,
          contentId,
          title: (canonicalManifestJson as any)?.title ?? null,
          contentType: (canonicalManifestJson as any)?.type ?? null,
          manifestHash: canonicalManifestHash,
          visibility: content.storefrontStatus || "UNLISTED",
          primaryFile: (canonicalManifestJson as any)?.primaryFile ?? null,
          publishedAt: new Date().toISOString()
        }),
        signal: controller.signal
      } as any);
      if (!providerResponse.ok) {
        const providerError: any = await providerResponse.json().catch(() => null);
        const providerCode = String(providerError?.error || providerError?.code || "").trim() || null;
        const providerMessage =
          String(providerError?.message || providerError?.reason || "").trim() ||
          `Provider delegated publish failed (${providerResponse.status}).`;
        app.log.warn(
          {
            contentId,
            target,
            providerStatus: providerResponse.status,
            providerCode,
            providerMessage
          },
          "publish.delegated_provider_failed"
        );
        const failureAction = classifyDelegatedPublishFailure({
          providerStatus: providerResponse.status,
          providerCode
        });
        if (failureAction === "skip_relationship_required") {
          delegatedPublishWarning = providerMessage;
          app.log.warn(
            {
              contentId,
              target,
              providerStatus: providerResponse.status,
              providerCode,
              providerMessage
            },
            "publish.delegated_provider_skipped_relationship_required"
          );
        } else if (failureAction === "conflict") {
          return reply.code(409).send({
            code: providerCode || "delegated_publish_conflict",
            message: providerMessage,
            providerStatus: providerResponse.status
          });
        } else {
          return reply.code(502).send({
            code: providerCode || "delegated_publish_failed",
            message: providerMessage,
            providerStatus: providerResponse.status
          });
        }
      }
      const providerJson: any = await providerResponse.json().catch(() => null);
      delegatedPublishRecord = providerJson?.delegatedPublish || null;
      const receipt = providerJson?.receipt;
      if (receipt && typeof receipt.id === "string" && receipt.type === "content_publish" && receipt.payload) {
        delegatedReceipt = {
          id: receipt.id,
          type: "content_publish",
          payload: receipt.payload as ReturnType<typeof buildContentPublishReceiptPayload>
        };
      }
    } catch {
      return reply.code(502).send({
        code: "delegated_publish_unreachable",
        message: "Provider delegated publish endpoint is unreachable."
      });
    } finally {
      clearTimeout(timeout);
    }
  }

  const splitVersionId = sv?.id ? String(sv.id) : "";
  if (!splitVersionId) return badRequest(reply, "Split version missing");

  const now = new Date();
  const publishServiceProfile = resolveProviderServiceProfile({ hasLocalInvoiceMinting: false });
  const commerceOriginForPublish =
    publishServiceProfile.canonicalCommerceOrigin || getPublicOrigin(req);
  await prisma.$transaction(async (tx) => {
    await tx.manifest.update({
      where: { id: manifest.id },
      data: { json: canonicalManifestJson as any, sha256: canonicalManifestHash }
    });
    await tx.splitVersion.update({
      where: { id: splitVersionId },
      data: { lockedManifestSha256: canonicalManifestHash }
    });
    await tx.contentItem.update({
      where: { id: contentId },
      data: { status: "published", manifestId: manifest.id, currentSplitId: splitVersionId }
    });
    const publicOrigin = commerceOriginForPublish.replace(/\/$/, "");
    await tx.publishEvent.create({
      data: {
        contentId,
        publicUrl: `${publicOrigin}/buy/${contentId}`,
        targetHash: canonicalManifestHash,
        splitVersionId,
        clearanceId: derivativeInfo.clearanceId,
        priceSats: content.priceSats != null ? BigInt(content.priceSats as any) : null,
        publisherNodeId: publicOrigin || null,
        status: "PUBLISHED"
      }
    });
  });

  // Best-effort: trigger public sharing on publish
  try {
    await triggerPublicStartBestEffort();
  } catch {}

  const providerNodeIdForReceipt = delegatedPublishRecord?.providerNodeId || (isNetworkProviderConfigured(providerCfg) ? providerCfg.providerNodeId : null);
  appendLifecycleReceiptSafe({
    type: "content_publish",
    subjectNodeId: creatorIdentity.nodeId,
    providerNodeId: providerNodeIdForReceipt,
    objectId: contentId,
    payload: buildContentPublishReceiptPayload({
      contentId,
      manifestHash: canonicalManifestHash,
      title: (canonicalManifestJson as any)?.title ?? null,
      type: (canonicalManifestJson as any)?.type ?? null,
      primaryFile: (canonicalManifestJson as any)?.primaryFile ?? null,
      publishedAt: now.toISOString(),
      creatorNodeId: creatorIdentity.nodeId,
      providerNodeId: providerNodeIdForReceipt
    })
  });

  const publicOrigin = commerceOriginForPublish;
  return reply.send({
    ok: true,
    publishedAt: now.toISOString(),
    manifestSha256: canonicalManifestHash,
    publicOrigin,
    delegatedPublishWarning,
    delegatedPublish: delegatedPublishRecord
      ? {
          id: delegatedPublishRecord.id,
          providerNodeId: delegatedPublishRecord.providerNodeId,
          creatorNodeId: delegatedPublishRecord.creatorNodeId,
          publishReceiptId: delegatedPublishRecord.publishReceiptId
        }
      : null,
    delegatedReceipt
  });
});

// Update storefront status (owner only)
app.patch("/api/content/:id/storefront", { preHandler: [requireAuth, requireFeature("public_discovery")] }, async (req: any, reply) => {
  const userId = (req.user as JwtUser).sub;
  const contentId = asString((req.params as any).id);
  const body = (req.body ?? {}) as { storefrontStatus?: string };

  const status = asString(body.storefrontStatus || "").trim().toUpperCase();
  if (!["DISABLED", "UNLISTED", "LISTED"].includes(status)) {
    return badRequest(reply, "storefrontStatus must be DISABLED|UNLISTED|LISTED");
  }

  const content = await prisma.contentItem.findUnique({ where: { id: contentId } });
  if (!content) return notFound(reply, "Content not found");
  if (content.ownerUserId !== userId) {
    const ok = await isAcceptedParticipant(userId, contentId);
    if (!ok) return forbidden(reply);
  }

  if (status !== "DISABLED") {
    if (!content.manifestId || content.status !== "published") {
      return reply.code(409).send({ code: "CONTENT_NOT_PUBLISHED", message: "Content must be published before listing." });
    }
    const links = await prisma.contentLink.findMany({
      where: {
        childContentId: contentId
      }
    });

    const isDerivativeType = ["derivative", "remix", "mashup"].includes(String(content.type || ""));
    if (isDerivativeType || links.length > 0) {
      if (links.length > 1) {
        return reply.code(409).send({
          code: "MULTIPLE_PARENTS_NOT_SUPPORTED",
          message: "Multiple parent links exist."
        });
      }
      if (links.length === 0) {
        return reply.code(409).send({
          code: "DERIVATIVE_PARENT_REQUIRED",
          message: "Derivative must be linked to an original before being listed publicly."
        });
      }
      for (const link of links) {
        if (link.requiresApproval && !link.approvedAt) {
          return reply.code(409).send({
            code: "DERIVATIVE_NOT_APPROVED",
            message: "Derivative must be approved by upstream owners before being listed publicly."
          });
        }
      }
    }
  }

  const updated = await prisma.contentItem.update({
    where: { id: contentId },
    data: { storefrontStatus: status as any }
  });

  return reply.send({ ok: true, storefrontStatus: updated.storefrontStatus });
});

