// Short public link -> buy page
async function handlePublicProofBundle(req: any, reply: any) {
  const matchedHandle = asString((req.params as any).handle || "").trim();
  const requested = normalizePublicProfileHandle(matchedHandle);
  if (!requested) return notFound(reply, "Not found");

  const maybeName = requested.replace(/[-_.]+/g, " ").trim();
  const user =
    await prisma.user.findFirst({
      where: { displayName: { equals: requested } },
      select: {
        id: true,
        displayName: true,
        witnessIdentity: { select: { id: true, revokedAt: true, algorithm: true, publicKey: true, fingerprint: true } }
      }
    }) ||
    await prisma.user.findFirst({
      where: { displayName: { equals: maybeName } },
      select: {
        id: true,
        displayName: true,
        witnessIdentity: { select: { id: true, revokedAt: true, algorithm: true, publicKey: true, fingerprint: true } }
      }
    });
  if (!user) return notFound(reply, "Not found");

  const wk = await buildWellKnownContentboxPayload(req);
  const nodeUrl = asString(wk.nodeUrl || "").trim();
  if (!nodeUrl) return notFound(reply, "Not found");
  const profileUrl = `${nodeUrl.replace(/\/+$/, "")}/u/${encodeURIComponent(requested)}`;

  const verifiedProofs = await prisma.proofRecord.findMany({
    where: {
      userId: user.id,
      status: "verified",
      revokedAt: null
    },
    orderBy: [{ verifiedAt: "desc" }, { createdAt: "desc" }],
    select: { proofType: true, subject: true, claimJson: true, location: true, verifiedAt: true }
  });
  const creatorSignal = computeCreatorSignal(verifiedProofs as any, await getCreatorSignalNodeDetails());

  const domains = verifiedProofs
    .filter((p) => asString((p as any).proofType || "").trim().toLowerCase() === "domain")
    .map((p) => ({ domain: asString((p as any).subject || "").trim().toLowerCase(), verifiedAt: (p as any).verifiedAt?.toISOString?.() || null }))
    .filter((p) => p.domain.length > 0)
    .sort((a, b) => a.domain.localeCompare(b.domain));

  const social = verifiedProofs
    .filter((p) => asString((p as any).proofType || "").trim().toLowerCase() === "social")
    .map((p) => {
      const claim = ((p as any).claimJson || {}) as any;
      const subjectRaw = asString((p as any).subject || "").trim();
      const idx = subjectRaw.indexOf(":");
      const subjectProvider = idx > 0 ? subjectRaw.slice(0, idx).trim().toLowerCase() : "";
      const subjectAccount = idx > 0 ? subjectRaw.slice(idx + 1).trim() : subjectRaw;
      const provider = asString(claim?.provider || subjectProvider).trim().toLowerCase();
      const account = asString(claim?.account || claim?.username || subjectAccount).trim();
      return {
        provider,
        account,
        location: asString((p as any).location || "").trim() || null,
        verifiedAt: (p as any).verifiedAt?.toISOString?.() || null
      };
    })
    .filter((p) => p.provider.length > 0 && p.account.length > 0)
    .sort((a, b) => {
      const providerCmp = a.provider.localeCompare(b.provider);
      if (providerCmp !== 0) return providerCmp;
      return a.account.localeCompare(b.account);
    });

  const nostr = verifiedProofs
    .filter((p) => {
      const proofType = asString((p as any).proofType || "").trim().toLowerCase();
      const subjectRaw = asString((p as any).subject || "").trim().toLowerCase();
      const claim = ((p as any).claimJson || {}) as any;
      const claimPubkey = asString(claim?.pubkey || "").trim().toLowerCase();
      return proofType === "nostr" || subjectRaw.startsWith("nostr:") || /^[0-9a-f]{64}$/.test(claimPubkey);
    })
    .map((p) => {
      const claim = ((p as any).claimJson || {}) as any;
      const subjectRaw = asString((p as any).subject || "").trim();
      let pubkey = asString(claim?.pubkey || "").trim().toLowerCase();
      if (!pubkey) {
        const idx = subjectRaw.indexOf(":");
        pubkey = (idx > 0 ? subjectRaw.slice(idx + 1) : subjectRaw).trim().toLowerCase();
      }
      return {
        pubkey,
        display: pubkey.length > 18 ? `${pubkey.slice(0, 10)}…${pubkey.slice(-8)}` : pubkey,
        location: asString((p as any).location || "").trim() || null,
        verifiedAt: (p as any).verifiedAt?.toISOString?.() || null
      };
    })
    .filter((p) => /^[0-9a-f]{64}$/.test(p.pubkey))
    .sort((a, b) => a.pubkey.localeCompare(b.pubkey));

  const activeWitness = user.witnessIdentity && !user.witnessIdentity.revokedAt ? user.witnessIdentity : null;

  const bundle = {
    version: 1,
    handle: requested,
    displayName: asString(user.displayName || ""),
    profileUrl,
    nodeUrl,
    witness: activeWitness
      ? {
          algorithm: asString(activeWitness.algorithm || ""),
          publicKey: asString(activeWitness.publicKey || ""),
          fingerprint: asString(activeWitness.fingerprint || "")
        }
      : null,
    proofs: {
      domains,
      social,
      nostr
    },
    creatorSignal,
    generatedAt: new Date().toISOString(),
    signature: null
  };

  reply.type("application/json; charset=utf-8");
  return reply.send(bundle);
}

// Short public link -> buy page
async function handleShortPublicLink(req: any, reply: any) {
  const token = asString((req.params as any).token || "").trim();
  if (!token) return notFound(reply, "Not found");

  const share = await prisma.shareLink.findUnique({ where: { token } });
  if (share && share.status === "ACTIVE") {
    const content = await prisma.contentItem.findUnique({ where: { id: share.contentId } });
    if (!content || content.deletedAt) return notFound(reply, "Not found");
    return reply.redirect(`/buy/${encodeURIComponent(content.id)}?share=${encodeURIComponent(token)}`);
  }

  const sendNotAvailable = (content?: { title?: string | null }) => {
    const safeTitle = (content?.title || "This content").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
    const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Not Available</title>
  <style>
    body { font-family: system-ui, -apple-system, Segoe UI, sans-serif; background: #0b0b0b; color: #eee; padding: 24px; }
    .card { max-width: 720px; margin: 0 auto; background: #111; border: 1px solid #222; border-radius: 12px; padding: 20px; }
    .muted { color: #9aa0a6; font-size: 13px; }
    a { color: #9bdcff; text-decoration: none; }
    a:hover { text-decoration: underline; }
  </style>
</head>
<body>
  <div class="card">
    <h2>Not Available</h2>
    <p><strong>${safeTitle}</strong> isn’t publicly available yet.</p>
    <p class="muted">If you expected access, ask the owner to share a private link (e.g. <code>/p/&lt;token&gt;</code>) or publish the content.</p>
    <p class="muted"><a href="${APP_BASE_URL}">Return to Certifyd Creator</a></p>
  </div>
</body>
</html>`;
    return reply.type("text/html").send(html);
  };

  const content = await prisma.contentItem.findUnique({ where: { id: token } });
  if (!content) return notFound(reply, "Not found");
  if (content.status !== "published") return sendNotAvailable(content);
  return reply.redirect(`/buy/${encodeURIComponent(token)}`);
}

app.get("/p/:token", handleShortPublicLink);
app.get("/u/:handle", handlePublicNodeProfilePage);
app.get("/u/:handle/proofs.json", handlePublicProofBundle);
async function handlePublicProfileRedirect(req: any, reply: any) {
  const conf = await readBeatifyNodeProof();
  const beatifyHandle = normalizeBeatifyHandle(conf.beatifyHandle);
  if (!beatifyHandle) return notFound(reply, "Not found");
  return reply.redirect(302, `/u/${encodeURIComponent(beatifyHandle)}`);
}

app.get("/profile", handlePublicProfileRedirect);

async function resolveInviteClearanceContext(token: string, authorizationId: string) {
  const tokenHash = hashInviteToken(token);
  const inv: any = await prisma.invitation.findFirst({
    where: { OR: [{ token }, { tokenHash }] },
    include: { splitParticipant: { include: { splitVersion: true } } }
  });
  if (!inv || !inv.splitParticipantId) return null;
  const parentContentId = asString(inv?.splitParticipant?.splitVersion?.contentId || "").trim();
  if (!parentContentId) return null;
  const auth = await prisma.derivativeAuthorization.findUnique({
    where: { id: authorizationId },
    include: {
      derivativeLink: {
        include: {
          parentContent: { select: { id: true, title: true } },
          childContent: { select: { id: true, title: true } }
        }
      },
      votes: true
    }
  });
  if (!auth || String(auth.parentContentId || "") !== parentContentId) return null;

  const acceptedIdentityRef = asString(inv?.acceptedIdentityRef || "").trim();
  const acceptedIdentityUserId = parseUserIdFromParticipantRef(acceptedIdentityRef);
  const inviteUserId = asString(
    inv?.acceptedByUserId || acceptedIdentityUserId || inv?.splitParticipant?.participantUserId || ""
  ).trim();
  if (!inviteUserId) return null;

  const inviteTargetType = normalizeInviteTargetType(inv?.targetType);
  const inviteEmail = normalizeEmail(
    inv?.splitParticipant?.participantEmail ||
      (inviteTargetType === "email" ? asString(inv?.targetValue || "") : "") ||
      ""
  );
  const inviteUser = await prisma.user
    .findUnique({ where: { id: inviteUserId }, select: { email: true } })
    .catch(() => null);
  const inviteUserEmail = normalizeEmail(inviteUser?.email || "");
  const approverEmailForToken = inviteEmail || inviteUserEmail;

  const { eligible } = await getEligibleApproversForParent(parentContentId);
  const inviteApprover = eligible.find((a) => {
    const byUserId = Boolean(inviteUserId && a.participantUserId === inviteUserId);
    const byEmail = Boolean(
      approverEmailForToken &&
        normalizeEmail(a.participantEmail || "") &&
        normalizeEmail(a.participantEmail || "") === approverEmailForToken
    );
    return byUserId || byEmail;
  });
  if (!inviteApprover) return null;

  return {
    inv,
    auth,
    parentContentId,
    inviteUserId,
    inviteApprover,
    approverEmailForToken
  };
}

app.get("/invites/:token/clearance/:authorizationId", async (req: any, reply: any) => {
  const token = asString((req.params as any).token).trim();
  const authorizationId = asString((req.params as any).authorizationId).trim();
  if (!token || !authorizationId) return notFound(reply, "Not found");
  const ctx = await resolveInviteClearanceContext(token, authorizationId);
  if (!ctx) return forbidden(reply);

  const parentTitle = ctx.auth.derivativeLink?.parentContent?.title || "Original work";
  const childTitle = ctx.auth.derivativeLink?.childContent?.title || "Derivative";
  const progress = `${ctx.auth.approveWeightBps ?? 0}/${ctx.auth.approvalBpsTarget ?? 6667}`;
  const upstreamDefault = Number(ctx.auth.derivativeLink?.upstreamBps || 0) / 100;
  const safeParentTitle = escHtml(parentTitle);
  const safeChildTitle = escHtml(childTitle);

  const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Clearance / License for Release</title>
  <style>
    body { font-family: system-ui, -apple-system, Segoe UI, sans-serif; background: #0b0b0b; color: #eee; padding: 24px; }
    .card { max-width: 680px; margin: 0 auto; background: #111; border: 1px solid #222; border-radius: 12px; padding: 20px; }
    .muted { color: #9aa0a6; font-size: 13px; }
    input { padding: 8px 10px; border-radius: 8px; border: 1px solid #333; background: #0e0e0e; color: #fff; }
    button { padding: 10px 14px; border-radius: 10px; border: 1px solid #333; background: #141414; color: #fff; cursor: pointer; }
    button.primary { border-color: #1b4d2b; background: #0f2a1a; }
    button.danger { border-color: #5b1a1a; background: #2a0f0f; }
  </style>
</head>
<body>
  <div class="card">
    <h2>Clearance / License for Release</h2>
    <div class="muted">Original: <strong>${safeParentTitle}</strong></div>
    <div class="muted">Derivative: <strong>${safeChildTitle}</strong></div>
    <div class="muted">Progress: ${escHtml(progress)} bps</div>
    <p class="muted">Upstream royalty is fixed at derivative creation. Grant or reject clearance below.</p>
    <div class="muted">Upstream %: <strong>${upstreamDefault}%</strong></div>
    <div style="margin-top: 12px; display:flex; gap:10px;">
      <button class="primary" id="grantBtn" type="button">Grant clearance</button>
      <button class="danger" id="rejectBtn" type="button">Reject</button>
    </div>
    <div id="msg" class="muted" style="margin-top:10px;"></div>
  </div>
  <script>
    const msg = document.getElementById("msg");
    async function submit(decision) {
      const body = { decision };
      try {
        const r = await fetch("/invites/${encodeURIComponent(token)}/clearance/${encodeURIComponent(authorizationId)}/vote", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body)
        });
        const text = await r.text();
        msg.textContent = text || (r.ok ? "Recorded." : "Failed.");
      } catch (e) {
        msg.textContent = "Failed to submit.";
      }
    }
    document.getElementById("grantBtn").addEventListener("click", () => submit("approve"));
    document.getElementById("rejectBtn").addEventListener("click", () => submit("reject"));
  </script>
</body>
</html>`;

  return reply.type("text/html").send(html);
});

app.get("/invites/:token/clearance/:authorizationId/preview", async (req: any, reply: any) => {
  const token = asString((req.params as any).token).trim();
  const authorizationId = asString((req.params as any).authorizationId).trim();
  if (!token || !authorizationId) return notFound(reply, "Not found");
  const ctx = await resolveInviteClearanceContext(token, authorizationId);
  if (!ctx) return forbidden(reply);

  const link = ctx.auth.derivativeLink;
  if (!link?.childContentId) return notFound(reply, "Not found");

  const latestReview = await prisma.clearanceRequest.findFirst({
    where: { contentLinkId: link.id },
    orderBy: { createdAt: "desc" },
    select: { reviewGrantedAt: true }
  });
  if (!latestReview?.reviewGrantedAt) {
    return reply.code(409).type("text/plain").send("Preview not granted yet.");
  }

  const child = await prisma.contentItem.findUnique({
    where: { id: link.childContentId },
    select: { id: true, repoPath: true }
  });
  if (!child?.repoPath) return notFound(reply, "Not found");

  const manifest = await prisma.manifest.findUnique({ where: { contentId: child.id } });
  const manifestJson = (manifest?.json || {}) as any;
  const primaryFileId =
    (typeof manifestJson?.primaryFile === "string" && manifestJson.primaryFile) ||
    (Array.isArray(manifestJson?.files) && (manifestJson.files[0]?.path || manifestJson.files[0]?.objectKey)) ||
    null;
  let objectKey =
    (typeof manifestJson?.preview === "string" && manifestJson.preview) ||
    (typeof primaryFileId === "string" && primaryFileId) ||
    "";
  if (!objectKey) {
    const latestFile = await prisma.contentFile.findFirst({
      where: { contentId: child.id },
      orderBy: { createdAt: "desc" }
    });
    objectKey = asString(latestFile?.objectKey || "").trim();
  }
  if (!objectKey) return notFound(reply, "Preview not available");

  const repoRoot = path.resolve(child.repoPath);
  const absPath = path.resolve(repoRoot, objectKey);
  if (!absPath.startsWith(repoRoot)) return forbidden(reply);
  if (!fsSync.existsSync(absPath)) return notFound(reply, "File not found");

  const file = await prisma.contentFile.findFirst({ where: { contentId: child.id, objectKey } });
  const mime = file?.mime || "application/octet-stream";
  const stat = fsSync.statSync(absPath);
  const range = req.headers.range;
  if (range) {
    const m = /bytes=(\d+)-(\d+)?/.exec(range);
    if (m) {
      const start = Number(m[1]);
      const end = m[2] ? Number(m[2]) : stat.size - 1;
      if (start >= stat.size) return reply.code(416).send();
      reply.code(206);
      reply.header("Content-Range", `bytes ${start}-${end}/${stat.size}`);
      reply.header("Accept-Ranges", "bytes");
      reply.header("Content-Length", end - start + 1);
      reply.type(mime);
      return reply.send(fsSync.createReadStream(absPath, { start, end }));
    }
  }

  reply.header("Content-Length", stat.size);
  reply.type(mime);
  return reply.send(fsSync.createReadStream(absPath));
});

app.post("/invites/:token/clearance/:authorizationId/vote", async (req: any, reply: any) => {
  const token = asString((req.params as any).token).trim();
  const authorizationId = asString((req.params as any).authorizationId).trim();
  if (!token || !authorizationId) return notFound(reply, "Not found");
  const ctx = await resolveInviteClearanceContext(token, authorizationId);
  if (!ctx) return forbidden(reply);

  const link = ctx.auth.derivativeLink;
  if (!link) return notFound(reply, "Not found");
  const decision = asString((req.body as any)?.decision || "").toLowerCase();
  const rejectReason = decision === "reject" ? parseRejectReason(req.body) : null;
  if (!["approve", "reject"].includes(decision)) return badRequest(reply, "decision must be approve|reject");

  const fixedUpstreamRatePercent = Math.max(0, Number(link.upstreamBps || 0) / 100);
  if (decision === "approve") {
    const raw = (req.body as any)?.upstreamRatePercent;
    if (raw !== undefined && raw !== null && String(raw).trim() !== "") {
      const pct = Number(String(raw).trim());
      if (!Number.isFinite(pct)) return badRequest(reply, "upstreamRatePercent must be numeric");
      if (pct < 0 || pct > 100) return badRequest(reply, "upstreamRatePercent must be 0-100");
      if (Math.abs(pct - fixedUpstreamRatePercent) > 0.0001) {
        return reply.code(409).send("Upstream rate is fixed at derivative creation time.");
      }
    }
  }

  await prisma.derivativeApprovalVote.upsert({
    where: { authorizationId_approverUserId: { authorizationId: ctx.auth.id, approverUserId: ctx.inviteUserId } },
    update: { decision },
    create: { authorizationId: ctx.auth.id, approverUserId: ctx.inviteUserId, decision }
  });

  const votes = await prisma.derivativeApprovalVote.findMany({ where: { authorizationId: ctx.auth.id } });
  const voteUserIds = votes.map((v) => v.approverUserId);
  const voteUsers = voteUserIds.length
    ? await prisma.user.findMany({ where: { id: { in: voteUserIds } }, select: { id: true, email: true } })
    : [];
  const voteUserEmailById = new Map(voteUsers.map((u) => [u.id, normalizeEmail(u.email || "")]));

  const { eligible } = await getEligibleApproversForParent(ctx.parentContentId);
  let approveBps = 0;
  let rejectBps = 0;
  for (const v of votes) {
    const vEmail = voteUserEmailById.get(v.approverUserId) || "";
    const p = eligible.find((candidate) => {
      const byUserId = Boolean(candidate.participantUserId && candidate.participantUserId === v.approverUserId);
      const byEmail = Boolean(vEmail && normalizeEmail(candidate.participantEmail || "") === vEmail);
      return byUserId || byEmail;
    });
    const bps = p ? p.weightBps : 0;
    if (String(v.decision).toLowerCase() === "approve") approveBps += bps;
    if (String(v.decision).toLowerCase() === "reject") rejectBps += bps;
  }

  const status = approveBps >= (ctx.auth.approvalBpsTarget ?? 6667) ? "APPROVED" : "PENDING";
  await prisma.derivativeAuthorization.update({
    where: { id: ctx.auth.id },
    data: {
      approvedApprovers: votes.filter((v) => String(v.decision).toLowerCase() === "approve").length,
      approveWeightBps: approveBps,
      rejectWeightBps: rejectBps,
      status
    }
  });

  if (status === "APPROVED" && !link.approvedAt) {
    await prisma.contentLink.update({
      where: { id: link.id },
      data: { approvedAt: new Date(), approvedByUserId: ctx.inviteUserId, requiresApproval: true }
    });
    await prisma.clearanceRequest.updateMany({
      where: { contentLinkId: link.id, status: "PENDING" },
      data: { status: "CLEARED" }
    });
  }

  if (decision === "reject" && rejectReason) {
    try {
      await prisma.auditEvent.create({
        data: {
          userId: ctx.inviteUserId,
          action: "clearance.reject",
          entityType: "ContentLink",
          entityId: link.id,
          payloadJson: { reason: rejectReason, via: "invite_clearance" } as any
        }
      });
    } catch {}
  }

  return reply.type("text/plain").send("Thanks — your clearance response has been recorded.");
});

